/*Обозначения:
Это нотация Бэкуса-Наура (BNF) —
формальный способ описания синтаксиса языков программирования,
в данном случае SQL в PostgreSQL.

[ ] = "Можно не писать", необязательный элемент, например [ ONLY ]
       — можно написать UPDATE ONLY table или просто UPDATE table

{ } = "Обязательно что-то написать" (как пустое поле, которое надо заполнить)

| — выбрать ОДИН из вариантов

; = "Точка в конце предложения"

< > — замените на реальное значение

(<Список столбцов первичного ключа родительской таблицы>) - перечисление столбцов в круглых скобках
*/


/*
--     Проще всего: CASCADE удалит всё зависимое
DROP SCHEMA IF EXISTS abonent CASCADE;
DROP DOMAIN IF EXISTS Currency CASCADE;
DROP DOMAIN IF EXISTS PKField CASCADE;
DROP DOMAIN IF EXISTS TMonth CASCADE;
DROP DOMAIN IF EXISTS TYear CASCADE;
DROP SEQUENCE IF EXISTS Gen_disrepair CASCADE;
DROP SEQUENCE IF EXISTS Gen_executor CASCADE;
DROP SEQUENCE IF EXISTS Gen_nachislsumma CASCADE;
DROP SEQUENCE IF EXISTS Gen_paysumma CASCADE;
DROP SEQUENCE IF EXISTS Gen_request CASCADE;
DROP SEQUENCE IF EXISTS Gen_services CASCADE;
DROP SEQUENCE IF EXISTS Gen_street CASCADE;
*/


/******************************************************************************/
/*** Create DataBase ***/
/******************************************************************************/
CREATE DATABASE "abonent" WITH OWNER "postgres" ENCODING 'UTF8';


DO
$$
    DECLARE
        tables_to_drop TEXT[] := ARRAY [
            'street',
            'services',
            'disrepair',
            'executor',
            'abonent',
            'nachislsumma',
            'paysumma',
            'request'
            ];
        seqs_to_drop   TEXT[] := ARRAY [
            'gen_street',
            'gen_services',
            'gen_disrepair',
            'gen_executor',
            'gen_nachislsumma',
            'gen_paysumma',
            'gen_request'
            ];
        t              TEXT;
    BEGIN
        FOREACH t IN ARRAY tables_to_drop
            LOOP
                EXECUTE format('DROP TABLE IF EXISTS %s CASCADE', t);
            END LOOP;
        FOREACH t IN ARRAY seqs_to_drop
            LOOP
                EXECUTE format('DROP SEQUENCE IF EXISTS %s CASCADE', t);
            END LOOP;
    END;
$$;

CREATE SCHEMA IF NOT EXISTS abonent;
/******************************************************************************/
/*** Domains ***/
/******************************************************************************/
CREATE DOMAIN Currency AS
    NUMERIC(15, 2);
CREATE DOMAIN Pkfield AS INTEGER;
CREATE DOMAIN Tmonth AS
    SMALLINT
    CHECK (VALUE BETWEEN 1 AND 12);
CREATE DOMAIN Tyear AS
    SMALLINT
    CHECK (VALUE BETWEEN 1990 AND 2100);
/******************************************************************************/
/*** Generators ***/
/******************************************************************************/
CREATE SEQUENCE Gen_disrepair START WITH 13 INCREMENT BY 1;
CREATE SEQUENCE Gen_executor START WITH 7 INCREMENT BY 1;
CREATE SEQUENCE Gen_nachislsumma START WITH 80 INCREMENT BY 1;
CREATE SEQUENCE Gen_paysumma START WITH 79 INCREMENT BY 1;
CREATE SEQUENCE Gen_request START WITH 24 INCREMENT BY 1;
CREATE SEQUENCE Gen_services START WITH 5 INCREMENT BY 1;
CREATE SEQUENCE Gen_street START WITH 9 INCREMENT BY 1;
/******************************************************************************/
/*** Tables ***/
/******************************************************************************/
CREATE TABLE Abonent
(
    Accountid VARCHAR(6),
    Streetid  SMALLINT,
    Houseno   SMALLINT,
    Flatno    SMALLINT,
    Fio       VARCHAR(20),
    Phone     VARCHAR(15)
);
CREATE TABLE Disrepair
(
    Failureid PKFIELD,
    Failurenm VARCHAR(50)
);
CREATE TABLE Executor
(
    Executorid PKFIELD,
    FIO        VARCHAR(20)
);
CREATE TABLE Nachislsumma
(
    Nachislfactid PKFIELD,
    Accountid     VARCHAR(6) NOT NULL,
    Serviceid     PKFIELD    NOT NULL,
    Nachislsum    CURRENCY,
    Nachislmonth  TMONTH,
    Nachislyear   TYEAR
);
CREATE TABLE Paysumma
(
    Payfactid PKFIELD,
    Accountid VARCHAR(6) NOT NULL,
    Serviceid PKFIELD    NOT NULL,
    Paysum    CURRENCY,
    Paydate   DATE,
    Paymonth  TMONTH,
    Payyear   TYEAR
);
CREATE TABLE Request
(
    Requestid     PKFIELD,
    Accountid     VARCHAR(6)                   NOT NULL,
    Executorid    INTEGER,
    Failureid     INTEGER                      NOT NULL,
    Incomingdate  DATE    DEFAULT CURRENT_DATE NOT NULL,
    Executiondate DATE,
    Executed      BOOLEAN DEFAULT FALSE        NOT NULL
);
CREATE TABLE Services
(
    Serviceid PKFIELD,
    Servicenm VARCHAR(30)
);
CREATE TABLE Street
(
    Streetid SMALLINT,
    Streetnm VARCHAR(30)
);
