/*
В СУБД PostgreSQL имеется системная таблица information_schema.sequences,
в которой хранится информация о генераторах последовательностей,
имеющихся в БД. Выбрать список последовательностей в PostgreSQL можно
следующим запросом:
*/

SELECT *
FROM information_schema.sequences;


/*
В заключение рассмотрения генератора последовательности следует обратить
внимание на его основные отличия от автоинкремента.
SEQUENCE — это пользовательский объект БД, который генерирует
числовые значения в определённой последовательности в соответствии
с заданной спецификацией.

IDENTITY — это свойство таблицы, которое используется
для создания столбца идентификации. Генератор последовательности
является объектом БД, который не привязан ни к одной таблице,
а автоинкремент — это свойство одной конкретной таблицы. В отличие
от автоинкремента, значения которого создаются при вставке строк
в таблицу, значения последовательности можно получить без вставки
строки, так как для получения значения последовательности используется
вызов функции NEXTVAL.

Кроме того, генератор последовательности можно
переопределить запросом ALTER SEQUENCE (сбросить значение
последовательности до его начального значения, задать цикличность
последовательности, управлять кэшем, изменять другие параметры).



# Комментарии к объектам базы данных

Для сохранения в БД пояснений, относящихся к ней, её базовым объектам,
к столбцам таблиц и представлений, а также параметрам процедур,
используются комментарии (описания). Для создания такого комментария
используется запрос COMMENT ON, который имеет формат:

COMMENT ON
{
  DATABASE имя_базы_данных
  DOMAIN имя_домена
  TABLE имя_таблицы
  COLUMN имя_таблицы.имя_столбца
  INDEX имя_индекса
  FUNCTION имя_функции
  SEQUENCE имя_последовательности
  TRIGGER имя_триггера ON имя_таблицы
  VIEW имя_представления
} IS { 'текст' | NULL }

где текст — пояснение к объекту БД.
Указание пустой строки в качестве текста эквивалентно использованию NULL.

В результате действия запроса COMMENT ON в системном каталоге появится
комментарий к объекту БД.
Комментарии хранятся в столбце DESCRIPTION системной таблицы PG_DESCRIPTION.

Например, можно добавить комментарий к учебной БД с помощью запроса:
*/

COMMENT ON DATABASE "Abonent" IS 'Учебная БД Абонент';

---Такой запрос добавляет комментарий к домену PKField:

COMMENT ON DOMAIN PKField
    IS 'Домен предназначен для определения первичных ключей таблиц';

--Такой — к таблице Abonent:

COMMENT ON TABLE abonent
    IS 'Содержит адресные данные абонентов';

--А следующий запрос — к столбцу Accountid таблицы Abonent:

COMMENT ON COLUMN abonent.accountid IS 'Номер лицевого счёта';

/*
Также к столбцу Fio таблицы Abonent:
*/

COMMENT ON COLUMN abonent.fio IS 'ФИО абонентов';

/*
Просмотреть текст комментариев можно, извлекая столбец DESCRIPTION
строки с соответствующим идентификатором объекта из системной таблицы
PG_DESCRIPTION с помощью запроса. Например, для имени таблицы,
заданного параметром:
*/

SELECT DESCRIPTION, OBJOID
FROM PG_DESCRIPTION
WHERE OBJOID = :Par::REGCCLASS;

---Для вывода комментариев к столбцам можно использовать такой запрос:

SELECT PGD.DESCRIPTION
FROM PG_STATIO_ALL_TABLES          AS st
         INNER JOIN PG_DESCRIPTION AS pgd ON (pgd.OBJOID = st.RELID);

/*
Для вывода комментариев к пятому столбцу таблицы Abonent можно
использовать такой запрос:
*/

SELECT COL_DESCRIPTION('Abonent'::REGCLASS, 5)
FROM PG_DESCRIPTION
WHERE OBJOID = 'Abonent'::REGCLASS;

/*
Чтобы изменить комментарий, можно просто ввести новый запрос COMMENT ON
для того же объекта. Новый комментарий будет записан вместо старого.
Если необходимо удалить комментарий, то следует записать поверх него
пустой комментарий:
*/

COMMENT ON объект IS '';
COMMENT ON объект IS NULL;

--Удалить комментарий можно оператором:

COMMENT ON TABLE Abonent IS '';
COMMENT ON COLUMN Abonent.Fio IS '';


/*
Временная таблица, также как и обычная, может иметь последовательности,
индексы, триггеры, ограничения и комментарии на уровне столбца и на
уровне таблицы:
*/

CREATE TEMPORARY TABLE Remont
(
    Id          INT
        CONSTRAINT Pk_Remont PRIMARY KEY,
    Name_Remont VARCHAR(64) NOT NULL
);

CREATE SEQUENCE Gen_Remont;

COMMENT ON TABLE remont IS 'Справочник ремонтных работ';
COMMENT ON COLUMN remont.name_remont
    IS 'Название ремонтной работы';

CREATE UNIQUE INDEX Pk_Remont_Id ON Remont (Id, Name_Remont);


SELECT table_name,
       column_name,
       data_type,
       pg_catalog.col_description(
               (table_schema || '.' || table_name)::regclass,
               ordinal_position
       ) AS column_comment
FROM information_schema.columns
WHERE table_schema = 'abonent'
  AND table_name = 'abonent'
ORDER BY ordinal_position;

/*
## Программирование запросов модификации данных

### Добавление данных

В предыдущей теме были рассмотрены средства SQL, предназначенные для
определения структуры базы данных:
-таблиц,
-представлений
-последовательностей.

В данной теме внимание сосредоточено на операциях манипулирования данными —
т.е. на изменении содержимого баз данных.

Модификация данных осуществляется с использованием языка манипулирования
данными (Data Manipulation Language, DML).
В PostgreSQL к числу DML-запросов относятся:

- INSERT — добавление новых строк в таблицу;
- UPDATE — изменение существующих данных;
- DELETE — удаление строк;
- MERGE — комбинированная операция обновления или вставки на основе данных
  из другой таблицы.

Выполнять DML-запросы могут администратор и пользователи, обладающие
соответствующими правами доступа!!!

Запросы DML изменяют состояние таблиц, поэтому относятся к так называемым
запросам действия.
Эти действия необходимо завершать одной из команд управления транзакциями,
поскольку только после фиксации транзакции изменения становятся видимыми
другим пользователям и сохраняются в базе данных.

Формулировать DML-запросы следует с особой осторожностью: любые ошибки при
их составлении могут привести к утере информации или нарушению логики
данных.
Некорректное добавление, обновление или удаление может повлечь
за собой нарушение целостности, достоверности и непротиворечивости данных.

Во избежание подобных последствий необходимо учитывать ограничения
целостности, определяющие допустимые состояния базы данных и обеспечивающие
корректность всех вносимых изменений. Эти ограничения минимизируют риски
при выполнении операций модификации данных.

В данной теме рассматриваются правила и практики использования DML-запросов
для базовых таблиц.

Кроме того, отдельно обсуждаются особенности манипулирования данными
через обновляемые представления!!!

Добавление данных в определённую таблицу или представление БД осуществляется
вставкой одной или нескольких строк с помощью запроса-действия INSERT.

При вставке строк(и) проверяются:
- ограничения доменной целостности;
- ограничения первичного ключа или уникального индекса;
- проверочные ограничения типа CHECK;
- ограничения ссылочной целостности.

При нарушении какого-либо ограничения вставка не производится!!!

Различают два вида запроса INSERT:
- явный
- с подзапросом.

Запрос INSERT можно представить в общем виде. Указываются таблица,
список столбцов и список добавляемых в эти столбцы значений.
Синтаксис явного запроса выглядит так:

INSERT INTO <таблица> [(<список столбцов>)]
VALUES (<список значений>);

а с подзапросом SELECT следующим образом:

INSERT INTO <таблица> [(<список столбцов>)]
SELECT <список значений> FROM <откуда>
WHERE <список условий>;

В случае запроса с подзапросом в указанную таблицу (в перечисленные через
запятую столбцы) выполняется копирование выбранного с помощью запроса SELECT
набора данных.
Естественно, что количество и тип столбцов в запросе SELECT
должны соответствовать количеству и типу столбцов таблицы, в которую
осуществляется вставка.

В PostgreSQL запрос INSERT имеет следующий синтаксис:

[ WITH [ RECURSIVE ] запрос_WITH [, ...] ]
INSERT INTO таблица [ AS псевдоним ] [( столбец [, ...] )]
[ OVERRIDING { SYSTEM | USER } VALUE ]
{ DEFAULT VALUES | VALUES ( { выражение | DEFAULT } [, ...] ) }
[, ...] | запрос_SELECT )
[ ON CONFLICT [ <объект_конфликта> ]
    <действие_при_конфликте> ]
[ RETURNING * | выражение_результата [ [ AS ] имя_результата ] [, ...] ]

где

<объект_конфликта> ::= { имя_столбца_индекса
    | выражение_индекса }
    [ COLLATE правило_сортировки ] [ класс_операторов ] [, ...]
    [ WHERE предикат_индекса ]
    ON CONSTRAINT имя_ограничения


a <действие_при_конфликте> может быть следующим:

DO NOTHING

DO UPDATE SET { столбец = { выражение | DEFAULT }
    | (столбец [, ...]) = [ ROW ] ( { выражение | DEFAULT } [, ...] )
    | (столбец [, ...]) = ( вложенный_SELECT )
    } [, ...]
    [ WHERE условие ]

Запросом INSERT можно добавить в таблицу одну или несколько строк,
сформированных выражениями значений, либо ноль или более строк,
выданных дополнительным запросом.

Общее табличное выражение WITH позволяет задать один или несколько
подзапросов, на которые затем можно ссылаться по имени в запросе INSERT.

Имена целевых столбцов могут перечисляться в любом порядке. Если список
с именами столбцов отсутствует, то по умолчанию целевыми столбцами
становятся все столбцы заданной таблицы или первые N столбцов, если только
N столбцов поступает из секции VALUES или запроса. Значения, получаемые
из секции VALUES или запроса, связываются с явно или неявно определённым
списком столбцов **слева направо**. Все столбцы, не представленные в явном
или неявном списке столбцов, получают значения по умолчанию, если для них
заданы эти значения, либо NULL в противном случае. Если выражение для
любого столбца выдаёт другой тип данных, система попытается автоматически
привести его к нужному.

Если указывается секция OVERRIDING SYSTEM VALUE, то значения,
предоставляемые для столбцов идентификации, переопределяют значения,
выдаваемые последовательностью по умолчанию. Для столбцов идентификации,
определённого со свойством GENERATED ALWAYS, считается ошибкой присваивание
явного значения (кроме DEFAULT) без указания OVERRIDING SYSTEM VALUE или
OVERRIDING USER VALUE. В свою очередь, если указывается секция
OVERRIDING USER VALUE, то значения, предоставляемые для столбцов
идентификации, игнорируются и вместо них применяются значения, выдаваемые
последовательностью по умолчанию.

Необязательная секция ON CONFLICT задаёт действие, заменяющее возникновение
ошибки при нарушении ограничения уникальности или ограничения-исключения.
Эта конструкция является аналогом INSERT OR UPDATE в других СУБД. При этом
можно обращаться как к строкам, которые не добавились из-за конфликта,
так и к строкам, которые уже находятся в таблице.

Для каждой отдельной строки добавление либо выполняется успешно,
либо, если нарушается решающее  ограничение, решающее ограничение или индекс,
задаваемые как <объект_конфликта>, выполняется альтернативное
<действие_конфликта>.
Вариант ON CONFLICT DO NOTHING в качестве альтернативного действия
просто отменяет добавление строки.
Вариант ON CONFLICT DO UPDATE изменяет существующую строку,
вызвавшую конфликт со строкой, предложенной для добавления.

С помощью необязательного оператора RETURNING запрос INSERT вычислит
и возвратит значения для каждой фактически добавленной строки.
В основном это необходимо для получения значений, присвоенных по умолчанию,
например, последовательного номера строки.
Однако в этой секции можно задать любое выражение со столбцами таблицы.
Список RETURNING имеет тот же синтаксис, что и список результатов SELECT.
В результате будут возвращены те строки, которые были успешно вставлены.

# Явный запрос INSERT

Упрощённый синтаксис явного запроса INSERT в PostgreSQL имеет следующий вид:

INSERT INTO таблица [ AS псевдоним ] [ ( столбец [, ...] ) ]
{ DEFAULT VALUES
| VALUES ( { выражение | DEFAULT } [, ...] ) [, ...]
| скалярный_подзапрос }
[ RETURNING * | выражение_результата [ [ AS ] имя_результата ] [, ...] ];

В таблицу или представление вставляется строка со значениями столбцов,
указанными в перечне секции VALUES, причём i-е значение соответствует
i-му столбцу в списке столбцов.
Столбцы, не указанные в списке, заполняются значениями по умолчанию
или NULL, если ограничение, наложенное на столбец, позволяет вставку NULL.
Если допустимы NULL-маркеры и определено значение по умолчанию,
то вставлено будет значение по умолчанию. Если NULL недопустимы и не
определено значение по умолчанию, то запрос на вставку без явного
указания значения такого столбца выполнен не будет.

## Примечание

Если NULL недопустимы, то можно ввести, например, пустую строку для
символьного столбца, однако такую подмену делать не рекомендуется.

Рассмотрим вставку новой строки в таблицу при указании полного списка
её столбцов. Например, для вставки строки в таблицу Abonent можно
использовать запрос:
*/

INSERT INTO Abonent (Accountid, Streetid, Houseno, Flatno, Fio, Phone)
VALUES ('500000', 8, 1, 1, 'Плитов Е. Д.', '556787');

/*
Если в списке опции VALUES указаны значения для всех столбцов модифицируемой
таблицы и порядок их перечисления соответствует порядку столбцов
в описании таблицы (как в приведённом примере), то список столбцов
в секции INTO можно опустить. Например, предыдущий запрос на вставку
строки в таблицу Abonent можно записать так:
*/

INSERT INTO Abonent
VALUES ('500000', 8, 1, 1, 'Плитов Е. Д.', '556787');

/*
Если требуется ввести NULL-маркер, например, в столбец Phone (номер
телефона абонента неизвестен), то он вводится точно так же, как и обычное
значение, например:
*/

INSERT INTO Abonent
VALUES ('500000', 8, 1, 1, 'Плитов Е. Д.', NULL);

/*
В примерах значения, помещаемые в таблицу, располагаются в том порядке,
в котором они были созданы запросом CREATE TABLE.
Но в некоторых случаях требуется поменять порядок вводимых значений
или вводить значения не во все столбцы в таблице.
Чтобы выполнить это условие, требуется явно указать
имена и порядок столбцов.
Примером этому может служить запрос:
*/

INSERT INTO Abonent (Accountid, Streetid, Fio)
VALUES ('500000', 8, 'Плитов Е. Д.');

/*
В связи с тем, что в общем случае порядок следования столбцов в самой
таблице может быть изменён, рекомендуется в запросе INSERT явно указывать
имена столбцов.
*/

/*
Следует продемонстрировать вставку строк в таблицу, содержащую столбец
идентификации.

При добавлении строки в подобные таблицы можно приводить, но можно и не
указывать ни имя, ни значение идентификационного столбца. В последнем
случае оно будет формироваться автоматически с помощью системного
генератора. Например, для таблицы Days запрос на вставку новой строки
может быть таким:
*/

INSERT INTO Days(Num, Dat, Implemented, Tel)
VALUES (3, '31.10.2024', TRUE, '316127');

--или таким:

INSERT INTO Days(Num, Dat, Implemented, Tel)
VALUES (DEFAULT, '31.10.2024', TRUE, '316127');

/*
а также подготовленным для запроса INSERT, который затем выполняется
и удаляется:
*/

PREPARE Ins_days (DATE, BOOLEAN, TEXT) AS
    INSERT INTO Days(Dat, Implemented, Tel)
    VALUES ($1, $2, $3);
EXECUTE Ins_days('31.10.2024', TRUE, '316127');
DEALLOCATE Ins_days;

/*
В общем случае значение первичного ключа в идентификационном столбце
может не быть следующим по порядку, но всегда уникальное.

Использовать результат скалярного подзапроса в качестве значения можно,
например, так:
*/

INSERT INTO Abonent
VALUES ('500000', 8, 1, 1, 'Плитов Е. Д.',
        (
        SELECT Phone
        FROM Abonent
        WHERE Accountid = '005488'
        ));

---или следующим образом:

INSERT INTO Request(Requestid, Accountid, Executorid, Failureid)
VALUES ((
        SELECT MAX(Requestid) + 1
        FROM Request
        ), '005488', 6, 1);

/*
В первом запросе скалярный подзапрос используется для нахождения номера
телефона абонента с номером лицевого счёта 005488, а во втором —
следующего значения первичного ключа. Важно отметить, что во втором
запросе столбцы Incomingdate и Executed принимают значения по умолчанию,
а столбец Executiondate — NULL.


При добавлении данных возможны ситуации, когда типичным должно быть не
конкретное значение данных, а способ его получения, например при
использовании значений по умолчанию. Так, если требуется в таблице Abonent
хранить время и имя пользователя, добавившего нового абонента, то следует
в неё добавить два соответствующих столбца:
*/

ALTER TABLE abonent
    ADD add_user VARCHAR(20)
        DEFAULT USER NOT NULL;
ALTER TABLE abonent
    ADD add_date DATE
        DEFAULT CURRENT_DATE NOT NULL;


select *
from Abonent


         /*
         После этого при добавлении данных нового абонента в таблице Abonent
         автоматически будут фиксироваться имя пользователя, дата и время этого
         действия.
         */


/*
Рассмотрим пример множественного задания списка значений в секции VALUES
запроса INSERT. Допустим, необходимо добавить сразу несколько строк
в таблицу Abonent.
В PostgreSQL для этого не требуется создавать несколько
запросов INSERT, можно добавить все строки одним запросом:
*/

         INSERT INTO abonent(AccountId, StreetId, Houseno, Flatno, Fio, Phone)
VALUES ('500010', 8, 1, 5, 'Иванов В. И.', '551189'),
       ('500011', 8, 1, 6, 'Воскрина Л. Г.', NULL),
       ('500012', 8, 1, 7, 'Мартынов И. Р.', '550303'),
       ('500013', 8, 1, 8, 'Федькин А. А.', '551102');

/*
Примером использования последовательности в DML-запросе на вставку строки
может служить запрос:
*/

INSERT INTO Executor
VALUES (NEXTVAL('Gen_Executor'),
        'Иванов А. А.');

select *
from Executor;

/*
Для добавления данных в столбец составного типа, т.е. в столбце, у которого
составной тип данных, рекомендовано использовать конструктор табличных
строк ROW или строку. Если составной тип содержит более
одного поля, то ROW можно опустить. Например, в таблицу Paysumma_1,
добавить строки можно следующим образом:
*/

INSERT INTO Paysumma_1
    (Payfactid, AccountId, Serviceid, Paysum, D_m_y)
VALUES (NEXTVAL('Gen_Paysumma'), '005488', 1, 100.00,
        ROW (CURRENT_DATE, 7, EXTRACT(YEAR FROM CURRENT_DATE)));



INSERT INTO Paysumma_1
    (Payfactid, AccountId, Serviceid, Paysum, D_m_y)
VALUES (NEXTVAL('Gen_Paysumma'), '115705', 3, 200.00,
        (CURRENT_DATE, 8, EXTRACT(YEAR FROM CURRENT_DATE)));

INSERT INTO Paysumma_1
    (Payfactid, AccountId, Serviceid, Paysum, D_m_y)
VALUES (NEXTVAL('Gen_Paysumma'), '443690', 2, 150.00,
        (CURRENT_DATE, 9, EXTRACT(YEAR FROM CURRENT_DATE)));


select *
from Paysumma_1;


/*
В общем случае пользователь БД может указать:
- какие значения должны обновляться из вставляемых данных;
- значения, которые должны обновляться, из совокупности существующих
  и вставляемых;
- значения, которые не должны изменяться.

Например, если появилась новая информация об исполнителях (поменялось ФИО
и появился новый), можно выполнить следующий запрос:
*/


INSERT INTO Executor (Executorid, Fio)
VALUES (4, 'Шлюков М. Г.'),
       (NEXTVAL('Gen_executor'), 'Смирнов К. А.')
ON CONFLICT (Executorid) DO UPDATE SET Fio = EXCLUDED.Fio;


select *
from Executor

         /*
         В результате его выполнения у абонента Шлюков  изменятся инициалы,
         и добавится новый исполнитель Смирнов К. А. с идентификатором 8. Здесь
         использовалась специальная системная таблица EXCLUDED,
         которая содержит все значения, которые не добавились из-за
         возникновения конфликта.
         */

/*
Если имеются новые данные об абонентах (поменялся номер телефона
и появился новый абонент), причём необходимо сохранить информацию
о прежнем номере телефона, то для обновления таблицы Abonent достаточно
выполнить такой запрос.


Если абонент с таким Accountid уже существует,
то дописывается в таблицу новый номер телефона в конец существующего
через пробел.
Скрипт добавляет новых абонентов, а для существующих — дописывает
новый номер телефона в начало старого через пробел, сохраняя историю номеров.
*/

         INSERT INTO Abonent (Accountid, Streetid, Houseno, Flatno, Fio, Phone)
VALUES ('443690', 7, 5, 1, 'Тулупова М. И.', '568742'),
       ('443691', 7, 5, 2, 'Иванов Д. А.', NULL) ON CONFLICT (Accountid)
DO UPDATE SET Phone = EXCLUDED.Phone || ' (' || Abonent.Phone || ')';



select *
from abonent
         /*
         Наконец, если имеет место третий случай, т.е. например, требуется добавить
         данные о новой ремонтной заявке и обновить совокупность данных
         о существующей заявке, то необходимо выполнить следующие запросы:
         */

-- добавление уникального ограничения
         ALTER TABLE Request
ADD CONSTRAINT Request_uq UNIQUE (Accountid, Incomingdate, Failureid);


/*
Этот запрос гарантирует, что в таблице Request не будет двух строк
с одинаковыми значениями в столбцах Accountid, Incomingdate и Failureid.
Это важно для предотвращения дублирования заявок, которые могут быть
поданы одним и тем же абонентом (Accountid) на ту же дату (Incomingdate)
и по той же причине (Failureid).
*/

-- INSERT INTO с обработкой конфликтов
INSERT INTO Request (Requestid, Accountid, Executorid, Failureid,
                     Incomingdate, Executiondate, Executed)
VALUES (NEXTVAL('Gen_request'), '115705', 1,
        3, '2023-12-28',
        CURRENT_DATE, TRUE),
       (NEXTVAL('Gen_request'), '115705', NULL,
        3, DEFAULT, NULL, FALSE)
ON CONFLICT (Accountid, Incomingdate, Failureid) DO UPDATE
    SET Requestid     = Request.Requestid,
        Executorid    = EXCLUDED.Executorid,
        Executiondate = EXCLUDED.Executiondate,
        Executed      = EXCLUDED.Executed;

/*
Ключевое слово	      Что означает
EXCLUDED	          Значения, которые пытались вставить (из VALUES)
Request               Текущие значения, уже существующие в таблице

DO UPDATE SET
    Requestid     = Request.Requestid,        -- оставляем старый ID
    Executorid    = EXCLUDED.Executorid,      -- берём новый Executorid
    Executiondate = EXCLUDED.Executiondate,   -- берём новую дату выполнения
    Executed      = EXCLUDED.Executed         -- берём новый статус
*/

select *
from request


/*
Данный запрос вставляет две новые строки в таблицу Request.
Если при вставке возникает конфликт по уникальному ограничению (т.е. уже
существует заявка с теми же AccountId, Incomingdate и FailureId),
существующая строка будет обновлена новыми значениями из вставляемой
строки. Это гарантирует, что не будут создаваться дубликаты, а вместо
этого обновятся соответствующие данные, такие как исполнитель (ExecutorId),
дата выполнения (Executiondate) и статус выполнения (Executed).
*/


/*
В строке ON CONFLICT (AccountId, Incomingdate, FailureId) DO UPDATE SET:

- ON CONFLICT обрабатывает конфликты, возникающие при нарушении
  уникального ограничения на комбинацию столбцов AccountId, Incomingdate
  и FailureId;
- DO UPDATE в случае конфликта обновляет существующую строку;
- SET:
    RequestId = Request.RequestId: сохраняет текущее значение RequestId
                в случае обновления;
    ExecutorId = EXCLUDED.ExecutorId: обновляет ExecutorId значением
                из EXCLUDED (новая вставляемая строка);
    Executiondate = EXCLUDED.Executiondate: обновляет Executiondate
                    значением из EXCLUDED;
    Executed = EXCLUDED.Executed: обновляет Executed значением
               из EXCLUDED.
*/


/*
Примером запроса на вставку в таблицу с массивом Executor_1
может быть такой:
*/

-- Создание таблицы Executor_1

CREATE TABLE Executor_1
(
    Executorid SERIAL PRIMARY KEY,   -- автоинкрементный первичный ключ
    Fio        VARCHAR(20) NOT NULL, -- ФИО исполнителя
    Phone      text[]                -- массив телефонов (тип - массив строк)
);

INSERT INTO Executor_1 (Fio, Phone)
VALUES ('Иванов И. И.', ARRAY ['111111', '2222222222']),
       ('Петров П. П.', ARRAY ['3333333333333', '4444444']);


--Извлечь данные из массива можно следующим образом:

SELECT *
FROM Executor_1;

---а с поиском так:

SELECT *
FROM Executor_1
WHERE '111111' = ANY (Phone);


/*
Вставить JSON-данные в таблицу Executor можно, например,
так:
*/

ALTER TABLE Executor
    ADD COLUMN Profile JSONB;

INSERT INTO Executor (ExecutorId, Fio, Profile)
VALUES (NEXTVAL('Gen_executor'), 'Иванов И. И.',
        '{
          "post": "мастер",
          "age": 30,
          "category": 3,
          "interests": [
            "рыбалка",
            "грибы",
            "охота"
          ]
        }'),
       (NEXTVAL('Gen_executor'), 'Петров П. П.',
        '{
          "post": "слесарь",
          "age": 25,
          "category": 5,
          "interests": [
            "музыка",
            "нумизматика"
          ]
        }');


---Извлечение данных из JSON:
-- извлечь возраст и должность каждого исполнителя
SELECT Fio,
       Profile ->> 'age'  AS age,
       Profile ->> 'post' AS post
FROM Executor;

-- найти исполнителей с интересом "музыка"
SELECT *
FROM Executor
WHERE Profile ->> 'interests' @> '[ "музыка" ]';

SELECT *
FROM Executor
WHERE (Profile -> 'interests')::JSONB @> '["музыка"]';

SELECT *
FROM Executor
WHERE Profile -> 'interests' ? 'музыка';


/*
Запрос-действие INSERT с подзапросом позволяет вставить одну или несколько
строк в таблицу или представление.

В PostgreSQL запрос INSERT с вложенным запросом реализуется также
с использованием подзапроса SELECT:

INSERT INTO таблица [ AS псевдоним ] [ ( имя_столбца [, ...] ) ]
<запрос_SELECT>
[ RETURNING * | выражение_результата [ [ AS ] имя_результата ] [, ...] ];

Рассмотрим примеры использования запросов INSERT с подзапросом SELECT.

Пусть дана пустая таблица Abonent_1 со столбцами, полностью совпадающими
по порядку следования, именам и типам данных со столбцами в таблице
Abonent.
Копировать из таблицы Abonent в таблицу Abonent_1 всей информации
по первым пяти абонентам, имеющим телефон, можно следующим запросом:
*/


INSERT INTO Abonent_1
SELECT *
FROM Abonent
WHERE Phone IS NOT NULL
    FETCH FIRST 5 ROWS ONLY;

--или при отсутствии таблицы Abonent_1 так:

CREATE TABLE Abonent_1 AS
SELECT *
FROM Abonent
WHERE Phone IS NOT NULL
    FETCH FIRST 5 ROWS ONLY;
--Начать с первой строки

/*
Следующий запрос выполняет то же самое, т.е. создаёт целевую таблицу
Abonent_1 на основе данных исходной таблицы Abonent:
*/
SELECT *
INTO TABLE Abonent_1
FROM Abonent
WHERE Phone IS NOT NULL
    FETCH FIRST 5 ROWS ONLY;

/*
В отсутствие указанных совпадений потребовалось бы привести
соответствующий список столбцов в запросе INSERT, или в подзапросе SELECT,
или в обоих местах.

Для вставки строк в таблицу на основании данных другой таблицы необходимо
определить, какие строки и какие столбцы нужно вставить, а затем
использовать оператор INSERT INTO ... SELECT для выборки нужных строк
из другой таблицы и их вставки в целевую таблицу.
*/


/*
Пусть имеется пустая таблица Fio со столбцами Abonent_fio и Executor_fio,
определёнными на типе данных VARCHAR(30):
*/

CREATE TABLE Fio
(
    Abonent_fio  VARCHAR(30) NOT NULL,
    Executor_fio VARCHAR(30)
);

/*
В эту таблицу необходимо поместить ФИО абонентов и исполнителей каждой
из ремонтных заявок.
Для этого можно применить запрос:
*/


INSERT INTO Fio (Abonent_fio, Executor_fio)
SELECT A.Fio, E.Fio
FROM Request                R
         LEFT JOIN Abonent  A USING (AccountId)
         LEFT JOIN Executor E USING (ExecutorId);

select *
from fio;


/*
В секции FROM запроса SELECT может быть указана не базовая таблица,
а представление. Таким образом, можно вставлять данные из представления
в базовую таблицу.
Например, если ранее было создано соединённое
представление Abonent_executor (содержатся ФИО абонентов и ФИО
назначенных на их ремонтные заявки исполнителей):
*/

CREATE VIEW Abonent_executor (Abonent_name, Executor_name)
AS
SELECT A.Fio, E.Fio
FROM Abonent                 A
         INNER JOIN Request  R USING (AccountId)
         INNER JOIN Executor E USING (ExecutorId);

---то предыдущий запрос можно переписать:

INSERT INTO Fio
SELECT Abonent_name, Executor_name
FROM Abonent_executor;


select *
from fio;


/*
Необходимо отметить, что результаты выполнения двух вышеприведённых
запросов будут различаться количеством добавленных строк. Первый запрос,
в отличие от второго, добавит строку с неопределёнными ФИО исполнителя.

Для добавления значения 'ЕСЕНИНА УЛИЦА' в случае её отсутствия в таблице
Street можно выполнить такой запрос:
*/

INSERT INTO Street (Streetid, Streetnm)
SELECT NEXTVAL('Gen_street'), 'ЕСЕНИНА УЛИЦА'
WHERE NOT EXISTS
      (
      SELECT 1
      FROM Street
      WHERE Streetnm = 'ЕСЕНИНА УЛИЦА'
      );

/*
В подзапросах, используемых в запросе INSERT, можно использовать оператор
UNION. Пусть имеется таблица Phone со столбцами Abonent_fio, Old_tel
и New_tel, определёнными на типе данных соответственно VARCHAR(30),
VARCHAR(15) и VARCHAR(15):
*/


CREATE TABLE Phone
(
    Abonent_fio VARCHAR(30) NOT NULL,
    Old_tel     VARCHAR(15) NOT NULL,
    New_tel     VARCHAR(15) NOT NULL
);

select *
from Phone;

/*
Известно, что номера телефонов, которые начинались с 2,
теперь начинаются с 1, а 6 сменились на 5.
В таблицу Phone необходимо поместить ФИО абонентов, у которых изменился
номер телефона, а также старые и новые номера телефонов.
Для этого можно применить запрос:
*/

INSERT INTO Phone (Abonent_fio, Old_tel, New_tel)
SELECT Fio, Phone, '1' || TRIM(LEADING '2' FROM Phone)
FROM Abonent
WHERE SUBSTRING(Phone FROM 1 FOR 1) = '2'
---SUBSTRING(строка FROM начало FOR длина)
---Вырезает часть строки
---SUBSTRING('254417' FROM 1 FOR 1) = '2'
---TRIM(LEADING '2' FROM Phone)
---Удаляет указанный символ в начале строки
---TRIM(LEADING '2' FROM '254417') = '54417'
UNION
SELECT Fio, Phone, '5' || TRIM(LEADING '6' FROM Phone)
FROM Abonent
WHERE SUBSTRING(Phone FROM 1 FOR 1) = '6';

Select *
from Phone;

/*
Результат:

| Abonent_fio        | Old_tel | New_tel |
|--------------------|---------|---------|
| Денисова Е. К.     | 680305  | 580305  |
| Лукашина Р. М.     | 254417  | 154417  |
| Маркова В. П.      | 683301  | 583301  |
| Стародубцев Е. В.  | 683014  | 583014  |
| Тулупова М. И.     | 214833  | 114833  |
| Шубина Т. П.       | 257842  | 157842  |

Таблица Phone после вставки
*/


/*
### Примечания

1. В подзапросе SELECT не следует использовать секцию ORDER BY,
    поскольку нецелесообразно сортировать таблицу результатов запроса,
    так как она добавляется в таблицу, которая, как и все остальные,
    не упорядочена.

2. В качестве значений, возвращаемых подзапросом SELECT, можно
   использовать агрегатные функции, но при этом нужно обеспечить
   совпадение типа и количества значений, возвращаемых запросом.

При добавлении данных можно использовать обобщённое табличное
выражение. Например, добавить идентификаторы новых услуг можно
следующим запросом:
*/


ALTER SEQUENCE Gen_Services RESTART WITH 5 INCREMENT BY 1;

select *
from Gen_Services;

WITH RECURSIVE s AS (
                    SELECT NEXTVAL('Gen_Services') AS k
                    UNION ALL
                    SELECT k + 1
                    FROM s
                    WHERE k < 10
                    )
INSERT
INTO Services (Serviceid, Servicenm)
SELECT k, 'Наименование услуги уточнить'
FROM s;


select *
from Services


         /*
         Обновление и удаление данных

         ## Обновление данных

         Обновление значений как отдельных строк, так и всей таблицы или
         представления БД, осуществляется запросом-действием **UPDATE**.
                                                                                       В общем виде запрос UPDATE указывает, где и что необходимо изменить,
                                                                                                               а также критерии отбора обновляемых строк:

         UPDATE <таблица> SET <столбец> = <выражение>
             [WHERE <список условий>];

         или

         UPDATE <таблица> SET <столбец> =
             (SELECT <значение> FROM <откуда> WHERE <список условий>)
             [WHERE <список условий_1>];

         Обновление с помощью запроса UPDATE может быть позиционированным
         (выполняется только над одной строкой) и поисковым (выполняется над
         нулевым или большим количеством строк).

         Позиционированное изменение может появиться только в контексте текущей
         операции в процедурном модуле с курсором, в то время как поисковое изменение
         появляется во всех остальных случаях.
         Поисковое изменение может эмулировать (имитировать, воспроизводить)
         позиционированное изменение, если в секции WHERE задано условие,
         уникально определяющее строку (например, используемый первичный ключ таблицы).
         Запрос UPDATE может анализировать информацию из других таблиц БД, используя
         запрос SELECT (вложенный запрос).

         В PostgreSQL обобщённый формат запроса UPDATE имеет вид:

         [ WITH [ RECURSIVE ] запрос_WITH [, ...] ]
         UPDATE [ ONLY ] таблица [ * ] [ [ AS ] псевдоним ]
         SET { столбец = { выражение | DEFAULT } |
             ( столбец [, ...] ) = [ ROW ] ( { выражение | DEFAULT } [, ...] ) |
             ( столбец [, ...] ) = ( вложенный_SELECT )
             } [, ...]
             [ FROM элемент_FROM [, ...] ]
             [ WHERE условие | WHERE CURRENT OF имя_курсора ]
             [ RETURNING { * | выражение_результата [ [ AS ] имя_результата ] } ]

             Запрос UPDATE содержит секцию SET, в ней указывается изменение, которое
             нужно сделать для определённого столбца. Секция SET может включать
             столбцы лишь из обновляемой таблицы, т.е. значение одного или нескольких
             столбцов модифицируемой таблицы может быть заменено другим значением.

             В качестве значений могут применяться контекстные переменные (например,
             в контексте текущего соединения клиента может использоваться контекстная
             переменная CURRENT_USER). Также можно установить для столбца NULL-маркер.
             Допускается применение вложенного запроса SELECT в секции SET.


         Секция WHERE используется для отбора изменяемых строк. Условие поиска
         может использовать вложенный запрос SELECT. При отсутствии секции WHERE
         обновляются значения указанных столбцов во всех строках модифицируемой
         таблицы.

         Выражение WITH позволяет задать один или несколько подзапросов,
         на которые затем можно ссылаться по имени в запросе UPDATE.

         Опция DEFAULT позволяет присвоить столбцу значение по умолчанию (это может
         быть NULL, если для столбца не определено некоторое выражение по умолчанию).
         Столбец идентификации при этом получает значение, выданное соответствующей
         последовательностью. Для генерируемого столбца это указание допускается,
         но не меняет обычное поведение, т.е. значение столбца вычисляется
         генерирующим выражением.

         Имя курсора используется в условии WHERE CURRENT OF, которое позволяет
         изменить строку, выбирая её из этого курсора последней. Курсор должен
         образовываться запросом, не применяющим группировку, к целевой таблице
         команды UPDATE. Следует заметить, что WHERE CURRENT OF нельзя задать
         вместе с логическим условием.

         Когда присутствует секция FROM, целевая таблица соединяется с таблицами,
         перечисленными в элемент_FROM, и каждая выходная строка соединения
         представляет операцию изменения для целевой таблицы. Применяя секцию FROM,
         необходимо обеспечить, чтобы соединение выдавало максимум одну выходную
         строку для каждой строки, которую нужно изменить. Другими словами, целевая
         строка не должна соединяться более чем с одной строкой из других таблиц.
         Если это условие нарушается, только одна из строк соединения будет
         использоваться для изменения целевой строки, но какая именно, предсказать
         нельзя.

         С помощью необязательного оператора RETURNING запрос UPDATE вычислит
         и возвратит значения для каждой фактически обновлённой строки.

         ---

         ### Примечания

         1. При выполнении обновления данных следует иметь в виду, что последующее
            восстановление изменённых данных, т.е. возврат таблицы к состоянию
            до выполнения запроса UPDATE, очень часто бывает затруднителен.

         2. Если при попытке обновить строку новое значение столбца противоречит
            ограничению, выдается сообщение об ошибке.

         */


/*
# Явный запрос
UPDATE

Явный запрос-действие UPDATE выбирает строки для изменения без
использования подзапроса в секции WHERE и в PostgreSQL имеет формат:

UPDATE [ ONLY ] таблица [ * ] [ [ AS ] псевдоним ]
SET { столбец = { выражение | DEFAULT } |
    ( столбец [, ...] ) = [ ROW ] ( { выражение | DEFAULT } [, ...] ) }
    [ WHERE условие | WHERE CURRENT OF имя_курсора ]
    [ RETURNING { * | выражение_результата [ [ AS ] имя_результата ] } [, ...] ];

В данном случае в секции
SET не используется подзапрос, секция WHERE
применяется для отбора изменяемых строк без использования подзапроса,
т.е.явно.

-----------------------------------------------------------------------------
Примеры явного запроса
UPDATE
-----------------------------------------------------------------------------
*/
---1. Установить для всех абонентов номер телефона 982223 (без секции WHERE):

         UPDATE Abonent
SET Phone = '982223';


--2. Изменить фамилию абонента с лицевым счётом '080047':

UPDATE Abonent
SET Fio = 'Серова Т. П.'
WHERE Accountid = '080047';

---3. Обновить несколько столбцов одним запросом:

UPDATE Abonent
SET Fio   = 'Зайцева А. К.',
    Phone = '328127'
WHERE Accountid = '136159';


/*
-----------------------------------------------------------------------------
Использование CASE в
UPDATE
-----------------------------------------------------------------------------

Операция CASE может применяться не только в запросе SELECT.
Она также очень полезна при изменении значений столбцов на основе условий,
задаваемых полями строки, относящимися к другим столбцам.Примером
такого использования операции CASE может быть запрос:
*/

UPDATE Nachislsumma
SET Nachislsum = CASE
                     WHEN Nachislyear = 2024
                         THEN Nachislsum * 1.1
                     WHEN Nachislyear = 2025
                         THEN Nachislsum * 1.2
                 END
WHERE Serviceid = 1;

/*
Данный запрос изменяет значения начислений за услугу с кодом 1
за 2024 г. и 2025 г. на 10% и 20% соответственно.
*/

/*
Рассмотрим задачу обновления значений типа BYTEA.
Пусть в столбце Photo, добавленном в таблицу Executor, необходимо
разместить фотографию исполнителя. Для ввода такой информации, например,
по исполнителю с кодом 1, нужно выполнить следующий запрос:
*/

UPDATE Executor
SET Photo = pg_read_binary_file(:Photo)
WHERE Executorid = 1;

/*
Здесь функция pg_read_binary_file() используется для чтения бинарных
файлов, которые должны находиться в определённом каталоге, доступном
серверу БД. В качестве значения параметра должен быть указан путь
к файлу изображения, например
'C:\Program Files\PostgreSQL\17\data\Photo_1.jpg'. Аналогичным образом
можно работать и с изображениями других типов данных, таких как png,
jpeg, txt, pdf.
*/

/*
В выражении для вычисления новых значений столбца может использоваться
не только имя изменяемого столбца, но и другие столбцы, например, таким
образом:
*/
UPDATE Request
SET Executiondate = (Incomingdate + 2)
WHERE Accountid = '015527';


/*
Аргумент DEFAULT можно также использовать для изменения значения столбца
на NULL, если для него не определено значение по умолчанию и разрешены
признаки NULL.
Например, с помощью запроса:
*/

UPDATE Abonent
SET Phone = DEFAULT;

---номера телефонов у всех абонентов становятся неопределёнными.

/*
Для изменения данных в столбце составного типа также необходимо
использовать ROW .
Например, в таблице Paysumma_1, изменить данные в записи можно следующим
образом:
*/


UPDATE Paysumma_1
SET D_m_y = ROW (CURRENT_DATE, 7, 2023)
WHERE Payfactid = 79;

select *
from paysumma_1;


/*
Чтобы обратиться к столбцу составного типа для извлечения конкретных
значений, необходимо после названия столбца поставить точку и написать
название поля, которое требуется извлечь, при этом название столбца
необходимо писать в круглых скобках.
Например:
*/

SELECT Payfactid,
       Accountid,
       D_m_y,
       (d_m_y).P_Month,
       (d_m_y).P_Year,
       (d_m_y).p_date
FROM Paysumma_1;

/*
Следует отметить, что если указать символ «*» после названия столбца,
который имеет составной тип, то все значения будут выводиться в развёрнутом
виде, т.е. каждое значение в отдельном столбце:
*/

SELECT Payfactid, Accountid, D_m_y, (D_m_y).*
FROM Paysumma_1;

/*
Рассмотрим примеры применения массивов. В массиве можно заменить либо
значение одного элемента:
*/

UPDATE Executor_1
SET Phone[2] = '777777'
WHERE Fio = 'Петров П. П.';

--либо части:

UPDATE Executor_1
SET Phone[3:4] = '{888888, 999999}'
WHERE Fio = 'Иванов И. И.';

---либо полностью:

UPDATE Executor_1
SET Phone = '{444444444444, 555555, 666666}'
WHERE Fio = 'Иванов И. И.';


/*
Текущая схема БД не позволяет хранить более одного номера телефона
абонента. Стандартным решением может быть создание новой таблицы,
где каждая строка хранит номер телефона и номер лицевого счёта абонента,
которому номер телефона принадлежит. Вместо этого можно добавить столбец
Phones для хранения массива номеров телефонов:
*/

ALTER TABLE Abonent
    ADD COLUMN Phones TEXT[] NOT NULL DEFAULT ARRAY []::TEXT[];

UPDATE Abonent
SET Phones = ARRAY [Phone]
WHERE Phone IS NOT NULL; -- копирование номеров телефонов

select *
from Abonent;

ALTER TABLE Abonent
    DROP COLUMN Phone;
-- удаление Phone

/*
Такой подход упрощает схему БД и позволяет избежать соединения таблиц,
так как небольшие массивы хранятся в самой строке таблицы.
*/


/*
# Запрос UPDATE с подзапросами

В секциях SET и WHERE запроса UPDATE можно использовать вложенные
запросы. Запрос-действие UPDATE с подзапросами в PostgreSQL имеет
формат:

[ WITH [ RECURSIVE ] запрос_WITH [, ...] ]
UPDATE [ ONLY ] таблица [ * ] [ [ AS ] псевдоним ]
SET столбец1 = (<подзапрос1>) [, столбец2 = (<подзапрос2>) ] ...
| (столбец1 [, столбец2...]) = (<подзапрос>)
[ WHERE <условие_поиска_с_подзапросом>
    | WHERE CURRENT OF имя_курсора ]
[ RETURNING { * | выражение_результата [ [ AS ] имя_результата ] }
    [, ...] ];

В секции SET <подзапрос> указывается для обновления определённого
столбца и представляет собой <скалярный_подзапрос>. В <условие_поиска_
с_подзапросом> секции WHERE подзапрос может представлять собой
<скалярный_подзапрос>, <подзапрос_столбца> или <табличный_подзапрос>
в зависимости от вида условия поиска (синтаксис условия поиска совпадает
с описанным ранее при изучении вложенных запросов).

Разберем использование подзапроса в секции WHERE запроса UPDATE,
позволяющее отбирать строки для обновления на основе информации из
других таблиц.

Например, для уменьшения на 10 значений начислений за услугу с кодом 2
абонентам, подавшим одну заявку на ремонт газового оборудования, нужно
выполнить запрос:
*/

UPDATE Nachislsumma N
SET Nachislsum = Nachislsum - 10
WHERE 1 = (
          SELECT COUNT(*)
          FROM Request R
          WHERE R.Accountid = N.Accountid
          )
  AND Serviceid = 2;

--- либо

UPDATE Nachislsumma N
SET Nachislsum = Nachislsum - 10
WHERE (
      SELECT COUNT(*)
      FROM Request R
      WHERE R.Accountid = N.Accountid
      ) = 1
  AND Serviceid = 2;


WITH single_request_abonents AS (
                                SELECT Accountid
                                FROM Request
                                GROUP BY Accountid
                                HAVING COUNT(*) = 1
                                )
UPDATE Nachislsumma N
SET Nachislsum = Nachislsum - 10
WHERE Accountid IN (
                   SELECT Accountid
                   FROM single_request_abonents
                   )
  AND Serviceid = 2;

/*
Это условие, которое проверяет, равно ли количество заявок у абонента единице.

Подзапрос, использованный в данном запросе UPDATE, является связанным,
так как в нем используется столбец Accountid внешней обновляемой таблицы
(условие R.Accountid = N.Accountid). При выполнении обновления сначала
выбирается строка из таблицы Nachislsumma, затем выполняется вложенный
запрос, который возвращает количество ремонтных заявок для выбранного
абонента, а уже затем, в случае удовлетворения условию в секции WHERE
запроса UPDATE, происходит обновление текущей строки таблицы
Nachislsumma. Обновление происходит последовательно для каждой строки
таблицы Nachislsumma без возврата к извлечению уже просмотреных
строк.


Приведём ещё один пример использования соотнесённого вложенного
запроса. Пусть требуется уменьшить на 10 значения начислений за август
2023 г. тем абонентам, которые до 15 сентября 2023 г. заплатили за август
2023 г. сумму, меньшую среднего значения всех своих платежей. Для
решения этой задачи можно использовать запрос:
*/


UPDATE Nachislsumma
SET Nachislsum = Nachislsum - 10
WHERE Nachislyear = 2023
  AND Nachislmonth = 8
  AND Accountid IN (
                   SELECT Accountid
                   FROM Paysumma A
                   WHERE Payyear = 2023
                     AND Paymonth = 8
                     AND Paydate < '15.09.2023'
                     AND Paysum < (
                                  SELECT AVG(Paysum)
                                  FROM Paysumma B
                                  GROUP BY Accountid
                                  HAVING A.Accountid = B.Accountid
                                  )
                   );


/*
В секции FROM подзапроса в запросе UPDATE может присутствовать имя
обновляемой таблицы. В этом случае предполагается, что используется то
состояние обновляемой таблицы, которое она имела до обновления.

Например, требуется уменьшить в 2 раза значения начислений за услугу
с кодом 3, которые превышают среднее значение начислений за апрель
2024 г. по всем абонентам за эту же услугу. Для этого необходимо
применить запрос UPDATE с подзапросом:
*/

UPDATE Nachislsumma
SET Nachislsum = Nachislsum / 2
WHERE Nachislsum > (
                   SELECT AVG(Nachislsum)
                   FROM Nachislsumma
                   WHERE Nachislmonth = 4
                     AND Nachislyear = 2024
                     AND Serviceid = 3
                   )
  AND Serviceid = 3;

/*
В предыдущем примере сначала выполнится подзапрос, возвратив среднее
значение сумм начислений за апрель 2024 г., а затем произойдёт обновление
таблицы Nachislsumma. В результате выполнения запроса в таблице
Nachislsumma обновляются 14 строк.

Аналогично возможно использование соотнесённого вложенного запроса,
относящегося к той же самой таблице, которая указана в качестве
обновляемой.
Рассмотрим пример такого соотнесённого подзапроса в секции SET.
Например, для замены дат выполнения ремонтных заявок, относящихся
к каждому абоненту, на наиболее позднюю дату их регистрации можно
использовать запрос:
*/

UPDATE Request
SET Executiondate = (
                    SELECT MAX(R.Incomingdate)
                    FROM Request R
                    WHERE R.Accountid = Request.Accountid
                    );

/*
После выполнения обновления даты выполнения всех ремонтных заявок
у каждого абонента стали одинаковыми (они стали совпадать с датой
поступления последней заявки, поданной этим абонентом). Например,
от абонента с номером лицевого счёта '005488' поступило три ремонтных
заявки: первая — 04.09.2022, вторая — 17.12.2023 и последняя —
04.04.2025. Дата выполнения всех трёх заявок после выполнения запроса
стала равной 04.04.2025.



Главное расширение, которое вводит PostgreSQL в запрос UPDATE
стандарта ANSI, — секция FROM. В следующем примере показано обновление
данных с помощью запроса UPDATE с подзапросом, а потом — обновление
с использованием секции FROM.

Допустим, необходимо обновить данные в таблице Abonent, установив
идентификатор улицы, равным 1, тем абонентам, на чьи ремонтные заявки
был назначен исполнитель Школьников С. М.
Запрос может быть записан так:
*/

UPDATE Abonent
SET Streetid = 1
WHERE Accountid IN (
                   SELECT Accountid
                   FROM Request
                   WHERE Executorid IN (
                                       SELECT Executorid
                                       FROM Executor
                                       WHERE Fio = 'Школьников С. М.'
                                       )
                   );

---или проще:

UPDATE Abonent A
SET Streetid = 1
FROM Executor         AS E
         JOIN Request AS R USING (Executorid)
WHERE R.Accountid = A.Accountid
  AND E.Fio = 'Школьников С. М.';


select *
from Abonent A;
/*
Оба запроса выполняют одно и то же действие, но по-разному. Выполнение
обновления во втором запросе сводится к соединению двух таблиц —
Executor и Request — с таблицей Abonent. Таким образом, во втором
запросе секция FROM значительно упрощает реализацию запроса UPDATE.

Для обновления строк в таблице на основании данных другой таблицы
сначала необходимо определить, какие строки нужно обновить и какие
значения столбцов нужно установить. Следующие примеры запросов
демонстрируют возможность обновления таблицы Request данными
о выполнении и погашении заявок из таблицы Request_new:
*/

-- с коррелированным подзапросом
UPDATE Request
SET (Executiondate, Executed) = (
                                SELECT Executiondate, Executed
                                FROM Request_new
                                WHERE Request.Requestid = Request_new.Requestid
                                )
WHERE Request.Executiondate IS NULL;

-- с соединением
UPDATE Request
SET Executiondate = Request_new.Executiondate,
    Executed      = Request_new.Executed
FROM Request_new
WHERE Request_new.Requestid = Request.Requestid
  AND Request.Executiondate IS NULL;

/*
Следующий запрос с использованием обобщённого табличного выражения
у абонента(ов) с максимальной суммой значений начислений увеличивает
значения всех платежей на 20%:
*/

WITH Maxnachments AS (
                     SELECT Accountid, SUM(Nachislsum) AS Totalnachments
                     FROM Nachislsumma
                     GROUP BY Accountid
                     ),
     Maxnach AS (
                     SELECT MAX(Totalnachments) AS Maxnachment
                     FROM Maxnachments
                     )
UPDATE Paysumma P
SET Paysum = Paysum * 1.2
WHERE P.Accountid IN (
                     SELECT M.Accountid
                     FROM Maxnachments M,
                          Maxnach      N
                     WHERE M.Totalnachments = N.Maxnachment
                     );

/*
Использование оператора RETURNING даёт возможность отобразить данные
до или после изменения.
Например, следующий запрос:
*/

WITH a AS (
          UPDATE Abonent SET Phone = '111111'
              WHERE Accountid = '136159'
              RETURNING *
          )
SELECT *
FROM Abonent;

/*
Заменит номер телефона у абонента с номером лицевого счёта '136159'
и отобразит все данные до действия UPDATE, а такой запрос:
*/

WITH a AS (
          UPDATE Abonent SET Phone = DEFAULT
              WHERE Accountid = '136159'
              RETURNING Phone
          )
SELECT *
FROM a;

/*
покажет номер телефона после изменения.
*/


/*
Для одновременного вывода
данных до и после изменения корректным будет следующий запрос:
*/

WITH Old_data AS (
                 SELECT *
                 FROM Abonent
                 WHERE Accountid = '136159'
                 ),
     Updated AS (
                 UPDATE Abonent SET Phone = '111111'
                     WHERE Accountid = '136159'
                     RETURNING *
                 )
SELECT 'Old', *
FROM Old_data
UNION ALL
SELECT 'New', *
FROM Updated;


/*
# Удаление данных

Удаление всех, нескольких или одной строки из базовой или временной
таблицы, представления или курсора осуществляется запросом-действием
DELETE. Общий вид запроса DELETE простой: указывается, из какой таблицы
удаляются данные и, если требуется, отбираются удаляемые данные:

DELETE FROM <таблица> [WHERE <список условий>];

Существует два вида этого запроса: явный (простой) запрос DELETE
и запрос DELETE с подзапросом. Удаление данных с помощью запроса DELETE
может быть позиционированным и поисковым (аналогично описанному ранее
обновлению данных с помощью запроса UPDATE).

В PostgreSQL запрос DELETE удаляет из указанной таблицы строки,
удовлетворяющие условию WHERE. Если секция WHERE отсутствует, команда
удаляет из таблицы все строки!!!
Запрос DELETE имеет формат:

[ WITH [ RECURSIVE ] запрос_WITH [ ... ] ]
DELETE FROM [ ONLY ] базовая_таблица | представление
    [ [ AS ] псевдоним ]
[ USING элемент_FROM [ ... ] ]
[ WHERE <условие_поиска> | WHERE CURRENT OF имя_курсора ]
[ RETURNING { * | выражение_результата [ [ AS ] имя_результата ] } ]

---
С помощью DELETE можно удалять только отдельные строки, а не
индивидуальные значения столбцов, поэтому параметр столбца является
недоступным.

Если перед именем таблицы добавлено ONLY, соответствующие строки
удаляются только из указанной таблицы.
Без ONLY строки будут также удалены из всех таблиц,
унаследованных от указанной.

Можно удалять строки в таблице, используя информацию из других таблиц
БД. Это можно делать либо применив вложенные запросы, либо указав
дополнительные таблицы в опции USING.

Помимо запроса DELETE, СУБД PostgreSQL поддерживает для полного
удаления всех данных таблицы запрос TRUNCATE TABLE, который будет
рассмотрен далее.

---

## Примечания

1. Запрос DELETE без секции WHERE удаляет все строки в таблице, поэтому
   при использовании запроса DELETE надо соблюдать предельную осторожность.

2. При попытке удалить строку, на значение которой имеется ограничение
   ссылочной целостности, выдаётся сообщение об ошибке.


В общем случае правильно построить запрос на удаление довольно сложно:
при малейшей неточности запрос DELETE удалит не те данные. Поэтому
для предотвращения удаления неиспользуемых данных рекомендуется,
во-первых, сначала убедиться, что удаляются только требуемые строки
путём выборки их запросом SELECT, и, во-вторых, создавать копию таблиц.
Это особенно важно при построении запросов DELETE с подзапросом!!!


# Явный запрос DELETE
Явный запрос-действие DELETE позволяет удалить содержимое всех строк
указанной таблицы или тех её строк, которые выделяются условием поиска
секции WHERE. Условие поиска явного запроса DELETE не содержит подзапроса.

Например, для удаления всего содержимого таблицы Abonent можно выполнить
запрос:
*/

DELETE
FROM Abonent;

/*
Обычно требуется удалить только определённые строки из таблицы или
представления. Чтобы указать, какие строки нужно удалить, необходимо
использовать условие поиска, как это делается для запроса SELECT.
Так, чтобы удалить из таблицы Abonent абонента с номером лицевого счёта,
равным '005488', требуется выполнить запрос:
*/

DELETE
FROM Abonent
WHERE Accountid = '005488';

/*
Но в данном случае соответствующая строка из таблицы Abonent удалена
не будет, так как имеются строки для данного абонента в дочерних
таблицах (Nachislsumma, Paysumma, Request).

Можно использовать DELETE с условием поиска, которое затрагивает
несколько строк:
*/

DELETE
FROM Nachislsumma
WHERE Nachislyear = 2022;


/*
# Запрос DELETE с подзапросом

В секции WHERE запроса-действия DELETE можно использовать вложенные
запросы, которые могут быть как независимыми, так и коррелированными.

Рассмотрим несколько примеров использования независимого подзапроса
в секции WHERE запроса DELETE.

Для удаления ремонтных заявок, исполнителем которых является
Булгаков Т. И., необходимо выполнить запрос:
*/

DELETE
FROM Request
WHERE Executorid IN (
                    SELECT Executorid
                    FROM Executor
                    WHERE Fio = 'Булгаков Т. И.'
                    );


/*
Запрос DELETE удаляет все строки со значением столбца Executorid
исполнителя ремонтных заявок с ФИО Булгаков Т.И., возвращаемым подзапросом.

Особое место занимают запросы DELETE, где в основном запросе и подзапросе
используется одна и та же таблица. Рассмотрим примеры с независимыми
подзапросами. С помощью запроса:
*/

DELETE
FROM Paysumma
WHERE AccountID IN (
                   SELECT AccountID
                   FROM Paysumma
                   GROUP BY AccountID
                   HAVING COUNT(Payfactid) > 8
                   );

/*
Можно удалить информацию о всех платежах тех абонентов, которыми было
произведено более восьми платежей.
Запрос вида:
*/

DELETE
FROM Request
WHERE Incomingdate NOT IN (
                          SELECT MAX(Incomingdate)
                          FROM Request
                          GROUP BY AccountID
                          );

/*
в таблице ремонтных заявок для каждого абонента удаляет все заявки,
кроме самых поздних.

Подзапросы в секции WHERE могут иметь несколько уровней вложенности.
Они могут также содержать внешние ссылки на целевую таблицу запроса
DELETE.
При этом единственное ограничение на применение подзапросов
в некоторых СУБД заключается в том, что целевую таблицу нельзя указывать
в секции FROM подзапроса независимо от уровня вложенности.
Это предотвращает ссылки из вложенных запросов на целевую таблицу
(часть строк которой может быть удалена), за исключением внешних ссылок на
строку, проверяемую в данный момент на соответствие условию поиска
запроса DELETE.



Рассмотрим использование коррелированного подзапроса в секции WHERE
запроса DELETE, т.е. подзапроса, который содержит внешнюю ссылку на
текущую строку таблицы, из которой удаляются данные.
Например, для удаления всех сведений об оплате услуг абонентами, проживающими на
Татарской улице, можно использовать запрос:
*/

DELETE
FROM Paysumma P
WHERE EXISTS
      (
      SELECT *
      FROM Abonent A,
           Street  S
      WHERE S.Streetnm = 'ТАТАРСКАЯ УЛИЦА'
        AND A.Streetid = S.Streetid
        AND P.Accountid = A.Accountid
      );

/*
В этом примере при проверке условия P.Accountid = A.Accountid внутренний
запрос ссылается на строку таблицы Paysumma, проверяемую в данный момент.
Это означает, что подзапрос будет выполняться отдельно для каждой строки
таблицы Paysumma.
В результате выполнения запроса из таблицы Paysumma будет удалено 24 оплаты
абонентами с номерами лицевых счетов '126112', '136160', '136169' и '443069'
(именно они проживают на Татарской улице).

В качестве подзапроса в секции WHERE запроса DELETE можно использовать
запрос SELECT, который внутри себя содержит связанный подзапрос.
Например, требуется удалить ремонтные заявки тех абонентов, которые
оплачивали услуги более восьми раз. Запрос будет выглядеть так:
*/

DELETE
FROM Request R
WHERE R.Accountid IN (
                     SELECT P1.Accountid
                     FROM Paysumma P1
                     WHERE 8 < (
                               SELECT COUNT(*)
                               FROM Paysumma P2
                               WHERE P1.Accountid = P2.Accountid
                               )
                     );

/*
Для работы вложенного соотнесённого запроса формируется текущая строка-
кандидат (берётся первая строка таблицы Paysumma). Подзапрос возвращает
количество оплат абонента с номером лицевого счёта, содержащимся в
строке-кандидате (условие P1.Accountid = P2.Accountid). Запрос DELETE
удаляет все строки со значением столбца Accountid, входящим во множество
значений, формируемых вложенным соотнесённым запросом. В итоге будут
удалены все строки таблицы Request, в которых значение столбца Accountid
равно '115705' (количество оплат, произведённых этим абонентом, равно 9).

Существует и более простое решение данной задачи:
*/

DELETE
FROM Request A
WHERE (
      SELECT COUNT(*)
      FROM Paysumma P
      WHERE A.Accountid = P.Accountid
      ) > 8;

/*
Как уже отмечалось, DML-запросы можно также использовать в секции WITH,
что позволяет выполнять в одном запросе сразу несколько разных операций.
Первым простым примером применения CTE может быть следующий запрос,
удаляющий все платежи абонентов, у которых имеются начисления за услугу
«Газоснабжение» за 2024 год:
*/

WITH Nachisl_2024 AS (
                     SELECT DISTINCT Accountid
                     FROM Nachislsumma
                     WHERE Serviceid = (
                                       SELECT Serviceid
                                       FROM Services
                                       WHERE Servicenm = 'Газоснабжение'
                                       )
                       AND Nachislyear = 2024
                     )
DELETE
FROM Paysumma
WHERE Accountid IN (
                   SELECT Accountid
                   FROM Nachisl_2024
                   );

---Во втором примере такой запрос:

WITH Mov_Rows AS (
                 DELETE FROM Request
                     WHERE Incomingdate BETWEEN '2024-10-01' AND '2025-11-01'
                     RETURNING *
                 )
INSERT
INTO Request_log
SELECT *
FROM Mov_Rows;


select *
from Request_log;

/*
перемещает строки из Request в предварительно созданную лог-таблицу
Request_log:
*/

CREATE TABLE Request_log
(
    USER_log VARCHAR(10) DEFAULT USER,
    Date_Imz DATE        DEFAULT CURRENT_DATE
) INHERITS (Request);

/*
Запрос DELETE в WITH удаляет указанные строки из Request и возвращает
их содержимое в опции RETURNING, а затем главный запрос читает это
содержимое и вставляет в таблицу Request_log. В данном примере секция
WITH присоединяется к запросу INSERT, а не к SELECT, вложенному в INSERT.
*/


/*
Для демонстрации удаления данных из таблицы с использованием информации
из другой таблицы рассмотрим применение опции USING. Пусть в учебной БД
имеется таблица балансов абонентов (разница между суммами значений
начислений и платежей по услуге на последнее число каждого месяца):
*/


CREATE TABLE Balance
(
    Accountid     VARCHAR(6),
    Serviceid     PKField,
    Balance_date  DATE,
    Balance_value Currency
);

/*
Где Balance_date — дата баланса абонента;
Balance_value — значение баланса
абонента.

Предположим, что в данной таблице имеются полные дубли. Требуется
избавиться от них. Для идентификации и удаления дубликатов применим
метод, использующий временную таблицу. Этот метод удаляет дубликаты,
оставляя одну строку из каждой группы дубликатов, идентифицированных
по всем столбцам.
В PostgreSQL каждая строка в таблице имеет скрытый
уникальный идентификатор CTID, который представляет собой ссылку на
физическое местоположение строки в таблице. Этот столбец не
отображается явно, но его можно кратковременно использовать для
манипуляций с данными, таких как удаление дубликатов.
Вот запрос:
*/

DELETE
FROM Balance
    USING (
          SELECT Accountid,
                 Serviceid,
                 Balance_date,
                 Balance_value,
                 MIN(CTID) AS Min_ctid
          FROM Balance
          GROUP BY Accountid, Serviceid, Balance_date, Balance_value
          HAVING COUNT(*) > 1
          ) Subquery
WHERE Balance.Accountid = Subquery.Accountid
  AND Balance.Serviceid = Subquery.Serviceid
  AND Balance.Balance_date = Subquery.Balance_date
  AND Balance.Balance_value = Subquery.Balance_value
  AND Balance.CTID <> Subquery.Min_ctid;

/*
Внутренний запрос (Subquery) выбирает строки с дубликатами и находит
минимальное значение CTID (идентификатор строки). Затем DELETE удаляет
все дубликаты, кроме одной строки с минимальным CTID.
*/

/*
-----------------------------------------------------------------------------
Удаление всех строк таблицы
-----------------------------------------------------------------------------
Удалить все строки, не затронув структуру таблицы, в PostgreSQL можно
двумя способами:
1) Если не использовать секцию WHERE в запросе DELETE.
2) Использовать запрос TRUNCATE TABLE.

Удаление строк из большой таблицы, содержащей тысячи строк, является
«дорогой» операцией, поскольку СУБД поддерживает копии всех удалённых
транзакций на случай, если потребуется отменить внесённые изменения.
Если таблица большая, то этот процесс может оказаться длительным
и потребовать много места, пока операция удаления не завершится
с помощью COMMIT.
*/

/*
Иногда нужно удалить все строки из таблицы, причём точно известно,
что восстанавливать их не требуется. В таких случаях вместо запроса
DELETE можно использовать запрос TRUNCATE TABLE.
При выполнении такого запроса СУБД удаляет все данные из таблицы,
в том числе не сохраняет информацию, необходимую для отмены этих удалений.
Когда СУБД усекает (truncate) таблицу, строки удаляются безвозвратно,
однако структура таблицы остаётся.
Общий вид запроса-действия TRUNCATE TABLE в PostgreSQL:

TRUNCATE [ TABLE ] [ ONLY ] <таблица> [ * ]
    [ , ... ] [ RESTART IDENTITY | CONTINUE IDENTITY ]
    [ CASCADE | RESTRICT ]

- RESTART IDENTITY — автоматически перезапускает последовательности,
  связанные со столбцами опустошаемой таблицы;
- CONTINUE IDENTITY — позволяет не изменять значения последовательности
  (это поведение по умолчанию);
- CASCADE — автоматически опустошает все таблицы, ссылающиеся по
  внешнему ключу на заданные таблицы, или на таблицы, затронутые
  в результате действия CASCADE;
- RESTRICT — отказывает в опустошении любых таблиц, на которые по
  внешнему ключу ссылаются другие таблицы, не перечисленные в этой
  команде.

Запрос TRUNCATE TABLE работает быстрее, чем запрос удаления DELETE,
и не записывает удаляемые строки в журнал транзакций. Также он не
активирует триггеры, срабатывающие при удалении.

При этом следует учесть, что если на таблицу наложены условия, задающие
внешние ключи (без использования опции ON DELETE CASCADE), то нельзя
усечь таблицу.
Удаление не пройдёт, даже если подчинённая таблица не имеет вообще никаких
строк. Вначале следует отключить условие, используя запрос ALTER TABLE.

Например, можно удалить все строки таблицы Request так:
*/

TRUNCATE TABLE Request;


SELECT conname, conrelid::regclass
FROM pg_constraint
WHERE confrelid = 'abonent'::regclass
  AND contype = 'f';

SELECT fk.conname       AS имя_ограничения,
       fk_table.relname AS таблица_откуда_идет_ссылка,
       fk_attr.attname  AS колонка_откуда_идет_ссылка,
       pk_table.relname AS таблица_куда_идет_ссылка,
       pk_attr.attname  AS колонка_куда_идет_ссылка
FROM pg_constraint         fk
         JOIN pg_class     fk_table ON fk_table.oid = fk.conrelid
         JOIN pg_class     pk_table ON pk_table.oid = fk.confrelid
         JOIN pg_attribute fk_attr ON fk_attr.attrelid = fk.conrelid
    AND fk_attr.attnum = ANY (fk.conkey)
         JOIN pg_attribute pk_attr ON pk_attr.attrelid = fk.confrelid
    AND pk_attr.attnum = ANY (fk.confkey)
WHERE fk.confrelid = 'abonent'::regclass
  AND fk.contype = 'f';

-- 2. Удалить внешний ключ
ALTER TABLE paysumma
    DROP CONSTRAINT paysumma_accountid_fkey;

-- 3. Усечь таблицу
TRUNCATE TABLE abonent;

-- 4. Восстановить внешний ключ
ALTER TABLE paysumma
    ADD CONSTRAINT paysumma_accountid_fkey
        FOREIGN KEY (accountid) REFERENCES abonent (accountid)
            ON DELETE CASCADE;
-- добавили CASCADE, чтобы в будущем можно было усекать
/*
Однако, например, таблицу Abonent усечь не получится из-за нарушений
ссылочной целостности.
*/


/*
#Условное манипулирование данными. Обновление представлений
## Условное манипулирование данными
### Запрос INSERT ... ON CONFLICT ... DO UPDATE

В практике программирования реляционных баз данных бывают ситуации,
когда необходимо добавить новую строку с заданным набором уникальных
значений, а если такая строка уже существует, вместо добавления
обновить существующую строку.

Для решения такой задачи в других СУБД используется оператор
UPSERT (update or insert).

В PostgreSQL такой оператор отсутствует.
Но для подобных случаев PostgreSQL предоставляет в INSERT запросе
секцию ON CONFLICT.
Секция ON CONFLICT позволяет задать действие,
совершаемое вместо добавления новой строки при обнаружении конфликта
уникальности.
Действие UPDATE позволяет обновить конфликтную строку.

Например, требуется добавить исполнителя ремонтных заявок с ФИО
Петров А.С. с идентификатором 1, причём если исполнитель с таким кодом
уже существует, то следует изменить его ФИО на Петров А.С.
Запрос будет выглядеть так:
*/

INSERT INTO Executor
VALUES (1, 'Петров А. С.')
ON CONFLICT (Executorid) DO UPDATE SET Executorid = EXCLUDED.Executorid,
                                       Fio        = EXCLUDED.Fio;
----Присвоить значение из попытки вставки
----EXCLUDED — это псевдозапись (pseudo-table), содержащая значения,
-- которые пытались вставить.
/*
Пытаемся вставить (1, 'Петров А. С.')
         │
         ▼
    Executorid = 1 уже существует?
         │
    ┌────┴────┐
    ▼         ▼
   Нет        Да
    │          │
    ▼          ▼
  INSERT    UPDATE
  новая     существующая
  строка    строка
            (берём значения из EXCLUDED)

*/


select *
from executor
         /*
         Здесь ON CONFLICT означает, что целевое действие выполнено, когда строка
         уже существует (т.е. когда существует строка с тем же первичным ключом).


         При использовании ON CONFLICT DO UPDATE между ключевыми словами
         CONFLICT и DO UPDATE необходимо указать, на основе какого ограничения
         или уникального индекса проверяется наличие конфликта.
         Вместо ограничения или индекса можно указать столбец.
         */


/*
Синтаксис секции SET такой же, как в запросе UPDATE, но дополнительно
предоставляется доступ к псевдотаблице EXCLUDED.
С помощью этой псевдотаблицы можно извлечь значения столбцов строки,
которую не удалось добавить.

Если бы исполнителя с идентификатором 1 не существовало в таблице
Executor, в неё была бы вставлена новая строка.

### Примечание

ON CONFLICT DO UPDATE позволяет использовать не более одного ограничения
или уникального индекса для проверки конфликта.

Есть ещё одна особенность применения запроса
INSERT ... ON CONFLICT ... DO UPDATE. Это использование оператора
RETURNING с системным столбцом XMAX для отличия новых строк от
обновлённых. Если вставлена новая строка, то XMAX равен 0, а при
обновлении — не равен 0.
Перепишем предыдущий запрос следующим образом:

*/

         START TRANSACTION;
INSERT INTO Executor
VALUES (1, 'Петров А. С.'),
       (10, 'Сидоров А. С.')
ON CONFLICT (Executorid) DO UPDATE
    SET Executorid = EXCLUDED.Executorid,
        Fio        = EXCLUDED.Fio
RETURNING Executorid, Fio, (XMAX = 0) AS Inserted;


/*
В результате его выполнения будут выведены обновлённая и добавленная
строки соответственно с FALSE (так как при обновлении XMAX не равен 0)
и TRUE (так как при добавлении XMAX равен 0) в столбце Inserted.
*/


/*
-----------------------------------------------------------------------------
Запрос MERGE
-----------------------------------------------------------------------------
Для изменения строк в таблице с целью их обновления или удаления,
а также вставки новых из другого источника используется запрос-действие
MERGE (слияние).

Выбор действия — добавить, обновить или удалить
строки — определяется в зависимости от условия.
Запрос MERGE фактически представляют собой объединение запросов:
-INSERT,
-UPDATE
-DELETE
и позволяет избежать их многократного использования.

В PostgreSQL запрос имеет синтаксис:

[ WITH запрос_WITH [...] ]
MERGE INTO [ ONLY ] целевая_таблица [ * ] [ [ AS ] псевдоним ]
USING <исходный_источник> ON условие_соединения
<секция_when> [...]
[ RETURNING { * | выражение [ [ AS ] результат ] } [...] ]

где <исходный_источник>:
    { [ ONLY ] исходная_таблица | (подзапрос) } [ AS ] псевдоним

<секция_when>:
    { WHEN MATCHED [ AND условие ]
        THEN { изменение_при_объединении | удаление_при_объединении
               | DO NOTHING }
    | WHEN NOT MATCHED BY SOURCE [ AND условие ]
        THEN { изменение_при_объединении | удаление_при_объединении
               | DO NOTHING }
    | WHEN NOT MATCHED [ BY TARGET ] [ AND условие ]
        THEN { добавление_при_объединении | DO NOTHING } }

добавление_при_объединении:
    INSERT { (столбец [, ...]) }
    [ OVERRIDING { SYSTEM | USER } VALUE ]
    [ VALUES { { выражение | DEFAULT } [, ...] } | DEFAULT VALUES ]

изменение_при_объединении:
    UPDATE SET { столбец = { выражение | DEFAULT }
               | (столбец [, ...]) = [ ROW ] { { выражение | DEFAULT } [, ...] }
               | (столбец [, ...]) = (подзапрос) } [, ...]

удаление_при_объединении:
    DELETE

Работу запроса MERGE можно пояснить следующим образом.

Выбирается первая строка из исходной таблицы и проверяется, существует
ли такая строка целевой таблицы, что на ней становится истинным
<условие_соединения>.

Если да, то для этой строки устанавливается статус MATCHED (совпадает),
NOT MATCHED BY SOURCE (не совпадает по исходному источнику) или
NOT MATCHED [BY TARGET] (не совпадает по целевой таблице).

После этого происходит переход к первой секции WHEN, проверяется
дополнительное <условие> при его наличии и производится либо обновление
этой строки целевой таблицы согласно запросу UPDATE, либо удаление
этой строки согласно запросу DELETE.
Если таких строк целевой таблицы несколько, то все они обновляются
или удаляются.
При этом для каждой строки может быть выполнено действие не более чем
одной секции WHEN.
Для каждой отдельной строки будет выполняться действие первой же секции,
условие которой выдаст TRUE.

Если для текущей строки исходной таблицы <условие_соединения> возвращает
FALSE для всех строк целевой таблицы, то проверяется дополнительное
<условие> при его наличии и в целевую таблицу вставляется строка согласно
запросу INSERT, указанному в секции WHEN NOT MATCHED.

Описанная выше процедура повторяется для всех строк исходной таблицы.

В одном запросе MERGE могут быть определены секции WHEN MATCHED
и WHEN NOT MATCHED одновременно или одна из них (обязательно).
!!!Допускается указывать несколько секций WHEN MATCHED и WHEN NOT MATCHED!!!

Если перед именем целевой таблицы указано слово ONLY, то соответствующие
строки обновляются или удаляются только в целевой таблице, в противном
случае — также во всех таблицах, наследуемых от целевой!!!
Аналогично, если перед именем таблицы-источника указано слово ONLY,
то соответствующие строки берутся только из указанной таблицы,
в противном случае — из всех таблиц, наследуемых от указанной.
Задание «*» после имени таблицы означает использование всех дочерних таблиц.

Указание DO NOTHING означает пропуск строки.

Секция RETURNING указывает, что запрос MERGE должен вычислить и вернуть
значения для каждой вставленной, изменённой или удалённой строки.
Вычислить в ней можно любое выражение со столбцами исходной или целевой
таблицы.

Рассмотрим примеры использования запроса MERGE.
Допустим, требуется удалить все погашенные ремонтные заявки, поданные абонентами,
проживающими на улице с кодом 7.
Если у этих абонентов нет зарегистрированных заявок,
то следует по ним внести информацию о заявке в таблицу Request.
Запрос на такое слияние данных:
*/

-- =============================================================================
-- ЗАПРОС MERGE: синхронизация таблицы Request с данными из Abonent
-- =============================================================================
-- Что делает:
--   1. Для абонентов с улицы 7 (исходные данные):
--      - Если у абонента ЕСТЬ заявка И она выполнена (Executed = TRUE) →
--        удаляем эту заявку
--      - Если у абонента НЕТ заявок → создаём новую заявку
-- =============================================================================

MERGE INTO Request R -- Целевая таблица (куда вносим изменения)
USING ( -- Источник данных (откуда берём информацию)
      SELECT * -- Берём всех абонентов
      FROM Abonent
      WHERE Streetid = 7 -- Только проживающих на улице 7
      ) Ab
ON R.Accountid = Ab.Accountid -- Условие соединения: связываем заявку с абонентом

-- -----------------------------------------------------------------------------
-- СЕКЦИЯ 1: Когда заявка СУЩЕСТВУЕТ (есть связь с абонентом)
-- -----------------------------------------------------------------------------
WHEN MATCHED AND R.Executed THEN -- Если заявка найдена И она выполнена (TRUE)
    DELETE -- Удаляем эту заявку

-- -----------------------------------------------------------------------------
-- СЕКЦИЯ 2: Когда заявка НЕ СУЩЕСТВУЕТ (нет связи с абонентом)
-- -----------------------------------------------------------------------------
WHEN NOT MATCHED THEN -- Если заявка не найдена для этого абонента
    INSERT ( -- Вставляем новую заявку
        Requestid, -- Уникальный номер заявки
        Accountid, -- Лицевой счёт абонента
        Failureid, -- Код неисправности (4)
        Incomingdate, -- Дата регистрации (сегодня)
        Executed -- Статус выполнения (FALSE = не выполнена)
    )
    VALUES (NEXTVAL('Gen_Request'), -- Следующее значение из последовательности
            Ab.Accountid, -- Лицевой счёт из источника (абонент с улицы 7)
            4, -- Фиксированный код неисправности (4)
            CURRENT_DATE, -- Текущая дата
            FALSE -- Заявка не выполнена
           );

/*
Следующий запрос позволяет посмотреть статистику по использованию таблицы
Request, т.е. сколько строк было вставлено в таблицу, сколько обновлено
и сколько удалено:
*/

SELECT RELNAME,
       N_TUP_INS AS "Inserts",
       N_TUP_UPD AS "Updates",
       N_TUP_DEL AS "Deletes"
FROM pg_stat_user_tables
WHERE RELNAME = 'request';

/*
Примером вычисления следующего по порядку значения первичного ключа
может быть запрос, который для абонентов с начислениями за услугу
«Водоснабжение» более 200 условных единиц увеличивает на 10% значения
соответствующих оплат, а при отсутствии оплат добавляет их с соответствующим
значением начисления и датой оплаты, равной текущей:
*/

CREATE SEQUENCE IF NOT EXISTS gen_paysumma START WITH 71;

MERGE INTO Paysumma P
USING (
      SELECT *
      FROM Nachislsumma
      WHERE Nachislsum > 200
        AND Serviceid = 4
      ) AS N
ON (
    P.Accountid = N.Accountid
        AND P.Serviceid = N.Serviceid
        AND P.Paymonth = N.Nachislmonth
        AND P.Payyear = N.Nachislyear
    )
WHEN MATCHED THEN
    UPDATE
    SET Paysum = Paysum * 1.1
WHEN NOT MATCHED THEN
    INSERT
    VALUES (NEXTVAL('gen_paysumma'), -- ← безопасно
            N.Accountid, N.Serviceid, N.Nachislsum,
            CURRENT_DATE, N.Nachislmonth, N.Nachislyear)
    RETURNING *;


/*
В результате выполнения этого запроса в таблицу Paysumma будет добавлена
одна новая строка и в четырёх строках увеличатся значения оплат.

Необходимо иметь в виду, что в предыдущем примере в таблицу добавляется
только одна строка. В общем случае, если возможно добавление нескольких
строк, запрос не выполнится из-за попытки вставки одинаковых значений
в столбец первичного ключа.
Для предотвращения такой ситуации при получении очередного уникального
значения первичного ключа следует использовать последовательность.

Запрос MERGE является удобным и мощным средством для синхронизации
таблицы БД с внешними источниками данных. Продемонстрируем это на
следующем примере.
Требуется обновить таблицу Services из таблицы Services_New,
т.е. те услуги, которые уже присутствуют
в Services, должны быть удалены или их наименование должно быть
обновлено в зависимости от их отсутствия или наличия в Services_New
соответственно, и наконец, услуги, которых нет в таблице Services,
должны быть добавлены.
Запрос слияния:
*/

-- =============================================================================
-- ЗАПРОС MERGE: синхронизация таблицы Services с данными из Services_New
-- =============================================================================
-- Что делает: полностью синхронизирует целевую таблицу Services с источником
-- Services_New:
--   1. Услуги, которых нет в источнике → удаляются
--   2. Услуги, которых нет в целевой таблице → добавляются
--   3. Услуги, у которых изменилось название → обновляются
-- =============================================================================

MERGE INTO Services S -- Целевая таблица (которую обновляем)
USING Services_New S_New -- Таблица-источник (откуда берём новые данные)
ON S.Serviceid = S_New.Serviceid -- Условие соединения по коду услуги

-- -----------------------------------------------------------------------------
-- СЕКЦИЯ 1: Строки, которые ЕСТЬ в целевой таблице, но НЕТ в источнике
-- -----------------------------------------------------------------------------
WHEN NOT MATCHED BY SOURCE THEN -- Записи в Services, которых нет в Services_New
    DELETE -- Удаляем их (услуга больше не актуальна)

-- -----------------------------------------------------------------------------
-- СЕКЦИЯ 2: Строки, которых НЕТ в целевой таблице, но ЕСТЬ в источнике
-- -----------------------------------------------------------------------------
WHEN NOT MATCHED BY TARGET THEN -- Записи в Services_New, которых нет в Services
    INSERT -- Добавляем их как новые услуги
    VALUES (Serviceid, Servicenm) -- Вставляем код и название

-- -----------------------------------------------------------------------------
-- СЕКЦИЯ 3: Строки, которые ЕСТЬ в обеих таблицах (совпадают по коду)
-- -----------------------------------------------------------------------------
WHEN MATCHED -- Код услуги есть и в Services, и в Services_New
    AND S.Servicenm != S_New.Servicenm -- Но названия РАЗЛИЧАЮТСЯ
    UPDATE -- Обновляем название
    SET Servicenm = S_New.Servicenm
-- Берём название из таблицы-источника

/*
Вернуть содержимое таблицы Services в прежнее состояние можно тем же
запросом, предварительно выполнив следующий код:
*/

DELETE
FROM Services_new;
INSERT INTO Services_new (Serviceid, Servicenm)
VALUES (1, 'Газоснабжение');
INSERT INTO Services_new (Serviceid, Servicenm)
VALUES (2, 'Электроснабжение');
INSERT INTO Services_new (Serviceid, Servicenm)
VALUES (3, 'Теплоснабжение');
INSERT INTO Services_new (Serviceid, Servicenm)
VALUES (4, 'Водоснабжение');


/*
### Примечание

Нельзя изменять значения столбцов таблицы в секции UPDATE, по которым
связываются таблицы.

В заключение рассмотрения запросов манипулирования данными необходимо
отметить, что в них, как и в запросе выборки, могут
использоваться параметры. Например:
при вставке:
*/

INSERT INTO Abonent
    (Accountid, Streetid, Houseno, Flatno, Fio, Phone)
VALUES (:Nls, :Street, :Dom, :Kv, :Fio, :Tel);

--при обновлении:

UPDATE Abonent
SET Fio = :Fio
WHERE Accountid = :Nls;

--при удалении:

DELETE
FROM Nachislsumma
WHERE Nachislyear = :Year;


/*
Обновление представлений

Одной из операций над представлениями является их непосредственное
использование с запросами модификации DML: INSERT, UPDATE и DELETE.
Такие представления называются **модифицируемыми** (обновляемыми).
При обновлении представлений изменения автоматически передаются в базовую
таблицу, на которой основано представление.

Представление можно обновлять, если определяющий его запрос соответствует
следующим требованиям:

- должен отсутствовать предикат DISTINCT, т.е. повторяющиеся строки не
  должны исключаться из НД;
- в секции FROM должна быть задана только одна таблица, которую можно
  обновлять, т.е. у представления должна быть одна исходная таблица,
  а пользователь должен иметь соответствующие права доступа к ней.
  Если исходная таблица сама является представлением, то оно также должно
  удовлетворять этим условиям;
- каждое имя в списке возвращаемых столбцов должно быть ссылкой на простой
  столбец, т.е. в этом списке не должны содержаться выражения, вычисляемые
  столбцы или агрегатные и оконные функции, а также функции, возвращающие
  множества;
- запрос не должен содержать операции с множествами (UNION, INTERSECT
  и EXCEPT) на верхнем уровне запроса;
- в запросе не должно содержаться секций WITH, GROUP BY, HAVING, LIMIT,
  OFFSET;
- для INSERT запрос должен включать столбцы основной таблицы с ограничением
  NOT NULL, если только не указано другое значение по умолчанию.

Эти требования базируются на том принципе, что представление разрешается
обновлять в том случае, если СУБД может для каждой строки представления
найти исходную строку в исходной таблице, а для каждого обновляемого
столбца представления — исходный столбец в исходной таблице.
Если представление соответствует этим требованиям, то над ним и, как
следствие, над исходной таблицей можно выполнять имеющие смысл операции
вставки, удаления и обновления.

Например, следующие представления являются представлениями только для
чтения:
*/

/* Представление Dailyrequest только для чтения
   из-за наличия DISTINCT в запросе
*/

CREATE VIEW Dailyrequest
AS
SELECT DISTINCT AccountId, RequestId, Incomingdate, FailureId
FROM Request;

/* Представление Summtotal только для чтения из-за наличия
   агрегатной функции в списке возвращаемых элементов,
   обращения к двум таблицам и использования секции GROUP BY */

CREATE VIEW Summtotal (Abonent, Summa)
AS
SELECT Fio, SUM(Nachislsum)
FROM Abonent      A,
     Nachislsumma N
WHERE A.AccountId = N.AccountId
GROUP BY Fio;

/*
Следующее представление Pay_nach является обновляемым:
*/

CREATE OR REPLACE VIEW Pay_nach
AS
SELECT Fio,
       Accountid,
       (
       SELECT SUM(Paysum)
       FROM Paysumma
       WHERE Accountid = A.Accountid
       ) AS P,
       (
       SELECT SUM(Nachislsum)
       FROM Nachislsumma
       WHERE Accountid = A.Accountid
       ) AS N
FROM Abonent A;


WITH paysum_agg AS (
                   SELECT Accountid, SUM(Paysum) AS SumPaysum
                   FROM Paysumma
                   GROUP BY Accountid
                   ),
     nachisl_agg AS (
                   SELECT Accountid, SUM(Nachislsum) AS SumNachislsum
                   FROM Nachislsumma
                   GROUP BY Accountid
                   )
SELECT A.Fio,
       A.Accountid,
       COALESCE(p.SumPaysum, 0)     AS SumPaysum,
       COALESCE(n.SumNachislsum, 0) AS SumNachislsum
FROM Abonent                   A
         LEFT JOIN paysum_agg  p ON A.Accountid = p.Accountid
         LEFT JOIN nachisl_agg n ON A.Accountid = n.Accountid;

/*
Рассмотрим примеры работы с обновляемыми представлениями, показывающие,
как изменяются данные представления при манипулировании данными таблицы,
на основе которой оно создано, и как изменяются данные таблицы при
манипулировании данными представления.

Например, с помощью предыдущего представления Pay_nach можно заменить
ФИО у абонента с номером лицевого счёта '005488':
*/

SELECT *
FROM Pay_nach;
UPDATE Pay_nach
SET Fio = 'Петрова А. И.'
WHERE Accountid = '005488';


select *
from abonent
where Accountid = '005488';

/*
-----------------------------------------------------------------------------
Создание смешанного представления с CHECK OPTION
-----------------------------------------------------------------------------
Пусть требуется создать смешанное представление, которое содержит список
таблицы Abonent.
Вертикальное подмножество должно включать в себя столбцы
с ФИО и номерами лицевых счетов абонентов, а горизонтальное подмножество —
строки со значением номера лицевого счёта абонента, большего или равного
200000. Для этого можно использовать запрос:
*/

---drop view  Abonent_view

CREATE VIEW Abonent_view (Accountid, Fio)
AS
SELECT Accountid, Fio
FROM Abonent
WHERE Accountid >= '200000'
WITH CHECK OPTION;


SELECT *
FROM Abonent_view;

/*
Это представление является обновляемым, так как:
1) является подмножеством одной таблицы (нет соединения таблиц);
2) в списке возвращаемых элементов нет вычисляемых выражений и агрегатных
   функций;
3) используется простое условие поиска (без подзапросов);
4) запрос SELECT, на котором базируется представление, не содержит DISTINCT,
   секций GROUP BY и HAVING.

Следовательно, к этому представлению могут быть применены запросы INSERT,
UPDATE, DELETE и MERGE.
Продемонстрируем это с помощью следующих примеров.

-----------------------------------------------------------------------------
INSERT через представление
-----------------------------------------------------------------------------

Пусть требуется вставить строку в набор данных, возвращаемый представлением
Abonent_view. Это можно выполнить с помощью запроса:
*/

INSERT INTO Abonent_view (Accountid, Fio)
VALUES ('999999', 'Васильев С. В.');

/*
Необходимо отметить важное обстоятельство: с помощью созданного
представления возможна вставка значений в столбцы Accountid и Fio
и предотвращается вставка определённых значений в остальные столбцы.
При открытии доступа к этому представлению пользователям и программам
разрешается вставлять данные только в эти два столбца.

Пользователи получают возможность создавать новые строки в таблице Abonent,
вставляя данные в представление Abonent_view, но они смогут размещать значения
только в двух столбцах, которые заданы в определении представления.
-----------------------------------------------------------------------------
Проверка WITH CHECK OPTION (INSERT)
-----------------------------------------------------------------------------

Проверим работу опции WITH CHECK OPTION, которая должна ограничивать
операции DML, применяемые к представлению таким образом, чтобы они
не нарушали условия поиска запроса SELECT, на котором базируется
представление. Начнём с INSERT. Для этого выполняем запрос:
*/

INSERT INTO Abonent_view (Accountid, Fio)
VALUES ('100000', 'Скляров А. А.');

/*
Этот запрос на вставку не будет выполнен, так как содержит вставку
значений, нарушающих условие отбора запроса SELECT, с помощью которого
представление было создано. Будет выдано сообщение об ошибке такого
содержания: «ОШИБКА: новая строка нарушает ограничение-проверку для
представления Abonent_view».

Если бы при определении представления Abonent_view не было опции
WITH CHECK OPTION, то предыдущий запрос не вернул бы ошибку. Строка
с номером лицевого счёта '100000' была бы вставлена в таблицу Abonent,
на которой базируется представление, но в самом представлении её не было
бы видно. Чтобы избежать таких противоречий, нужно включать в определение
представления опцию WITH CHECK OPTION. Тогда до реального выполнения
операций модификации или вставки строк через представление для каждой
строки будет проверяться, соответствует ли она условиям представления.

-----------------------------------------------------------------------------
DELETE через представление
-----------------------------------------------------------------------------

Выполним запрос на удаление:
*/
DELETE
FROM Abonent_view
WHERE Accountid = '999999';

/*
-----------------------------------------------------------------------------
Другой пример обновляемого представления
-----------------------------------------------------------------------------

Рассмотрим ещё один пример работы с обновляемым представлением.

Пусть необходимо создать представление, которое показало бы
всю информацию об абонентах, кроме информации о номере телефона.
При этом должны быть исключены из рассмотрения
абоненты с фамилиями, начинающимися с буквы М. Запрос на создание такого
представления выглядит так:
*/

CREATE VIEW Abonent_information (Code, Street, House, Flat, Name)
AS
SELECT Accountid, Streetid, Houseno, Flatno, Fio
FROM Abonent
WHERE Fio NOT LIKE 'М%'
WITH CHECK OPTION;

/*
Это представление является обновляемым, потому что запрос основан на одной
таблице, каждый столбец представления ссылается на простой столбец,
и секция WHERE не содержит вложенного запроса. Данные, которые пользователь
увидит после выполнения запроса:
*/

SELECT *
FROM Abonent_information;

/*
-----------------------------------------------------------------------------
UPDATE через представление
-----------------------------------------------------------------------------

Допустим, что был выполнен запрос на изменение данных в таблице Abonent:
*/

UPDATE Abonent
SET Fio = 'Булгакова Т. П.'
WHERE Accountid = '080047';

/*
Пользователем также был выполнен запрос на добавление данных в
представление Abonent_information:
*/

INSERT INTO Abonent_information (Code, Street, House, Flat, Name)
VALUES ('123456', 3, 12, 34, 'Тарасов А. В.');

/*
Поскольку столбец Phone может содержать NULL, то вставка строки в
представление проходит успешно:
*/

SELECT *
FROM Abonent_information;

/*
Пользователь может выполнять в представлении запросы на обновление
и удаление данных. Допустим, были выполнены последовательно два запроса:
*/

UPDATE Abonent_information
SET Name = 'Симкина З. А.'
WHERE Code = '136159';

DELETE
FROM Abonent_information
WHERE Code = '123456';

---Данные, получаемые в результате выполнения запроса:

SELECT *
FROM Abonent_information;

/*
-----------------------------------------------------------------------------
Ограничение WITH CHECK OPTION при UPDATE
-----------------------------------------------------------------------------

Если пользователь попытается вставить или обновить значение столбца Name
для абонента с номером лицевого счёта '005488', установив ФИО абонента,
например, как Морозов А. Н., с помощью запроса:
*/


UPDATE Abonent_information
SET Name = 'Морозов А. Н.'
WHERE Code = '005488';

/*
то подобный запрос потерпит неудачу из-за того, что при создании
представления была использована опция WITH CHECK OPTION. Будет выдано
сообщение об ошибке: «новая строка нарушает ограничение-проверку для
представления Abonent_information».

Если пользователь выполнит запрос на удаление:
*/

DELETE
FROM Abonent_information
WHERE Name LIKE '%м%';

/*
то ошибки не возникнет, но в самой таблице Abonent никаких изменений
не произойдет (в данном случае это не является следствием использования
опции WITH CHECK OPTION, а есть следствие применения в запросе
представления условия поиска WHERE Fio NOT LIKE 'М%').
*/


/*
Процедурное и событийное программирование
Основы разработки исполняемых модулей.
SQL-сценарии

#### Общие сведения

Эта тема посвящена изучению процедурного языка SQL, служащего для
обработки и анализа данных, который предполагает расширение стандартного
набора запросов, изученных в предыдущих темах, средой программирования.

При создании информационных систем часто бывает целесообразно перенести
часть операций с данными с клиентского приложения на серверную часть.
Разработчики используют процедурный язык SQL для решения самых
разнообразных задач, одной из которых является реализация на сервере
основной бизнес-логики предметной области. Это даёт возможность:

- упростить программный код приложения;
- уменьшить объём данных, передаваемых по сети;
- ускорить работу приложения.

Практически в каждой современной СУБД используется свой процедурный
язык, позволяющий обрабатывать возникающие проблемы, создавать и
выполнять хранимые процедуры и функции, триггеры и сценарии с использованием
локальных переменных, операторов присваивания, ветвления и циклов.
Язык, который предоставляет такую возможность для сервера PostgreSQL,
называется Procedural Language / PostgreSQL Structured Query Language
(PL/pgSQL).
Основным назначением процедурного языка являются создание
серверной логики приложений и более гибкая обработка данных.

В базах данных информационных систем  СУБД декларативно выполняют действия,
указанные приложением.
Комбинация SQL-запросов с операторами процедурного SQL
даёт возможность автоматизировать процесс обработки и анализа данных,
в частности, с целью получения новой информации. Применительно к
рассматриваемой в настоящем учебнике предметной области это может быть
информация о дисциплине оплаты жилищно-коммунальных услуг, а также
анализ качества и своевременности выполнения ремонтных заявок.

Процедурный язык — это простой, но достаточно мощный набор процедурных
расширений языка SQL, которые были включены ещё в 1999 г. в стандарт
языка SQL3.
В каждой СУБД, использующей процедурный язык, существует возможность
создания независимых исполняемых модулей, представленных разработчиками
в виде исходных кодов:
-хранимые процедуры (ХП),
-хранимых функций (ХФ),
-триггеров,
-выполнимых блоков,
-процедурных пакетов.

Такие модули выполняются полностью на сервере, возвращая при
необходимости клиентскому приложению значения, полученные в результате
выполнения.

Процедурные объекты представляют собой группы связанных между собой
операторов процедурного SQL и запросов SQL, применение которых делает
работу разработчика более лёгкой и гибкой, поскольку часто оказывается
гораздо проще выполнить, например, ХП, чем последовательность отдельных
команд и запросов.

**Хранимые функции и процедуры** сохраняются в БД в
компилированном виде (в виде исполняемых модулей).
Фактически запросы, написанные на декларативном языке,
просто вкладываются в исполняемые модули, написанные на императивном языке,
как в следующем примере анонимного блока:


DO                                      -- 1
LANGUAGE PLPGSQL                        -- 2
$$                                      -- 3
DECLARE Request_count INTEGER;          -- 4
BEGIN                                   -- 5
    SELECT COUNT(*)                     -- 6
    INTO Request_count                  -- 7
    FROM Request                        -- 8
WHERE Executorid = (SELECT Executorid   -- 9
                        FROM Executor   -- 10
        WHERE Fio = 'Булгаков Т. И.');  -- 11
    RAISE NOTICE                        -- 12
        'Булгаков Т. И. является
             исполнителем % заявок.',   -- 13
        Request_count;                  -- 14
    -- Установить номер телефона
        абонента Свирина З. А.          -- 15
    UPDATE Abonent                      -- 16
    SET Phone = '326127'                -- 17
    WHERE Fio = 'Свирина З. А.';        -- 18
END                                     -- 19
$$;                                     -- 20

-----------------------------------------------------------------------------
Операторы процедурного SQL
(императивное программирование)
Запросы SQL
(декларативное программирование)

=============================================================================
Таблица 8.1. Комментирование кода
=============================================================================
| Строки | Описание                                                          |
|--------|-------------------------------------------------------------------|
| 1      | Команда выполнения так называемого анонимного блока процедурного  |
|        | языка                                                             |
| 2      | Объявление используемого процедурного языка                       |
| 3      | Начало текстовой строки, содержащей процедурный код               |
| 4      | Объявление целочисленной переменной для хранения данных о         |
|        | количестве ремонтных заявок, исполнителем которых является        |
|        | Булгаков Т.И.                                                |
| 5      | Ключевое слово BEGIN указывает на начало исполняемого раздела     |
| 6-11   | Запрос, определяющий общее количество ремонтных заявок,           |
|        | исполнителем которых является Булгаков Т.И. Особенно интересна    |
|        | строка 7: использованная в ней секция INTO на самом деле не       |
|        | является частью инструкции SQL, а связывает базу данных с         |
|        | локальными переменными PL/pgSQL                                   |
| 12-14  | Оператор RAISE используется для вывода количества заявок          |
| 15     | Однострочный комментарий, объясняющий назначение запроса UPDATE   |
| 16-18  | Чтобы установить номер телефона абоненту с ФИО Свирина З.А.,      |
|        | необходимо обновить таблицу Abonent                               |
| 19     | Ключевое слово END указывает на конец исполняемого раздела        |
| 20     | Конец текстовой строки, содержащей процедурный код                |
=============================================================================


Хранение процедурных объектов в том же месте, где они исполняются,
обеспечивает уменьшение объёма передаваемых по сети данных и повышает
общую производительность системы!!!
Применение процедурных объектов упрощает сопровождение программных комплексов
и внесение изменений в них, позволяет повысить независимость
прикладного программного обеспечения.
Например, изменение схемы контроля в триггере автоматически
отражается во всех приложениях, не требуя внесения в них каких-либо
изменений.

Обычно системы управления базами данных выполняют действия только
по запросам приложения. Базы данных, в которых не только выполняются
действия, явно указанные приложением, но и которые реагируют на
события, возникающие в самой БД, называются **активными**.

Применение активных баз данных в информационных системах позволяет перенести
управляющую бизнес-логику в СУБД, которая будет сама обнаруживать
возникновение заранее описанных событий в объектах контроля и управления
и реагировать на них в соответствии с заранее определёнными действиями.
Это в свою очередь позволяет упростить программный код приложения
и ускорить его работу.

Таким образом, СУБД может стать не просто центром хранения и обработки
информации от объектов контроля, но также центром принятия решений
и выработки управляющих воздействий на объекты управления.

Активные СУБД объединяют технологии БД с программированием «на логических
правилах» для придания БД возможности реагирования на некоторые
(возможно, внешние) события.

**Активность** — это способность БД выполнять некоторые действия над
данными опосредованно, без явного вмешательства приложения. Присущие
активным БД возможности реагирования на события можно использовать
в широком спектре приложений, включающих безопасность, материализацию
представлений, проверку целостности и т.д.


Активная база данных состоит из (пассивной) БД и множества активных
правил, поддерживаемых триггерами.
Формально функционирование триггера определяется в терминах предписаний,
содержащих три компонента:

1) событие;
2) условие;
3) действие, выполняемое при наступлении события и истинности условия.

---
**Триггером** называется хранимая процедура, написанная на процедурном
языке, и вызываемая системой автоматически при срабатывании связанных
с ней предписаний.
---

Следует отметить, что вместе с преимуществами использование хранимых
процедур и функций имеет следующие недостатки:

- повышение нагрузки на сервер базы данных;
- распыление бизнес-логики между СУБД и клиентским приложением;
- проблемы с быстрой миграцией программного обеспечения с одной СУБД
  на другую из-за различий в процедурных языках.

При разработке программного обеспечения важно соблюдать разумный
компромисс между процедурной (серверной) и клиентской реализацией
бизнес-логики.
Разумный компромисс зависит от конкретных требований
системы.
В типичных сценариях:
- простая логика (например, агрегаты, расчёты) реализуется в базе данных;
- сложная, многослойная логика выносится в приложение;
- критически важные проверки (права доступа, валидация) остаются
  на сервере.

Выбор всегда должен основываться на анализе производительности,
масштабируемости, безопасности и удобства поддержки.

В настоящей теме рассмотрен ряд вопросов, относящихся к процедурному
языку PL/pgSQL, приведены особенности создания и работы с различными
модулями на процедурном языке PostgreSQL.

/*Основы разработки исполняемых модулей*/
**Процедурный язык** — это блочно-структурированный язык программирования,
используемый для написания различных исполняемых модулей в СУБД.
Базовой единицей является блок!!!

Весь код PL/pgSQL состоит из одного или нескольких блоков, которые
могут следовать последовательно или вложены в другой блок!!!

Блоки могут быть именованными объектами БД — это ХП, ХФ,
триггеры — или неименованными (анонимными) блоками.
Анонимные блоки, как правило, применяются при создании скриптов для создания
базы данных и первоначального заполнения её данными, а также для выполнения
каких-либо разовых работ.
Кроме того, они часто помещаются внутрь исполняемой секции другого блока SQL.

Процедурный язык может включать стандартные запросы SQL, а также
расширения языка SQL.
Несмотря на то, что стандартный язык SQL предоставляет огромный набор
средств для взаимодействия с реляционными БД, в нём не предусмотрены
перечисленные ниже возможности, которые в ряде случаев могут
оказаться полезными:

1. перехват исключений, возникающих при обработке данных;
2. организация итераций по возвращаемым строкам данных;
3. хранение кода в БД, а не только на клиентской машине;
4. организация принятия решений и альтернативного ветвления при
   обработке строк таблицы.

Указанные возможности реализуются с помощью процедурного языка,
который содержит следующие языковые элементы расширения SQL:

1. объявление и инициализацию локальных переменных, оператор присваивания;
2. условные операторы (оператор ветвления и оператор цикла);
3. курсоры (явный или неявный) для выполнения цикла при просмотре строк;
4. генератор последовательности целых значений;
5. генерацию сообщения об исключительной ситуации и прерывание
   выполнения кода триггера или хранимой процедуры;
6. оператор для выполнения запросов в блоках, хранимых процедурах,
   функциях и триггерах.

Таким образом, в процедурном SQL обычно могут использоваться следующие
основные операторы:

1. DQL и DML SQL-запросы. Процедурный SQL был разработан для реализации
   последовательности выполнения SQL-запросов, с помощью которых
   происходит взаимодействие с БД. Напрямую с помощью SQL-запросов можно
   только выбирать данные (SELECT) и производить их изменение (INSERT,
   DELETE, UPDATE, MERGE);
2. DDL SQL-запросы;
3. DCL SQL-запросы;
4. команды управления транзакциями;
5. управляющие операторы: операторы условных переходов, перехода по метке,
   прерывания выполнения, циклы;
6. курсоры;
7. автоинкремент;
8. операторы перехвата и обработки исключений.

-----------------------------------------------------------------------------
# SQL-сценарии

Для создания и модификации БД и её объектов используется пакет запросов
языка определения данных, как правило, оформленный в виде текстового
файла, называемого *SQL-скриптом*.
Пакет из последовательности запросов и команд процедурного языка
называют *SQL-сценарием*.

**Скрипт** — это текстовый файл, содержащий запросы и обычно имеющий
расширение sql.
Все запросы, команды и операторы SQL-скрипта выполняются
последовательно в том порядке, в котором они следуют в скрипте.


В общем случае скрипт может содержать запросы создания:
(DDL-скрипт создания) и модификации (DDL-скрипт модификации)
всех объектов БД, запросы изменения данных (DML-скрипт)
и команды фиксации/отмены транзакций.
Основное предназначение скриптов — автоматическое выполнение
административных задач.

Для выполнения скриптов в PostgreSQL используется утилита psql.
Для создания скриптов может использоваться любой текстовый редактор,
например редактор скриптов в DBeaver, но сами скрипты выполняются
утилитой psql.

СУБД PostgreSQL допускает использование в файле сценария команды COPY.
Эта команда применяется для импорта и экспорта данных между таблицами
базы данных и файлами в файловой системе. Это один из самых быстрых
способов массовой загрузки или выгрузки данных, поскольку он обходит
шаги, которые обычно выполняются клиентами (например, парсинг строк или
формирование отдельных команд INSERT).

Общий синтаксис команды:

COPY table_name [ (column_list) ]
TO 'file_path' [WITH] {FORMAT format_name,
    option_name option_value[, ...]};

COPY (query)
TO 'file_path' [WITH] {FORMAT format_name,
    option_name option_value[, ...]};

COPY table_name [ (column_list) ]
FROM 'file_path' [WITH] {FORMAT format_name, option_name
    option_value[, ...]} [WHERE condition];

где:

- TO используется для экспорта данных из таблицы или результата запроса
  в файл;
- FROM используется для импорта данных из файла в таблицу;
- file_path — полный путь к файлу, который PostgreSQL будет читать или
  записывать;
- format_name: формат файла (text, csv или binary);
- option_name и option_value: дополнительные параметры, такие как
  DELIMITER, HEADER, NULL и т.д.

Пример экспорта данных из таблицы в файл:
*/

COPY Abonent TO 'C:/SQL/abonent.csv' CSV HEADER;
COPY Abonent TO 'C:/SQL/abonent.csv' WITH (FORMAT CSV, HEADER, ENCODING 'UTF8');
COPY Abonent TO 'C:/SQL/abonent.txt'
    WITH (ENCODING 'WIN1251');

SHOW server_encoding;
SHOW client_encoding;

/*
Эта команда экспортирует все строки из таблицы Abonent в файл abonent.csv
формата CSV. При этом благодаря опции HEADER добавляется строка
с названиями столбцов HEADER.

По умолчанию в формате CSV используется запятая «,» в качестве разделителя.

Изменить разделитель, например, на табуляцию можно с помощью опции
DELIMITER:
*/

COPY Abonent TO 'C:/SQL/abonent1.csv'
    WITH (FORMAT CSV, DELIMITER E'\t', HEADER);

/*
Экспортировать данные только из определённых колонок таблицы можно,
например, так:
*/

COPY Abonent (Accountid, Fio, Phone) TO 'C:/SQL/abonent2.csv' CSV HEADER;

/*
Примером экспорта данных из запроса в файл может быть следующий:
*/

COPY (SELECT *
      FROM Abonent) TO 'C:/SQL/abonent3.csv' CSV HEADER;

/*
Здесь выполняется запрос SELECT для получения всех строк из таблицы
Abonent, результат запроса экспортируется в файл abonent.csv.
*/


/*
Если необходимо выгрузить данные в простой текстовый файл (без
разделителей или с пользовательским форматом), нужно использовать
формат TEXT:
*/


COPY Abonent TO 'C:/SQL/abonent.txt' WITH (FORMAT TEXT);

/*
В этом варианте экспортируются данные из таблицы Abonent в текстовый
файл abonent.txt. Данные записываются построчно без заголовков и чётких
разделителей.
*/


/*
Команду COPY можно использовать для создания файла, который содержит
SQL-скрипты, например, INSERT команды для вставки данных. Экспорт
с кастомным форматом данных (пример генерации SQL) может быть таким:
*/
COPY (
    SELECT 'INSERT INTO Abonent VALUES (' ||
           '''' || Accountid || ''',' || Streetid || ',' ||
           Houseno || ',' || Flatno || ',' ||
           '''' || Fio || '''' ||
           CASE
               WHEN Phone IS NOT NULL
                   THEN ',''' || Phone || ''''
               ELSE ',NULL'
           END || ');' AS "Скрипт"
    FROM Abonent
    ) TO 'C:/SQL/abonent.sql';

--или

COPY (
    SELECT FORMAT('INSERT INTO Abonent VALUES (%L, %s, %s, %s, %L, %L);',
                  Accountid,
                  Streetid,
                  Houseno,
                  Flatno,
                  Fio,
                  Phone) AS sql_line
    FROM Abonent
    ) TO 'C:/SQL/abonent1.sql';

/*
=============================================================================
Шпаргалка по спецификаторам FORMAT() в PostgreSQL
=============================================================================
┌─────────────────────────────┬────────────────┬─────────────────────────────┐
│          Тип данных         │  Спецификатор  │          Почему             │
├─────────────────────────────┼────────────────┼─────────────────────────────┤
│ Число (INT, NUMERIC)        │      %s        │ Кавычки не нужны            │
├─────────────────────────────┼────────────────┼─────────────────────────────┤
│ Строка (VARCHAR, TEXT)      │      %L        │ Нужны кавычки               │
├─────────────────────────────┼────────────────┼─────────────────────────────┤
│ Дата (DATE, TIMESTAMP)      │      %L        │ Нужны кавычки               │
├─────────────────────────────┼────────────────┼─────────────────────────────┤
│ NULL                        │      %L        │ Выдаст NULL без кавычек     │
├─────────────────────────────┼────────────────┼─────────────────────────────┤
│ Имя таблицы                 │      %I        │ Для экранирования           │
├─────────────────────────────┼────────────────┼─────────────────────────────┤
│ Имя столбца                 │      %I        │ Для экранирования           │
└─────────────────────────────┴────────────────┴─────────────────────────────┘

-----------------------------------------------------------------------------
Золотое правило: если сомневаетесь — используйте %L, он безопаснее.
-----------------------------------------------------------------------------

Примеры использования:

  %s  → SELECT * FROM table WHERE id = %s           → 123
  %L  → SELECT * FROM table WHERE name = %L         → 'Иванов'
  %I  → SELECT * FROM %I ORDER BY %I               → "my table"

-----------------------------------------------------------------------------
    Важно: %L правильно обрабатывает NULL (выдаёт NULL без кавычек)
-----------------------------------------------------------------------------


Здесь COPY выполняет запрос, который генерирует SQL-скрипты для вставки
данных в таблицу Abonent. Каждая строка результата запроса содержит
запрос INSERT. Экспортирует эти строки в файл abonent.sql.


Пример импорта данных из файла abonent.csv в имеющуюся таблицу Abonent:
*/
COPY Abonent FROM 'C:/SQL/abonent.csv' CSV HEADER;

/*
При импорте пропускается первая строка в файле, так как она содержит
заголовки колонок (HEADER).

При импорте данных можно указать, в какие именно столбцы существующей
таблицы загружаются данные:
*/

COPY Abonent (Accountid, Fio, Phone)
    FROM 'C:/SQL/abonent_partial.csv' CSV HEADER;

/*
Импортирует данные из файла abonent_partial.csv только в указанные
столбцы Accountid, Fio, Phone таблицы Abonent. При импорте остальные
столбцы таблицы остаются пустыми или получают значения по умолчанию.

Если файл имеет разделитель, отличный от запятой (например, табуляцию),
необходимо указать это при импорте:
*/

COPY Abonent FROM 'C:/SQL/abonent.tsv'
    WITH (FORMAT CSV, DELIMITER E'\t', HEADER);

/*
-----------------------------------------------------------------------------
Примечание
-----------------------------------------------------------------------------

Команда COPY ... TO требует, чтобы PostgreSQL имел права на запись
в указанный каталог, а команда COPY ... FROM требует права на чтение.
Если PostgreSQL работает на сервере, файл должен находиться на сервере.

Пользователь должен иметь права на чтение (для экспорта) или на запись
(для импорта) в таблицу.

Текстовый файл сценария может содержать команду на создание БД
CREATE DATABASE.
При этом важно понимать, что различные СУБД хранят данные совершенно по-разному,
в связи с чем имеются существенные различия в синтаксисе команд CREATE DATABASE.
Обычно создание БД осуществляется «вручную», а не с помощью графического
инструментария, и выполняется только квалифицированным администратором БД.


В PostgreSQL создать базу данных можно с помощью шаблона:

CREATE DATABASE имя_базы
[ [ WITH ] [ OWNER [=] имя_пользователя ]
[ TEMPLATE [=] шаблон ]
[ ENCODING [=] кодировка ]
[ LOCALE [=] локаль ]
[ LC_COLLATE [=] категория_сортировки ]
[ LC_CTYPE [=] категория_типов_символов ]
[ TABLESPACE [=] табличное_пространство ]
[ ALLOW_CONNECTIONS [=] разрыв_подключения ]
[ CONNECTION_LIMIT [=] предел_подключений ]
[ IS_TEMPLATE [=] это_шаблон ]

Команда CREATE DATABASE создаёт базу данных PostgreSQL. Чтобы создать
базу данных, необходимо быть администратором или иметь специальное
право CREATE DB.

По умолчанию новая база данных создаётся копированием стандартной
системной базы данных template1. Задать другой шаблон можно, добавив
указание TEMPLATE имя. В частности, написав TEMPLATE template0, можно
создать чистую базу данных, содержащую только стандартные объекты,
предопределённые установленной версией PostgreSQL. Это может быть
полезно, когда не нужно копировать дополнительные объекты, добавленные
локально в template1, в новую базу данных.

Секция ENCODING отвечает за кодировку символов в новой базе данных.
В данной секции можно указать строковую константу или целочисленный
номер кодировки, либо DEFAULT, чтобы выбрать кодировку по умолчанию.

Секция LOCALE — это краткий вариант определения значения для двух
параметров LC_COLLATE и LC_CTYPE сразу, где параметр LC_COLLATE отвечает
за порядок сортировки, который будет использоваться в новой базе
данных. Этот параметр определяет порядок сортировки строк, например,
в запросах с ORDER BY, а также порядок индексов по текстовым столбцам.
По умолчанию используется порядок сортировки, установленный в шаблоне.
А параметр LC_CTYPE классифицирует символы в новой базе данных.
Этот параметр определяет принадлежность символов категориям, например:
строчные, заглавные, цифры и т.п. По умолчанию используется
классификация символов, установленная в шаблоне.

Секция TABLESPACE указывает имя табличного пространства, связываемого
с новой базой данных, или DEFAULT для использования табличного
пространства шаблона. Это табличное пространство будет использоваться
по умолчанию для объектов, создаваемых в этой базе.

Секция ALLOW_CONNECTIONS может принимать два параметра FALSE или TRUE.
Если FALSE, никто не сможет подключиться к базе данных. По умолчанию
имеет значение TRUE, т.е. подключения принимаются.


В секции CONNECTION LIMIT указывается максимальное количество
одновременных подключений к этой базе данных. Значение -1 (по умолчанию)
снимает ограничение.

Секция IS_TEMPLATE позволяет ограничить доступ пользователям на
клонирование БД. Если TRUE, базу данных сможет клонировать любой
пользователь с правами CREATEDB; в противном случае (по умолчанию),
клонировать эту базу смогут только администраторы и её владелец.

При создании БД в любой СУБД существенное значение имеет задание
кодовой таблицы (набора символов), используемой по умолчанию для
данных, хранимых в базе. Для хранения данных на русском языке пригодны
два варианта.

1. **Создание БД без задания кодовой таблицы.** Символьные данные
   хранятся в базе в том виде, как они были загружены, без каких-либо
   предварительных преобразований. Сортировка данных осуществляется
   в порядке возрастания кодовых символов.

Команда на создание БД без задания кодовой таблицы в PostgreSQL имеет
синтаксис:

CREATE DATABASE имя_базы
[WITH [OWNER [=] имя_пользователя]
ENCODING [=] SQL_ASCII
TEMPLATE [=] TEMPLATE0;

Например, для создания БД без задания кодовой таблицы можно использовать
команду:
*/
CREATE DATABASE "sqllab"
    WITH OWNER "postgres"
    ENCODING SQL_ASCII
    TEMPLATE TEMPLATE0;

/*
2. **Создание БД с кодовой таблицей русского языка.** В каждой СУБД
   используется своя кодировка для русского языка и символов кириллицы.
   В PostgreSQL это кодировка WIN1251, и в этом случае команда на
   создание БД имеет синтаксис:
*/

CREATE DATABASE "test"
    WITH OWNER "postgres"
    ENCODING 'WIN1251'
    TEMPLATE TEMPLATE0;

/*
Во многих СУБД для уже созданной БД кодовую страницу можно поменять
с помощью команды ALTER DATABASE, но в PostgreSQL в команде ALTER
DATABASE не предусмотрена возможность изменения кодовых символов.



Для подключения клиента к серверу PostgreSQL используется команда
CONNECT:

CONNECT {TO DEFAULT | имя_пользователя USING пароль}

Посмотреть список существующих баз данных можно, например, так:
*/

SELECT datname
FROM pg_database;

--Получить список подключений к БД можно следующим запросом:

SELECT pid,           -- Process ID
       usename,       -- User name
       datname,       -- Database name
       client_addr,   -- Client address
       client_port,   -- Client port
       backend_start, -- Time when backend started
       state,         -- Current state of backend
       query          -- Last executed query
FROM pg_stat_activity
WHERE state != 'idle';
-- Filter out idle connections

/*
Для физического удаления БД используется команда DROP DATABASE.
В PostgreSQL команда удаления БД имеет формат:

DROP DATABASE [IF EXISTS] имя [[WITH] (параметр [, ...])]

Данная команда удаляет из системного каталога записи, относящиеся
к базе, а также удаляет с диска каталог, содержащий данные. Выполнить
её может только владелец базы данных. Кроме того, нельзя удалить базу,
к которой есть подключение в данный момент.

Опция IF EXISTS позволяет не считать ошибкой, если база данных не
существует. В этом случае будет выдано замечание.

Одним из параметров может быть FORCE, который указывает на необходимость
попытаться принудительно завершить все существующие подключения к
целевой базе данных.

Следует отметить, что DROP DATABASE нельзя выполнять внутри блока
транзакции.
*/

/*
Создание триггеров, хранимых процедур и функций осуществляется с
использованием SQL-сценариев.
При выполнении SQL-сценария происходит компиляция ХП, ХФ и триггеров,
включённых в его текст.

В любом месте программы может быть поставлена метка, имеющая в синтаксисе

<< метка >>

где метка — произвольный идентификатор, позволяющий именовать некоторый
оператор модуля и таким образом ссылаться на него.

Допускается в качестве меток использование целых чисел без знака.
Метка располагается перед оператором на той же или отдельной строке.
Метки следует использовать для структурирования программы и более
гибкого управления выходом из вложенных циклов!!!

Процедурные объекты БД организованы в блоки:

[<< метка >>]
[DECLARE
    декларации]
BEGIN
    тело
[EXCEPTION
    операторы_обработки_исключений]
END [метка];

Здесь:
- каждый блок состоит из трёх разделов: объявления (DECLARE), тела и
  исключений (EXCEPTION). Разделы объявления и исключений являются
  необязательными, а тело — обязательным. Блок начинается с ключевого
  слова BEGIN и заканчивается точкой с запятой «;» после ключевого
  слова END;
- блок может иметь метку, расположенную в начале и конце. Метка блока
  используется, если нужно указать её в операторе EXIT тела блока или
  если требуется уточнить имена переменных, объявленных в блоке;
- раздел объявления — это место, где объявляются все переменные и
  курсоры, используемые в разделе тела. Каждый оператор в разделе
  объявлений заканчивается точкой с запятой «;»;
- тело — это место для размещения кода. Каждый оператор в основной
  части также заканчивается точкой с запятой;
- блок может содержать раздел исключений EXCEPTION.

Программа на процедурном языке имеет модульную структуру, которую можно
представить в виде четырёх разделов (блоков):

CREATE [OR REPLACE] <тип> имя (список_параметров)
AS
$$
[ DECLARE
    <список_объявления> ]
BEGIN
    <группа_операторов>
[ EXCEPTION
    <операторы_обработки_исключений> ]
END;
$$
LANGUAGE язык;

Первым разделом является заголовок. Он используется для присвоения
программе имени, для задания типа программы (например, функция,
процедура), а также списка параметров. Если раздел заголовка
используется, то это означает, что программа является именованным
блоком и её можно вызывать по имени.

Вторым разделом является раздел объявления переменных (раздел
деклараций). В нём указываются имена, типы, значения переменных,
которые используются в программе. Если переменные отсутствуют, то
этот раздел не используется.

Самый важный и необходимый раздел — раздел исполнения (раздел
исполняемого кода), в котором непосредственно на процедурном языке
описывается вся логика программы. Раздел исполняемого кода — это
единственный раздел, который обязательно должен присутствовать
в любой программе на процедурном языке, и в нём должно находиться
как минимум одно исполняемое выражение.

Последний раздел — необязательный раздел исключений, предназначенный
для нахождения и обработки всех случаев неверной работы программ.
Использование блока EXCEPTION позволяет обеспечить более надёжное
выполнение, а также даёт возможность управлять поведением программы
в случае ошибок.
*/


/*
# Переменные и константы

В модулях на процедурном языке могут использоваться переменные,
необходимые для работы модулей.

Переменные используются для следующих целей:
1) временное хранение данных;
2) манипуляция хранимыми значениями;
3) возможность многократного использования;
4) простота обслуживания;
5) повышение читаемости программы.

Всего, как правило, используется четыре типа переменных, причём
возможность применения конкретной переменной определяется тем,
является ли модуль хранимой процедурой или триггером.
Различают **локальные** и **контекстные переменные**, **входные** и **выходные
параметры**.

У переменной есть три важных атрибута:
1) имя (чтобы можно было к ней обратиться);
2) тип данных (чтобы понимать, что с этой переменной можно делать);
3) область видимости (чтобы понимать, где она будет использоваться).

В SQL у переменной есть три фазы:
1) объявление переменной при помощи инструкции DECLARE;
2) инициализация при помощи «=», «:=» или SELECT. Значение объявленной,
   но не инициализированной переменной есть NULL;
3) использование переменной при помощи подстановки её имени в нужное
   место скрипта.

**Локальные переменные** используются для хранения значений как в ХП
и в триггерах, так и в неименованных блоках процедурного языка.
Подобно переменным в других языках программирования, переменная
процедурного языка резервирует память для хранения значений,
используемых исключительно в рамках конкретного модуля.
За пределами модуля переменные недоступны, поэтому они по сути являются
закрытыми переменными.

Явное объявление локальной переменной в теле хранимой процедуры,
триггера или неименованного блока осуществляется в **разделе
деклараций** с помощью оператора DECLARE.
В PostgreSQL переменная определяется конструкцией:

имя { CONSTANT } <тип> [ COLLATE имя_правила_сортировки ]
[ NOT NULL ] [ DEFAULT | := | = ] <выражение> ];

Для переменной с ограничением NOT NULL нужно обязательно указать
значение по умолчанию.

Константа внешне похожа на переменную, но её значение должно быть
присвоено при объявлении и не может изменяться в процессе выполнения
программы. Применять именованные константы вместо конкретных значений
удобно, так как при этом можно изменить значения в блоке, модифицировав
объявление в разделе деклараций.
Даже если значение в блоке встречается только один раз, желательно объявить
его как именованную константу.
Это делает программу более удобной для восприятия.

В качестве типа данных переменной можно указывать:
1) один из системных типов;
2) ранее созданный домен;
3) конструкцию для заимствования типа данных столбца таблицы
   (переменной или представления). Такое явное объявление переменной
   осуществляется конструкцией вида:

   имя { переменная%TYPE | таблица.столбец%TYPE }

4) конструкцию для заимствования типа данных строки таблицы
   (составной тип). Конструкция имеет вид:

   имя таблица%ROWTYPE


При этом следует отметить, что переменные с заимствованным типом данных
не наследуют ограничения столбца, такие как NOT NULL или значения
по умолчанию!!!

Например, чтобы объявить переменную «x» целого типа, можно использовать
оператор:
*/

DECLARE x INTEGER;

/*
Объявить переменную «y» на существующем домене можно следующим образом:
*/

DECLARE y Currency;

/*
Объявить переменную New_phone с типом данных, совпадающим с типом
столбца Phone таблицы Abonent, можно так:
*/

DECLARE New_phone Abonent.Phone%TYPE;

/*
Все локальные переменные должны быть объявлены до первого выполняемого
блока процедурного языка (триггера, процедуры). Допускается при
объявлении локальной переменной сразу же её инициализировать.
Например:
*/

DECLARE x INTEGER := 123;
DECLARE x INTEGER = 123;
DECLARE x INTEGER DEFAULT 123;

/*
Константа z объявляется следующим образом:
*/

z CONSTANT INTEGER := 123;

/*
Объявить переменную New_executor с типом данных, совпадающим с типом
строки таблицы Executor, и проинициализировать её можно так:
*/

New_executor Executor%ROWTYPE = ROW(7, 'Феськов А. В.');


/*
Если программа содержит вложенные блоки, то значение переменной,
объявленной во внешнем блоке, недоступно переменной с тем же именем
во внутреннем блоке, а также наоборот!!!

Объявленным переменным в дальнейшем могут присваиваться различные
значения с помощью оператора присваивания. Переменным должны
присваиваться значения того типа данных, с каким они были объявлены.

В PostgreSQL оператор имеет синтаксис:
имя_локальной_переменной { ::= | = } <выражение>;

Например, присваивание значения ранее инициализированной переменной
может выглядеть так:
*/

New_phone = '556601';
New_phone := '556601';

/*
Для последовательности Executor_id, получение
очередного значения и присвоение его локальной переменной Executor_number
(в теле триггера или функции) имеют вид:
*/

Executor_number := NEXTVAL('Executor_ID');

--или

SELECT LAST_VALUE
FROM Executor_id INTO Executor_number;

SELECT LAST_VALUE
INTO Executor_number
FROM Executor_id;

/*
СУБД делает доступными множество переменных, поддерживаемых в контексте
текущего соединения клиента и его деятельности. Эти **контекстные
переменные** доступны для использования в процедурных языках.

Одними из таких переменных являются переменные, характеризующие статус
выполнения оператора или запроса. Определить статус можно, используя
системные индикаторы состояния или специальную переменную (функцию).

В PostgreSQL типичным примером является контекстная переменная ROW_COUNT,
которая возвращает количество строк, полученных последним выполненным
запросом или оператором. Для получения значения этой переменной нужно
использовать следующую команду:
*/

GET DIAGNOSTICS переменная_целого_типа { = | ::= } ROW_COUNT;

/*
В PostgreSQL существует второй способ определения статуса выполнения
команды, который заключается в проверке значения контекстной булевой
переменной FOUND. При вызове функции на PL/pgSQL значение этой переменной
инициализируется в FALSE. Далее при результативном выполнении запросов
или операторов значение переменной изменяется на TRUE.

В триггерах для реализации отслеживания целостности данных используются
контекстные переменные OLD.столбец и NEW.столбец.
Эти переменные хранят старые (до изменения) и новые (после изменения)
значения указанного столбца таблицы, когда выполняется запрос
на модификацию данных.

Также в триггерах может использоваться контекстная переменная TG_OP
для задания определённых действий в зависимости от типа события DML,
для которого срабатывает триггер.

**Входные параметры** недоступны для использования в триггерах. Они
применяются для передачи значений ХП и ХФ из клиентских приложений
или других ХП и ХФ.


**Выходные параметры** также недоступны для использования в триггерах.
Они используются для возвращения значений из ХП и ХФ вызвавшим их
объектам.

Примеры практического использования всех четырёх типов переменных
в модулях на процедурном языке PL/pgSQL приведены при изучении
анонимных блоков, ХП, ХФ и триггеров.

В PL/pgSQL можно использовать запросы SELECT, INSERT, UPDATE, DELETE
и MERGE, а также операторы управления транзакциями COMMIT, ROLLBACK
и SAVEPOINT.

Запрос SELECT используется для присвоения значений переменным:

SELECT список_возвращаемых_элементов
INTO [STRICT] <список_переменных>
FROM список_источников
WHERE <условие_поиска>;

где <список_переменных> — это список скалярных переменных, разделённых
запятыми, или строка. В случае отсутствия ключевого слова STRICT
переменным списка присваиваются значения только первой возвращаемой
строки, или NULL, если список возвращаемых элементов пуст.

Использование DML-запросов в PL/pgSQL осуществляется в соответствии
с правилами их применения в SQL.



##Операторы

При программировании на процедурных языках существует возможность
использовать:
- ветвление;
- циклическое выполнение группы операторов;
- переходы.

#### Условный оператор

Для осуществления ветвления по условию в процедурных языках, как и в
большинстве языков программирования, используется оператор **IF**.
В PL/pgSQL оператор ветвления IF представлен следующим синтаксисом:

IF логическое_условие1 THEN
    группа_операторов1
[ELSEIF логическое_условие2 THEN
    группа_операторов2] [; ...]
[ELSE
    группа_операторов3]
END IF;

где логическое_условие — любой предикат, который должен быть истинным,
чтобы выполнялась группа_операторов, следующая за THEN;


<группа_операторов> ::= { <блок_операторов>
                         | DML_оператор
                         | оператор_процедурного_языка }

<блок_операторов> ::=
  BEGIN
    [ группа_операторов ... ]
  END

**Блок операторов** — это группа операторов SQL, рассматриваемых как
единое целое. Блок операторов начинается с зарезервированного слова
BEGIN и заканчивается зарезервированным словом END. При этом блок
операторов может содержать вложенный блок операторов, заключённый
в операторные скобки BEGIN ... END, и т.д. Следует отметить, что между
BEGIN ... END может не быть ни одного оператора, т.е. допустим «пустой»
блок операторов.

Следует отметить, что если <группа_операторов> представляет собой
один-единственный DML_оператор или оператор_процедурного_языка, то
заключать данный оператор в скобки BEGIN ... END не обязательно.

Конструкция IF ... ELSIF ... фактически представляет собой один из
способов реализации функций оператора CASE. Условия в конструкции
IF ... ELSIF ... всегда выполняются в порядке их следования в операторе!!!

Следующий фрагмент кода иллюстрирует использование оператора IF
в теле ХП в предположении, что Street_cod, House_nom, Flat_nom были
ранее объявлены как локальные переменные или входные параметры,
а Line — как локальная переменная или выходной параметр:
*/

IF
(House_nom IS NOT NULL AND Flat_nom IS NOT NULL
)
THEN
    Line = 'Код улицы - ' || Street_cod || ', д.' || House_nom
           || ', кв.' || Flat_nom;
ELSE
    Line = Street_cod;
END IF;


/*
В PL/pgSQL может быть организовано множественное ветвление, например,
определение уровня оплаты V_paylevel в зависимости от значения платы
(переменная V_paysum):
*/

IF V_paysum <= 150
THEN
    V_paylevel := 'Low Pay';
ELSIF V_paysum > 500 AND V_paysum <= 700
THEN
    V_paylevel := 'Avg Pay';
ELSIF V_paysum > 700 AND V_paysum <= 1500
THEN
    V_paylevel := 'Moderate Pay';
ELSE
    V_paylevel := 'High Pay';
END IF;

/*
В конце каждого оператора ставится точка с запятой, в том числе и перед
ELSE и ELSIF.

В PL/pgSQL имеется оператор:
NULL;

который ничего не делает. Он может применяться, например, для
преднамеренного задания пустой одной из ветвей оператора IF/THEN/ELSE.

DO $$
DECLARE
    status TEXT := 'pending';
BEGIN
    IF status = 'approved' THEN
        RAISE NOTICE 'Заявка одобрена';
    ELSE
        NULL;  -- Здесь ничего не делаем
    END IF;
END;
$$;

-----------------------------------------------------------------------------
### Оператор множественного выбора CASE и выражение CASE

Система управления БД PostgreSQL поддерживает использование в
процедурном языке оператора множественного выбора **CASE** и выражения
CASE.

Как и в обычном SQL, PL/pgSQL поддерживаются две формы оператора CASE:
простая и с поиском:

#### CASE (простая форма)
WHEN выражение [, ...] THEN операторы;
[WHEN выражение [, ...] THEN операторы ...];
[ELSE операторы];
END CASE;

#### CASE (форма с поиском)
WHEN логическое_выражение THEN операторы;
[WHEN логическое_выражение THEN операторы ...];
[ELSE операторы];
END CASE;

В конце каждого оператора, как и в случае с IF, ставится точка с запятой.

Принцип работы оператора CASE в PL/pgSQL аналогичен принципу работы
операции CASE в обычном SQL (см. лекц. 3.4).

Выражение **CASE** возвращает одно значение, которое является результатом
вычисления выбранного выражения. Это значение присваивается определённой
переменной, используемой в дальнейших выражениях.

Синтаксис простого выражения CASE:

переменная := CASE выражение
    WHEN выражение [, ...] THEN выражение
    [WHEN выражение [, ...] THEN выражение ...]
    [ELSE выражение]
END;

Синтаксис формы выражения CASE с поиском:

переменная := CASE
    WHEN логическое_выражение THEN выражение
    [WHEN логическое_выражение THEN выражение ...]
    [ELSE выражение]
END;

В отличие от оператора множественного выбора CASE, здесь код завершается
словом END и после выражений не ставится точка с запятой.



# Операторы циклов

**Безусловный цикл.** PL/pgSQL поддерживает безусловный цикл LOOP.
Безусловный цикл реализует повторное выполнение фрагмента кода
в следующем виде:

<<метка>>
LOOP
    <группа_операторов>
    { EXIT | EXIT WHEN условие }
END LOOP [метка];

Выполнение повторяется до тех пор, пока цикл не будет явным образом
завершён с помощью оператора EXIT или EXIT WHEN. Оператор EXIT немедленно
завершает цикл, а оператор EXIT WHEN завершает цикл при истинности
заданного условия.

Например, следующий цикл будет выполняться до тех пор, пока переменная
V_counter не превысит значение 15:
*/


DO $$
    DECLARE
        V_counter INTEGER := 0;
    BEGIN
        LOOP
            V_counter := V_counter + 1;
            EXIT WHEN V_counter > 15;
            RAISE NOTICE 'V_counter = %', V_counter;
        END LOOP;
    END;
$$;


/*
При организации простого цикла следует внимательно следить за наличием
выхода из цикла, чтобы не получить бесконечный цикл.

**Цикл WHILE.** Для организации цикла с предусловием используется
оператор WHILE. Тело цикла WHILE обрабатывается, пока выполняется
заданное логическое условие.

В PL/pgSQL цикл имеет следующий синтаксис:

<<метка>>
WHILE логическое_условие LOOP
    <группа_операторов>
END LOOP [метка];

Следующий фрагмент кода иллюстрирует использование в PL/pgSQL оператора
WHILE в предположении, что переменная Result была ранее объявлена
и инициализирована как локальная переменная или параметр строкового
типа:
*/

DO $$
    DECLARE
        Result TEXT := '123';
    BEGIN
        WHILE LENGTH(Result) < 8
            LOOP
                Result := '0' || Result;
            END LOOP;
        RAISE NOTICE 'Result = %', Result;
    END;
$$;

/*
В этом фрагменте переданное строковое значение (Result) дополняется
нулями слева до получения восьми символов.
Result = 00000123


Цикл FOR. Различают два варианта реализации цикла FOR в процедурном
языке: цикл со счётчиком и цикл неявного курсора.

Цикл FOR со счётчиком позволяет повторить фрагмент кода заранее
определённое число раз и записывается в формате:

[<<метка>>]
FOR переменная_цикла IN [REVERSE]
    нижняя_граница..верхняя_граница [BY шаг]
LOOP
    <группа_операторов>
END LOOP [метка];

Переменная цикла создаётся автоматически. Циклу можно присвоить
метку. Это позволит обращаться к переменной цикла с указанием метки:
метка. С указанием REVERSE нижняя и верхняя границы меняются местами.

Данный цикл удобно использовать, если известно число итераций,
которое должно быть выполнено. Оно вычисляется на основе нижней
и верхней границ переменной цикла. Переменная цикла инициализируется
значением нижней границы (или, если указана опция REVERSE, значением
верхней границы). Затем при каждой итерации значение переменной
цикла увеличивается (или уменьшается, если указана опция REVERSE).
Цикл завершается, когда значение переменной превышает верхнюю
границу (или, при наличии опции REVERSE, становится меньше нижней
границы).

Ниже приведён пример цикла FOR, тело которого выполняется 7 раз.
Пример не имеет практического смысла, а только демонстрирует
использование цикла. В отличие от простого цикла и цикла WHILE,
объявлять переменную V_counter цикла FOR не требуется:
*/
DO $$
    BEGIN
        FOR V_counter IN 2020..2026
            LOOP
                RAISE NOTICE 'V_counter = %', V_counter;
            END LOOP;
    END;
$$;


DO
$$
    DECLARE
        V_year  INTEGER;
        V_total NUMERIC;
    BEGIN
        FOR V_year IN 2020..2025
            LOOP
                SELECT SUM(Paysum)
                INTO V_total
                FROM Paysumma
                WHERE Payyear = V_year;

                RAISE NOTICE 'Год %: общая сумма платежей = % руб.', V_year, COALESCE(V_total, 0);
            END LOOP;
    END;
$$;


DO
$$
    DECLARE
        V_year    INTEGER;
        V_nachisl NUMERIC;
        V_pay     NUMERIC;
    BEGIN
        FOR V_year IN 2022..2025
            LOOP
                SELECT SUM(Nachislsum)
                INTO V_nachisl
                FROM Nachislsumma
                WHERE Nachislyear = V_year;

                SELECT SUM(Paysum)
                INTO V_pay
                FROM Paysumma
                WHERE Payyear = V_year;

                RAISE NOTICE 'Год %: Начисления = %, Платежи = %, Разница = %',
                    V_year,
                    COALESCE(V_nachisl, 0),
                    COALESCE(V_pay, 0),
                    COALESCE(V_nachisl - V_pay, 0);
            END LOOP;
    END;
$$;


DO
$$
    DECLARE
        V_year    INTEGER;
        V_nachisl NUMERIC;
        V_pay     NUMERIC;
    BEGIN
        RAISE NOTICE 'Годы с задолженностью:';
        FOR V_year IN 2022..2025
            LOOP
                SELECT SUM(Nachislsum)
                INTO V_nachisl
                FROM Nachislsumma
                WHERE Nachislyear = V_year;

                SELECT SUM(Paysum)
                INTO V_pay
                FROM Paysumma
                WHERE Payyear = V_year;

                IF COALESCE(V_nachisl, 0) > COALESCE(V_pay, 0)
                THEN
                    RAISE NOTICE '  % год: долг = % руб.', V_year, COALESCE(V_nachisl - V_pay, 0);
                END IF;
            END LOOP;
    END;
$$;



DO
$$
    DECLARE
        V_year INTEGER;
        V_rec  RECORD;
    BEGIN
        FOR V_year IN 2022..2025
            LOOP
                RAISE NOTICE '--- Топ-3 абонента за % год ---', V_year;

                FOR V_rec IN
                    SELECT A.Accountid, A.Fio, SUM(P.Paysum) AS total
                    FROM Paysumma         P
                             JOIN Abonent A ON P.Accountid = A.Accountid
                    WHERE P.Payyear = V_year
                    GROUP BY A.Accountid, A.Fio
                    ORDER BY total DESC
                    LIMIT 3
                    LOOP
                        RAISE NOTICE '  % (%- %) руб.', V_rec.Fio, V_rec.Accountid, V_rec.total;
                    END LOOP;
            END LOOP;
    END;
$$;



DO
$$
    DECLARE
        V_year  INTEGER;
        V_month INTEGER;
        V_total NUMERIC;
    BEGIN
        FOR V_year IN 2022..2025
            LOOP
                FOR V_month IN 1..12
                    LOOP
                        SELECT SUM(Paysum)
                        INTO V_total
                        FROM Paysumma
                        WHERE Payyear = V_year
                          AND Paymonth = V_month;

                        IF COALESCE(V_total, 0) > 0
                        THEN
                            RAISE NOTICE 'Год %, месяц %: сумма платежей = % руб.',
                                V_year, V_month, V_total;
                        END IF;

                    END LOOP;
            END LOOP;
    END;
$$;

/*
# Операторы перехода

В процедурном языке PL/pgSQL существуют операторы, позволяющие:

1) выйти из цикла или перейти на начало этого же или другого цикла;
2) перейти на конечный оператор процедуры, функции или триггера,
   т.е. завершить выполнение программы;
3) временно приостановить выполнение хранимой процедуры для передачи
   вызвавшей программе полученных данных;
4) досрочно начать новую итерацию цикла.

Оператор **EXIT** используется для завершения цикла, когда дальнейшая
обработка нежелательна или невозможна.
Синтаксис:

EXIT [метка] [WHEN <условие>];

По оператору EXIT цикл завершается немедленно и управление переходит
к следующему за END LOOP оператору, а по оператору EXIT WHEN цикл
завершится только когда станет истинным условие в секции WHEN,
например:
*/

DO $$
    DECLARE
        Pausum NUMERIC := 100;
    BEGIN
        LOOP
            Pausum := 2 * Pausum;
            EXIT WHEN Pausum > 4000;
            RAISE NOTICE 'Pausum = %', Pausum;
        END LOOP;
        RAISE NOTICE 'Финальное значение Pausum = %', Pausum;
    END;
$$;



DO
$$
    DECLARE
        Pausum NUMERIC := 100;
    BEGIN
        LOOP
            Pausum := 2 * Pausum;

            IF Pausum > 4000
            THEN
                EXIT;
            END IF;

            RAISE NOTICE 'Pausum = %', Pausum;
        END LOOP;

        RAISE NOTICE 'Финальное значение Pausum = %', Pausum;
    END;
$$;

/*
Оператор **CONTINUE** моментально начинает новую итерацию внутреннего
цикла оператора WHILE или FOR.

С использованием необязательного параметра метки CONTINUE также может
начинать новую итерацию для внешних циклов.

Синтаксис оператора CONTINUE:

CONTINUE [метка] [WHEN <условие>];

Пример:

Значение V_counter  	CONTINUE WHEN V_counter < 10	Результат
2..9	                TRUE → CONTINUE	                Пропускает RAISE NOTICE
10..15	                FALSE	                        Выполняет  RAISE NOTICE
*/

DO $$
    DECLARE
        V_counter INTEGER := 1;
    BEGIN
        LOOP
            V_counter := V_counter + 1;
            EXIT WHEN V_counter > 15;
            CONTINUE WHEN V_counter < 10;
            -- вычисления для V_counter в диапазоне 10..15
            RAISE NOTICE 'V_counter в диапазоне 10..15: %', V_counter;
        END LOOP;
    END;
$$;

/*
Следует отметить, что в PL/pgSQL существует специальный оператор
**PERFORM**, который позволяет выполнить запрос без возврата
результатов.
Оператор PERFORM часто используется внутри анонимных
блоков, хранимых процедур и функций для выполнения определённых
действий без необходимости возвращать результаты выполнения.
Синтаксис оператора выглядит следующим образом:

PERFORM [запрос];

Например, если следующий запрос для выборки данных из таблицы
Paysumma:
*/

SELECT *
FROM Paysumma
WHERE Paysum > 1800;

--выполнить с помощью PERFORM на PL/pgSQL следующим образом:
DO $$
    BEGIN
        PERFORM * FROM Paysumma WHERE Paysum > 1800;
    END;
$$;

/*
то PERFORM выводит только строки с информацией о времени выполнения
запроса (в миллисекундах), не возвращает и не отображает фактические
данные.
*/


/*
##Вывод сообщений о событии базы данных.
Анонимные блоки.
Обработка ошибок

#### Вывод сообщений о событии базы данных

В СУБД PostgreSQL имеется возможность отправлять клиентским приложениям
сообщения о действиях, выполненных в базе данных. Использование этого
механизма позволяет оперативно информировать заинтересованных клиентов
о наиболее важных событиях внутри базы данных. В биллинговых
информационных системах такими событиями могут быть фиксация поступления
произведённого платежа, регистрация заявки на ремонт, образование
задолженности, смена тарифа и многое другое. Информирование абонентов
о подобных событиях с помощью соответствующих клиентских приложений
является весьма полезным.

В PostgreSQL для вывода сообщений пользователю или для генерирования
ошибок служит команда RAISE, один из форматов которой имеет следующий:

RAISE [<уровень>] 'формат' [, выражение [, ...]]
[USING параметр = значение [, ...]];

Возможен разный <уровень> важности сообщения:
- DEBUG (запись информации в журнал сервера);
- LOG (запись информации в журнал сервера с более высоким приоритетом);
- INFO, NOTICE и WARNING (запись информации в журнал сервера и передача
  в клиентское приложение);
- EXCEPTION (выдают ошибку, обычно выходят из текущей транзакции).

Если не указать уровень, то команда RAISE по умолчанию использует
уровень EXCEPTION, выдаст сообщение об ошибке и остановит текущую
транзакцию.
Важно помнить, что клиенту передаются не все сообщения,
а только уровни:
-INFO,
-NOTICE,
-WARNING.

Параметр **формат** служит для формирования текста сообщения. За этим
параметром могут следовать переменные, значения которых подставляются
в строку 'формат' в те позиции, которые обозначены символом «%».

В части формата «%» выражается как заполнитель, и его фактическое
значение заменяется только следующей переменной при выполнении команды:
*/
--вывести значение переменной a:
RAISE NOTICE 'Вызов Ps (%)', a;

--Значение переменной «a» заменит % в формате;

-- вывести исключение:
RAISE EXCEPTION 'Ошибка. Требуется исправить!';

-- вывод SQLERRM для отображения сообщений об ошибках:
RAISE EXCEPTION '%', SQLERRM;

/*
Количество заполнителей должно совпадать с количеством аргументов,
иначе PostgreSQL выдаст ошибку.

Возможные ключевые слова для параметра:
- MESSAGE устанавливает текст сообщения об ошибке. Этот параметр нельзя
  применять, если в команде RAISE присутствует формат перед USING;
*/
DO $$
    DECLARE
        Acc TEXT := '999999';
    BEGIN
        IF NOT EXISTS
        (
        SELECT 1
        FROM Abonent
        WHERE Accountid = Acc
        )
        THEN
            RAISE EXCEPTION USING MESSAGE = 'Абонент с номером ' || Acc || ' не найден';
        END IF;
    END;
$$;


-- DETAIL предоставляет детальное сообщение об ошибке;


DO $$
    DECLARE
        Acc TEXT := '999999';
    BEGIN
        IF NOT EXISTS
        (
        SELECT 1
        FROM Abonent
        WHERE Accountid = Acc
        )
        THEN
            RAISE EXCEPTION 'Абонент не найден'
                USING DETAIL = 'Запрос: SELECT * FROM Abonent WHERE Accountid = ' || Acc,
                    HINT = 'Проверьте правильность номера лицевого счёта';
        END IF;
    END;
$$;

-- HINT предоставляет подсказку по вызванной ошибке;

DO $$
    DECLARE
        V_paysum NUMERIC := -100;
    BEGIN
        IF V_paysum < 0
        THEN
            RAISE EXCEPTION 'Сумма платежа не может быть отрицательной'
                USING HINT = 'Платеж должен быть больше или равен 0';
        END IF;
    END;
$$;


-- ERRCODE устанавливает код ошибки (SQLSTATE). Код ошибки задаётся либо
-- по имени, либо напрямую пятисимвольным кодом SQLSTATE.

DO $$
    DECLARE
        Acc     TEXT := '0005488';
        V_count INTEGER;
    BEGIN
        SELECT COUNT(*) INTO V_count FROM Paysumma WHERE Accountid = Acc;

        IF V_count = 0
        THEN
            RAISE EXCEPTION 'У абонента % нет платежей', Acc
                USING ERRCODE = 'no_data_found';
        END IF;
    END;
$$;

/*
Например, оператор:

RAISE EXCEPTION 'Номер лицевого счёта % не существует', Acc
USING HINT = 'Проверьте номер лицевого счёта';

прерывает транзакцию и выдаёт сообщение об ошибке с подсказкой.

-----------------------------------------------------------------------------
### Анонимные блоки

При работе с СУБД существует возможность выполнения кода на процедурном
языке (блока) без оформления именованных ХП или ХФ. В PostgreSQL такую
возможность предоставляет выполнимый (анонимный) блок. Анонимный блок
применяется для увеличения производительности выполнения на стороне
базы данных сложного кода, обрабатывающего данные.
Блок компилируется при каждом выполнении, не сохраняется в БД и нет прямой
возможности передать параметры и вернуть значение.

При разработке анонимного блока, называемого DO-блоком, функции или
хранимой процедуры тело должно быть передано в виде строкового литерала:

DO
[
    <<метка>>
    [LANGUAGE язык]
    [DECLARE
        <список_объявления>]
    BEGIN
        <группа_операторов>
        [EXCEPTION
            <операторы_обработки_исключений>]
    END
    [метка]
]



Оператор DO не принадлежит блоку. Он используется для выполнения
анонимного блока. Оператор LANGUAGE задаёт имя процедурного языка,
на котором написан код. По умолчанию подразумевается PL/pgSQL.

Так как символом «'» помечают начало и конец DO-блока, то нужно
экранировать все одинарные кавычки «'» в теле, например следующим
образом:

DO
'<<первый_блок>>
DECLARE
    i INT := 0;
BEGIN
    i := i + 1;
    RAISE NOTICE '' Текущее значение счетчика: % '', i;
END первый_блок ';

Результат выполнения:
Текущее значение счетчика: 1

Для удобства одинарную кавычку «'» заменяют двойным долларом «$$».

Также можно использовать токен перед $$, как имя$$:
*/


DO -- вывод построчно, а не в одну строку
$$
    <<первый_блок>>
        DECLARE
        i INT := 0;
    BEGIN
        i := i + 1;
        RAISE NOTICE 'Текущее значение счетчика: % ', i;
    END первый_блок $$;

/*
Результат выполнения:
Текущее значение счетчика: 1

или между $$, как $имя$ следующим образом:
*/


DO -- вывод построчно, а не в одну строку
$первый_блок$
    DECLARE
        i INT := 0;
    BEGIN
        i := i + 1;
        RAISE NOTICE ' Текущее значение счетчика: % ', i;
    END $первый_блок$;


/*

В дальнейшем будем использовать следующий формат:

DO
[ LANGUAGE язык ]
{ $$ | $метка$ }
[ DECLARE
    <список_объявления> ]
BEGIN
    <группа_операторов>
    [ EXCEPTION
        <операторы_обработки_исключений> ]
END { $$ | $метка$ };

-----------------------------------------------------------------------------
Анонимный DO-блок формирования чисел Фибоначчи:
-----------------------------------------------------------------------------
*/
DO $$
    DECLARE
        N       INT = 45;
        Counter INT = 1;
        Two     INT = 0;
        One     INT = 1;
    BEGIN
        WHILE (Counter <= N)
            LOOP
                Two = One + Two;
                One = Two - One;
                Counter = Counter + 1;
                --RAISE NOTICE 'Число %', One;
            END LOOP;
        RAISE NOTICE 'Число %', One;
    END $$;

/*
-----------------------------------------------------------------------------
Вложенные блоки (субблоки)
-----------------------------------------------------------------------------

Процедурный SQL позволяет размещать блок внутри тела другого блока.
Этот блок, вложенный в другой блок, называется субблоком. Блок,
содержащий субблок, называется внешним блоком. Субблоки используются
для группировки операторов, так что большой блок можно разделить на
меньшие и более логические субблоки. Переменные в подблоке могут иметь
те же имена, что и во внешнем блоке, даже если это не очень хорошая
практика.

Если в субблоке объявляется переменная с тем же именем, что и во внешнем
блоке, переменная из внешнего блока скрывается для вложенного блока.
Для получения доступа к переменной во внешнем блоке можно использовать
метку блока для уточнения её имени ВАЖНО!!!:
*/

DO
$$
    <<внешний_блок>>
        DECLARE
        I INT := 0;
    BEGIN
        I := I + 1;
        RAISE NOTICE 'Текущее значение счётчика %', I;
        DECLARE
            I INTEGER := 0;
        BEGIN
            I := I + 10;
            RAISE NOTICE 'Текущее значение счётчика в субблоке %', I;
            RAISE NOTICE 'Текущее значение счётчика во внешнем блоке %',
                внешний_блок.I;
        END;
        RAISE NOTICE 'Текущее значение счётчика во внешнем блоке %', I;
    END внешний_блок
$$;

/*
┌─────────────────────────────────────────────────────────────────────────────┐
│  Внешний блок (метка: внешний_блок)                                         │
│  ┌─────────────────────────────────────────────────────────────────────┐    │
│  │  I (внешняя) = 0 → 1                                                │    │
│  │                                                                     │    │
│  │  ┌──────────────────────────────────────────────────────────────┐   │    │
│  │  │  Субблок                                                     │   │    │
│  │  │  ┌─────────────────────────────────────────────────────────┐ │   │    │
│  │  │  │  I (субблока) = 0 → 10 (независимая переменная)         │ │   │    │
│  │  │  └─────────────────────────────────────────────────────────┘ │   │    │
│  │  │  I (внешняя) = 1 (не изменилась!)                            │   │    │
│  │  └──────────────────────────────────────────────────────────────┘   │    │
│  │                                                                     │    │
│  │  I (внешняя) = 1                                                    │    │
│  └─────────────────────────────────────────────────────────────────────┘    │
└─────────────────────────────────────────────────────────────────────────────┘

*/

/*
-----------------------------------------------------------------------------
Результат выполнения:
-----------------------------------------------------------------------------

- Текущее значение счётчика 1
- Текущее значение счётчика в субблоке 10
- Текущее значение счётчика во внешнем блоке 1
- Текущее значение счётчика во внешнем блоке 1

-----------------------------------------------------------------------------
Пример SELECT INTO
-----------------------------------------------------------------------------
В следующих примерах запрос SELECT возвращает значения столбца Fio
таблицы Abonent для присваивания локальной переменной B_Fio.

В примере кода на PL/pgSQL блок выполняется без ошибки и запрос
возвращает одно значение:

*/


DO $$
    DECLARE
        B_fio Abonent.Fio%TYPE; -- неявное объявление типа
    BEGIN
        SELECT Fio
        INTO B_fio
        FROM Abonent
        WHERE Phone = '769975'
        ORDER BY Fio DESC;
        RAISE NOTICE 'ФИО: %', B_fio;
    END $$;


/*
Результат выполнения:

ФИО: Мищенко Е. В.

При возврате запросом нескольких значений ошибка также не возникает:
*/

/*
Запрос вернёт ФИО только одного абонента — того, который окажется
первым в выборке после сортировки по убыванию ФИО.
*/
DO $$
    DECLARE
        B_fio Abonent.Fio%TYPE; -- переменная типа кортежа
    BEGIN
        SELECT Fio
        INTO B_fio
        FROM Abonent
        WHERE Phone IS NOT NULL
        ORDER BY Fio DESC;
        RAISE NOTICE 'ФИО: %', B_fio;
    END $$;

/*
Результат выполнения:
ФИО: Шубина Т. П.
*/


/*
Важной особенностью результата выполнения этого блока является
присваивание локальной переменной B_fio первого значения (в запросе
отсутствует STRICT)

-----------------------------------------------------------------------------
Пример работы оператора CONTINUE
-----------------------------------------------------------------------------

Следующий пример анонимного выполнимого блока демонстрирует работу
оператора CONTINUE.
*/


DO $Итерация$
    DECLARE
        Number INTEGER := 1;
    BEGIN
        WHILE (Number < 10)
            LOOP
                RAISE NOTICE 'Итерация: %', Number;
                Number := Number + 1;
                IF Number = 7
                THEN
                    EXIT;
                END IF;
                IF Number = 4
                THEN
                    CONTINUE;
                END IF;
                RAISE NOTICE 'Конец итерации';
            END LOOP;
    END $Итерация$;

/*
Итерация: 1
Конец итерации
Итерация: 2
Конец итерации
Итерация: 3          ← нет "Конец итерации" (сработал CONTINUE)
Итерация: 4
Конец итерации
Итерация: 5
Конец итерации
Итерация: 6
*/


/*
Когда переменная Number станет равна 4, с помощью оператора CONTINUE
произойдёт переход к новой итерации, поэтому последующая строка
RAISE NOTICE 'Конец итерации' не будет выполняться, хотя цикл
продолжается. Когда переменная Number станет равна 7, оператор EXIT
произведёт выход из цикла, и он завершится.
*/


/*
В PL/pgSQL также можно создать ссылочную переменную, которая указывает
на системные переменные или другую переменную.

Например, если требуется создать ссылочную переменную или короткое имя
переменной для другой переменной, можно создать эти короткие переменные,
используя псевдоним. Вот пример:
*/

DO
$$
    DECLARE
        Var INT;
        Ves ALIAS FOR Var;
        Vd ALIAS FOR Ves;
    BEGIN
        SELECT COUNT(*) FROM Abonent INTO Var;
        RAISE NOTICE 'Ссылка №1 = %', Ves;
        RAISE NOTICE 'Ссылка №2 = %', Vd;
        RAISE NOTICE 'Обновить ссылку №1';
        SELECT COUNT(*) FROM Request WHERE Executiondate IS NULL INTO Ves;
        RAISE NOTICE 'Актуальная переменная = %', Var;
        SELECT COUNT(*) FROM Request WHERE Executed IS FALSE INTO Vd;
        RAISE NOTICE 'Актуальная переменная = %', Var;
    END;
$$

/*
В предыдущем примере определена ссылочная переменная Ves на фактическую
переменную Var. Далее создана переменная-псевдоним Vd из другой
переменной-псевдонима Ves. То есть создана новая ссылочная переменная,
которая указывает на другую ссылочную переменную. Кроме того, после
обновления второй ссылочной переменной она отразила эти изменения
в фактической переменной через первую ссылку.

Результат выполнения:

Ссылка №1 = 12
Ссылка №2 = 12
Обновить ссылку №1
Актуальная переменная = 2
Актуальная переменная = 4

-----------------------------------------------------------------------------
Псевдотип RECORD
-----------------------------------------------------------------------------

Ниже при изучении процедурных объектов используется псевдотип RECORD,
содержащий в себе строку, получаемую запросом SELECT. Структура
сформированной строки определяется только её атрибутами. В следующем
примере DO-блока производится выборка из таблицы Abonent и результат
присваивается переменной типа RECORD:
*/

DO
$$
    DECLARE
        Var RECORD;
    BEGIN
        SELECT *
        INTO Var
        FROM Abonent
        WHERE Accountid = '005488';
-- WHERE PHONE IS NOT NULL;
        RAISE NOTICE '%, %', Var.Fio, Var.Phone;
    END;
$$
LANGUAGE PLPGSQL;

/*
Результат выполнения:
Аксенов С. А., 556893
RECORD — это псевдотип, который может хранить целую строку таблицы
(строку результата запроса).
В отличие от обычных переменных, которые хранят одно значение (число, строку),
RECORD хранит набор полей (как строка таблицы).


После объявления в секции DECLARE переменной Var осуществляется
выборка всех данных абонента с номером лицевого счёта '005488'.
При этом результат выборки присваивается этой переменной в виде
строки. Затем выводятся атрибуты строки ФИО и номер телефона
абонента указанием точки после имени переменной.

По сравнению с другими способами решения подобных задач тип
RECORD позволяет сократить запрос, представить его более читаемым
или сделать производительным.

В заключение приведём пример анонимного блока для вывода
слова «PostgreSQL» в следующем виде:


В заключение приведём пример анонимного блока для вывода слова
«PostgreSQL» в следующем виде:

10 10 PostgreSQL
PostgreSQLLQSergtsoP
PostgreSQ  QSergtsoP
PostgreS    SergtsoP
Postgre      ergtsoP
Postgr        rgtsoP
Postg          gtsoP
Post            tsoP
Pos              soP
Po                oP
P                  P
Po                oP
Pos              soP
Post            tsoP
Postg          gtsoP
Postgr        rgtsoP
Postgre      ergtsoP
PostgreS    SergtsoP
PostgreSQ  QSergtsoP
PostgreSQLLQSergtsoP
*/

DO
$$
    DECLARE
        L INT;
        M INT;
        N VARCHAR(10) = 'PostgreSQL';
    BEGIN
        L = CHAR_LENGTH(N);
        M = L;
        RAISE NOTICE '% % %', L, M, N;
        WHILE L > 0
            LOOP
                RAISE NOTICE '%', LEFT(N, L) || RPAD(' ', (2 * (M - L)))
                    || RIGHT(REVERSE(N), L);
                L = L - 1;
            END LOOP;
        L = 2;
        WHILE L <= M
            LOOP
                RAISE NOTICE '%', LEFT(N, L) || RPAD(' ', (2 * (M - L)))
                    || RIGHT(REVERSE(N), L);
                L = L + 1;
            END LOOP;
    END
$$;

/*
В выполняемых блоках можно вызывать именованные процедурные модули: ХП, ХФ.
*/


/*
# Обработка ошибок

При разработке приложений процедурного языка необходимо учитывать,
что они будут работать не в «идеальном мире», где в программах не
бывает ошибок, пользователи вводят только правильные данные, а все
системы — и аппаратные, и программные — абсолютно надёжные. В жёсткой
реальности, как правило, проявляются ошибки, например пользователи
выполняют последовательность нажатий клавиш, от которых форма перестанет
работать.

Ошибка — это само событие (нарушение правил), в то время как исключение —
это реакция системы на это событие. Любая возникающая ошибка прерывает
выполнение кода и транзакции, в которой она выполняется.
В СУБД ошибки всех видов (синтаксические ошибки, ограничения данных,
ошибки транзакций, ошибки доступа, аппаратные и системные ошибки)
интерпретируются как исключения — ситуации, которые не должны возникать
при нормальном выполнении программы.
Исключения могут возникать из-за ошибок проектирования, ошибок кодирования,
аппаратных сбоев и многих других причин.
Нельзя предвидеть все возможные ошибки, но можно написать обработчики ошибок,
которые позволяют программе продолжать работать в их присутствии.

К числу исключений, как правило, относятся:
- ошибки, генерируемые системой (например, нехватка памяти или
  повторяющееся значение индекса);
- ошибки, вызванные действиями пользователя;
- предупреждения, выдаваемые приложением пользователю.

В большинстве современных СУБД имеются достаточно мощные и гибкие
механизмы перехвата, обработки и даже исправления разного рода ошибок.

Исключения не позволяют защитить программу от воздействия асинхронных
событий (асинхронных ситуаций). Эти события могут возникать за счёт
внешних воздействий на объекты, происходящих в моменты времени, не
связанные с каким-либо участком кода программы. Примерами таких событий
могут быть отключение питания компьютера, команда на перезагрузку
операционной системы, вредоносные воздействия на код программы со стороны
параллельных процессов и т.д.

Синхронные особые ситуации могут возникнуть только при выполнении тех
или иных фрагментов кода программы. Каждый такой фрагмент кода
представляет собой последовательность конкретных операторов текста
программы. Самое важное то, что при разработке программы зачастую
известно, в каком участке текста программы может возникнуть синхронная
особая ситуация. Например, при вводе данных пользователь может по ошибке
ввести текстовую информацию вместо числовой, не ввести значения всех
параметров и т.д. Именно для реагирования на синхронные особые ситуации,
возникающие в процессе выполнения программы, предназначен механизм
исключений. К сожалению, особых ситуаций, если они потенциально возможны,
избежать нельзя. Но разработчик может предусмотреть в программе операторы
для распознавания особой ситуации и для реакции на неё.

Поэтому вместе с понятием ошибки возникает понятие реакции системы на
ошибки. Система должна не только проверять, не нарушается ли ограничения
в ходе выполнения различных операций, но и соответствующим образом
реагировать, если операция приводит к нарушению ограничений. Всем
сообщениям, которые выдаёт сервер PostgreSQL, назначены пятисимвольные
коды ошибок, соответствующие кодам SQLSTATE, описанным в стандарте SQL
Имеются два типа реакции на попытку нарушения ограничений:
- **отказ** выполнить «некорректную» операцию;
- выполнение **компенсирующих действий**.

Например, если действует ограничение, что в Paymonth «Месяц оплаты»
должны быть целые числа в диапазоне от 1 до 12, то система отвергает
попытку ввести значение месяца 13. При этом для пользователя может
формироваться какое-нибудь сообщение.

При втором типе реакции система может допускать, например, вставку
недопустимого значения (что приведёт к нарушению целостности БД), но
автоматически производит компенсирующие действия.


Далее используются следующие понятия.

- **Раздел исключений** — необязательный раздел процедурного модуля
  (анонимного блока, процедуры, функции, триггера), содержащий один или
  несколько обработчиков исключений. Структура раздела исключений очень
  похожа на структуру операции CASE.

- **Инициирование исключения** — означает остановку выполнения текущего
  процедурного модуля с оповещением исполняемого ядра об ошибке.
  Исключение может инициировать либо СУБД, либо программный код.

- **Обработка исключения** — означает перехват ошибки, передачу управления
  обработчику исключения. Написанный программистом обработчик может
  содержать код, который в ответ на исключение выполняет определённые
  действия (например, записывает информацию об ошибке в журнал, выводит
  сообщение для пользователя или передаёт исключение во внешний блок).

- **Область действия** — часть кода (конкретный блок или весь раздел),
  в котором может инициироваться исключение, а также часть кода,
  инициируемые исключения которого могут перехватываться и обрабатываться
  соответствующим разделом исключений.

- **Передача исключения** — процесс передачи исключения во внешний модуль,
  если в текущем модуле это исключение не обработано.

- **Необработанное исключение** — исключение, которое передается без
  обработки из «самого внешнего» процедурного модуля. После этого
  управление передаётся исполнительной среде, которая уже сама определяет,
  как отреагировать на исключение (выполнить отказ транзакции, вывести
  сообщение об ошибке, проигнорировать её и т.д.).

- **Анонимное исключение** — исключение, с которым связан код ошибки
  и описание. Такое исключение не имеет имени.

- **Именованное исключение** — исключение, которому имя присвоено либо
  СУБД (в одном из встроенных пакетов), либо разработчиком.

Исключения позволяют отделить распознавание особой ситуации от реакции
на неё. В механизме исключений есть два этапа — генерация исключения
и обработка исключения. Генерация исключения выполняется в том месте,
где возникла и обнаружена особая ситуация, а обработка — там, где это
удобно в конкретном случае.

Итак, **исключительные ситуации (Exception)** — это сообщения, которые
генерируются при появлении ошибок в теле программного модуля.


Исключительные ситуации и их обработчики — это механизм, с помощью
которого программа реагирует на ошибки выполнения и устраняет их.
В случае возникновения ошибки инициируется (raised) исключительная
ситуация. При этом управление программой передаётся обработчику
исключительной ситуации, который является отдельным фрагментом
программы. Необходимо отметить, что раздел обработки ошибок отделён
от остальной части программы, что упрощает логическую структуру
программы и обеспечивает фиксацию всех ошибок. В этом случае:

1) логика программы нагляднее и легче для понимания;
2) программа распознает и обрабатывает любую ошибку независимо от того,
   какой оператор является причиной ошибки.

Однако следует учесть, что выполнение программы не будет продолжаться
с оператора, вызвавшего ошибку. Вместо этого выполнение будет
продолжаться в обработчике исключительных ситуаций, а затем во внешнем
блоке.

При использовании механизма исключительных ситуаций написанные на
процедурном языке программы становятся гораздо надёжнее, так как во
время их выполнения предоставляется возможность обработки как
запланированных, так и незапланированных ошибок. Не следует допускать
возникновения в программах исключительных ситуаций, которые не
обрабатываются.

Существуют два основных типа исключений: предопределённые (системные,
встроенные) и пользовательские. **Предопределённые** исключения и
ассоциированные с ними тексты сообщений связаны с типичными ошибками,
возникающими при работе с БД. К таким ошибкам относятся, например,
попытка удалить объект, который находится в использовании, попытка
вставить некорректные данные в столбец, на который наложено ограничение,
и т.д. Предварительно определённые исключения существуют во всех СУБД.
В PostgreSQL также есть предопределённые исключения, такие как
division_by_zero (деление на ноль), unique_violation (нарушение
уникальности), check_violation (нарушение проверки ограничения),
foreign_key_violation (нарушение ограничения внешнего ключа),
NO_DATA_FOUND (нет строк) и другие. Явного объявления и обработки
с помощью процедурного языка такие исключения не требуют.

Кроме того, во многих СУБД существует возможность создания
**пользовательских исключений**. Исключения, заданные разработчиком, —
это ошибки, которые предусмотрел разработчик, и они не обязательно
связаны с ошибками СУБД. Такие исключения в некоторых случаях
рассматриваются разработчиками как удобный способ передачи управления
другому разделу блока процедурного языка. PostgreSQL не поддерживает
именованные пользовательские исключения, но существует возможность
генерации пользовательских сообщений об ошибках. Для инициирования
пользовательского исключения применяется оператор RAISE, который обычно
должен располагаться внутри условного оператора IF. Таким образом,
создавать пользовательские исключения можно как в клиентском приложении,
так и на стороне сервера средствами SQL.

Рассмотрим особенности работы с исключениями в PL/pgSQL.
Перехват и обработка предопределённых исключений в хранимых функциях
и процедурах, а также в анонимных блоках возможна только внутри
конструкции:

BEGIN
    -- Здесь располагается потенциально опасный код
EXCEPTION
    WHEN '<идентификатор_ошибки>' THEN
        -- код, обрабатывающий исключение
END;

Чтобы обработать исключение, необходимо указать имя идентификатора
или идентификатор ошибки, которые будут обрабатываться. Коды всех
ошибок и их идентификаторов можно найти в официальной документации!!!.

Стандартные исключения инициируются автоматически при возникновении
соответствующей ошибки PostgreSQL. При установлении исключительной
ситуации управление программой сразу же передаётся специальному разделу
обработки исключений — EXCEPTION. Данный раздел помещается внутри тела
процедурного блока и содержит код, предназначенный для поддержки
исключений, в виде:

EXCEPTION
    WHEN Исключение_типа_1 [ OR исключение ...] THEN
        -- Обработка Исключение_типа_1
        RAISE NOTICE 'Обработанное исключение: %', SQLERRM;
        -- Дополнительная логика обработки
    WHEN Исключение_типа_2 [ OR исключение ...] THEN
        -- Обработка Исключение_типа_2
        RAISE NOTICE 'Следующее исключение: %', SQLERRM;
        -- Дополнительная логика обработки
    WHEN OTHERS THEN
        -- Обработка всех других исключений
        RAISE NOTICE 'Необработанное исключение: %', SQLERRM;
        -- Дополнительная логика обработки

где:
- EXCEPTION — начало блока обработки исключений;
- WHEN Тип исключения THEN — условие, позволяющее перехватить
  конкретный тип исключения;
- RAISE NOTICE используется для вывода сообщения о произошедшем
  исключении. SQLERRM — это
  встроенная переменная, содержащая текстовое описание ошибки;
- WHEN OTHERS THEN — блок, который обрабатывает все исключения,
  не указанные явно;
- Дополнительная логика обработки — здесь можно реализовать логику,
  которая должна выполняться в случае возникновения исключения,
  например, очистка ресурсов или запись в журнал.

Ключевое слово **OTHERS** обозначает обработку всех исключений,
не перечисленных явно в WHEN. Таким образом, задаётся обработчик
непредусмотренных исключений. Он используется в основном тогда, когда
нельзя полностью понять суть исключений, которые могут возникнуть
в блоке PL/pgSQL.

Например, если необходимо обработать все непредвиденные ошибки, код
в PostgreSQL может выглядеть так:

BEGIN
    ...
EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION '%', SQLERRM;
END;

где SQLERRM — сообщение об ошибке.

Раздел EXCEPTION должен располагаться в конце блока BEGIN ... END,
он является глобальным для всего блока и может иметь множество
обработчиков разных типов исключений (если в функции несколько блоков
BEGIN ... END, то каждый блок может иметь свой раздел EXCEPTION).
Обработка исключения какого-либо типа (типов) начинается строкой:

WHEN <Тип исключения> [OR исключение...] THEN

Таких строк, как следует из синтаксиса, может быть множество, под каждый
отдельный тип исключения. Каждый обработчик исключения состоит из
ключевого слова WHEN, задающего исключение, за которым следует
последовательность команд, выполняемых в случае, если исключение
возбуждено.

У каждой ошибки есть имя и код:

<Тип исключения> ::= { имя | SQLSTATE 'код' }

В качестве **Тип исключения** может задаваться одно из системных имён,
например division_by_zero. Если задаётся имя категории, ему
соответствуют все ошибки в данной категории. Тип ошибки также можно
задать кодом SQLSTATE; например, эти два варианта равнозначны:


WHEN DIVISION_BY_ZERO THEN ...
WHEN SQLSTATE '22012' THEN ...

Для инициирования (перехвата) и вывода сообщений о пользовательских
ошибках используется оператор RAISE:

-- Генерация пользовательского исключения
IF (условие инициирования) > 100 THEN
    RAISE EXCEPTION USING ERRCODE = код_ошибки,
                            MESSAGE = 'сообщение';
END IF;

После инициирования пользовательского исключения управление передаётся
в раздел обработки исключения.

Серверные исключения относятся к ошибкам, возникающим на сервере
PostgreSQL, например:

- ошибки блокировок;
- проблемы с доступностью серверных ресурсов;
- отказ транзакций (например, из-за deadlock или других ограничений).

Эти исключения генерируются сервером PostgreSQL в процессе обработки
запросов, и их можно перехватывать в пользовательских функциях,
процедурах или в клиентских приложениях.

Примеры выполненных блоков на PL/pgSQL с перехватом и обработкой
предопределённой ошибки деления на ноль:
*/

DO $$
    BEGIN
        PERFORM 1 / 0;
    EXCEPTION
        WHEN SQLSTATE '22012' THEN -- перехват ошибки по коду
        ---RAISE EXCEPTION '%', SQLERRM;
            RAISE USING MESSAGE = 'деление на ноль';
    END $$;



DO $inline$
    DECLARE
        I INT;
        J INT := 2;
    BEGIN
        I := 6 / J;
        RAISE NOTICE '6 / % = %', J, I;
        J := 0;
        I := 6 / J;
        RAISE NOTICE '6 / % = %', J, I;
    EXCEPTION
        WHEN DIVISION_BY_ZERO THEN -- перехват ошибки по системному имени
            RAISE NOTICE '6 / % Деление на ноль', J;
    END; $inline$

/*
Результат выполнения:

6 / 2 = 3
6 / 0 Деление на ноль

В первом примере в теле DO-блока использован оператор PERFORM
для вычисления выражения 1 / 0 без возврата результата.
*/


/*
В следующем DO-блоке производится перехват и обработка других основных
предопределённых ошибок:
*/


DO $$
    BEGIN
        -- Попытка вставки, которая может вызвать нарушение
        -- уникального ограничения (SQLSTATE = 23505)
        INSERT INTO Abonent
        VALUES ('005488', 1, 5, 2, 'Петров А. С.', '128453');

        -- Попытка вставки, которая может вызвать нарушение
        -- ограничения внешнего ключа (SQLSTATE = 23503)
        INSERT INTO Abonent
        VALUES ('123456', 10, 5, 2, 'Петров А. С.', '128453');

        -- Попытка вставки, которая может вызвать нарушение проверки
        -- ограничения (SQLSTATE = 23514)
        INSERT INTO Nachislsumma
        VALUES ('136160', 3, 600, 13, 2025);

        -- Попытка обновления несуществующей таблицы
        -- (SQLSTATE = 42P01)
        UPDATE Nachislsumma
        SET Nachislsum = 100
        WHERE Accountid = '136160';

        -- Попытка обновления несуществующего столбца
        -- (SQLSTATE = 42703)
        UPDATE Nachislsumma
        SET Paysum = 100
        WHERE Accountid = '136160';

    EXCEPTION
        WHEN unique_violation THEN
            RAISE NOTICE 'Нарушение уникального ограничения: HЛС уже существует.
                      Ошибка: %', SQLERRM;

        WHEN foreign_key_violation THEN
            RAISE NOTICE 'Нарушение ограничения по внешнему ключу: неверный Streetid.
                      Ошибка: %', SQLERRM;

        -- WHEN SQLSTATE '23000' THEN
        --     RAISE USING MESSAGE = 'Нарушение ограничения целостности';

        WHEN check_violation THEN
            RAISE NOTICE 'Нарушение ограничения: месяц должен быть от 1 до 12.
                      Ошибка: %', SQLERRM;

        -- WHEN SQLSTATE '22003' THEN
        --     RAISE USING MESSAGE = 'Числовое значение вне диапазона';

        WHEN undefined_table THEN
            RAISE NOTICE 'Таблица не существует. Ошибка: %', SQLERRM;

        WHEN undefined_column THEN
            RAISE NOTICE 'Имя столбца неверно. Ошибка: %', SQLERRM;

        WHEN OTHERS THEN
            RAISE NOTICE 'Произошла непредвиденная ошибка. Ошибка: %', SQLERRM;
    END $$;


/*
Приведём пример перехвата и исправления ошибки с кодом 23503
(нарушение ограничения ссылочной целостности) из предыдущего примера.
Это можно сделать, учитывая, например, правило предметной области,
допускающее возможность не указывать идентификатор улицы:
*/
DO $$
    BEGIN
        -- Попытка вставки, которая может вызвать нарушение ограничения
        -- внешнего ключа (SQLSTATE = 23503)
        INSERT INTO Abonent
        VALUES ('123456', 10, 5, 2, 'Петров А. С.', '128453');

    EXCEPTION
        WHEN foreign_key_violation THEN
            RAISE NOTICE 'Нарушение ограничения по внешнему ключу: неверный Streetid.
                      Ошибка: %', SQLERRM;
            RAISE NOTICE 'Ошибка исправлена, значение столбца Streetid заменено на NULL.
                      Строка добавлена.';
            INSERT INTO Abonent
            VALUES ('123456', NULL, 5, 2, 'Петров А. С.', '128453');

        WHEN OTHERS THEN
            RAISE NOTICE 'Произошла непредвиденная ошибка. Ошибка: %', SQLERRM;
    END $$;

/*
-----------------------------------------------------------------------------
Результат выполнения:
-----------------------------------------------------------------------------

Нарушение ограничения по внешнему ключу: неверный Streetid.
Ошибка: INSERT или UPDATE в таблице "abonent" нарушает ограничение
    внешнего ключа "abonent_Streetid_fkey".
    Ошибка исправлена, значение столбца Streetid заменено на NULL.
    Строка добавлена.
*/


/*
В PostgreSQL имеются два способа при обработке исключений получить
детальную информацию о произошедшей ошибке: использование специальных
переменных (SQLSTATE — содержит код ошибки; SQLERRM — содержит сообщение
об ошибке, связанное с исключением) и команда GET STACKED DIAGNOSTICS.
С помощью команды GET STACKED DIAGNOSTICS можно получить информацию
о текущем исключении:

GET STACKED DIAGNOSTICS переменная { = | := } элемент [, ...];

где каждый элемент представляется ключевым словом, указывающим, какое
значение состояния нужно присвоить заданной переменной (она должна иметь
подходящий тип данных, чтобы принять его).

Следует учесть, что если возникает исключение, то перед выходом из блока
выполняется только один обработчик исключений. После передачи управления
обработчику невозможно вернуться в выполняемый раздел блока.

Пример DO-блока для формирования и ввода N-го числа Фибоначчи с обработкой
ошибки (при N > 46) и выдачей подробной информации о ней:
*/
DO $$
    DECLARE
        N       INT = 46; -- 47 ---для int 2,147,483,647. 4 байта, 47 это 2,971,215,073
        Counter INT = 1;
        Two     INT = 0;
        One     INT = 1;
        Code    TEXT;
        Msg     TEXT;
        Context TEXT;
    BEGIN
        WHILE (N >= Counter)
            LOOP
                Two = One + Two;
                One = Two - One;
                Counter = Counter + 1;
            END LOOP;
        RAISE NOTICE '%-ое число Фибоначчи равно %', N, One;
    EXCEPTION
        WHEN SQLSTATE '22003' THEN
            RAISE INFO 'Проблема с числом Фибоначчи';
            GET STACKED DIAGNOSTICS
                Code = RETURNED_SQLSTATE,
                Msg = MESSAGE_TEXT,
                Context = PG_CONTEXT;
            RAISE NOTICE 'Код ошибки: %. Текст сообщения об ошибке: %.', Code, Msg;
            RAISE NOTICE 'Контекст ошибки: %', Context;
            RAISE NOTICE '46-е число Фибоначчи равно %', One;
    END $$;


/*Уникальные ли данные находятся в столбцах
Главная цель: понять, как планировщик PostgreSQL будет выполнять запросы
Планировщик использует эту статистику для оценки количества строк,
которые вернёт условие WHERE.
Чем точнее статистика, тем оптимальнее план запроса.

3. Как использовать эту информацию
3.1. Решить, нужен ли индекс
Уникальность	       Индекс нужен?	         Почему
Высокая (>80%)	        ✅ Да	         Index Scan эффективен
Средняя (20-80%)	    🟡 Возможно	     Зависит от запроса
Низкая (<20%)	        ❌ Нет	         Seq Scan может быть быстрее

-- payfactid (100% уникальных) → индекс нужен
CREATE INDEX idx_payfactid ON paysumma(payfactid);  -- ✅

-- payyear (4 значения, 5% уникальных) → индекс не нужен
CREATE INDEX idx_payyear ON paysumma(payyear);  -- ❌ бесполезно

*/
SELECT attname AS column_name,
       n_distinct,
       CASE
           WHEN n_distinct = -1
               THEN '✅ Уникальный (все разные)'
           WHEN n_distinct = -0.5
               THEN '🟡 Примерно 50% уникальных'
           WHEN n_distinct < 0 AND n_distinct > -1
               THEN
               '🟡 ' || (ABS(n_distinct) * 100)::INTEGER || '% уникальных'
           WHEN n_distinct = 0
               THEN '❌ Нет статистики'
           WHEN n_distinct BETWEEN 1 AND 10
               THEN '📊 Мало уникальных (' || n_distinct || ')'
           WHEN n_distinct > 10
               THEN '📊 Много уникальных (' || n_distinct || ')'
       END     AS uniqueness
FROM pg_stats
WHERE tablename = 'paysumma'
ORDER BY attname;


/*
В следующем примере анонимного блока на PL/pgSQL вычисляется
отношение сумм значений начислений и оплат за определенные
услуги, год и месяц. В случае нулевой оплаты операция деления
должна вызывать предопределенное исключение division_by_zero.
При этом выполнение блока прерывается, а управление передается
обработчикам исключений.
*/

DO
$$
    DECLARE
        Ratio NUMERIC;
        Mes   Tmonth  := 9;
        Year  Tyear   := 2024;
        Serv  Pkfield := 1;
    BEGIN
        Ratio := ROUND(
                (
                SELECT SUM(Nachislsum)
                FROM Nachislsumma
                WHERE Nachislmonth = Mes
                  AND Nachislyear = Year
                  AND Serviceid = Serv
                )
                    /
                (
                SELECT SUM(Paysum)
                FROM Paysumma
                WHERE Paymonth = Mes
                  AND Payyear = Year
                  AND Serviceid = Serv
                ),
                4);
        RAISE NOTICE 'Соотношение начислено/оплачено за % месяц % года услуги % = %',
            Mes, Year, Serv, Ratio;
    EXCEPTION
        WHEN DIVISION_BY_ZERO THEN
            RAISE NOTICE 'За % месяц % года нет оплаты услуги %', Mes, Year, Serv;
        WHEN OTHERS THEN
            RAISE NOTICE 'Произошла другая ошибка: %', SQLERRM;
    END;
$$;

/*
оотношение начислено/оплачено за 9 месяц 2024 года услуги 1 = 0.9992
[2026-04-20 20:41:40] completed in 10 ms
*/


/*
В последнем случае никакой ошибки не обнаружено и приложение,
использующее этот DO-блок будет считать, что расчет выполнен
успешно. На самом деле оплата за этот период и услугу
отсутствовала. Получается, что условие division_by_zero не
сработало так как сумма платежей не определена, а следовательно,
результатом деления является NULL. Учтем эту особенность
следующим образом:
*/

DO
$$
    DECLARE
        Ratio NUMERIC;
        Mes   Tmonth  := 9;
        Year  Tyear   := 2024;
        Serv  Pkfield := 4;
    BEGIN
        -- Расчет может вызвать ошибку деления на ноль
        Ratio := ROUND(
                (
                SELECT SUM(Nachislsum)
                FROM Nachislsumma
                WHERE Nachislmonth = Mes
                  AND Nachislyear = Year
                  AND Serviceid = Serv
                )
                    /
                (
                SELECT SUM(Paysum)
                FROM Paysumma
                WHERE Paymonth = Mes
                  AND Payyear = Year
                  AND Serviceid = Serv
                ), 4);

        IF Ratio IS NULL
        THEN
            RAISE EXCEPTION NO_DATA_FOUND;
        ELSE
            RAISE NOTICE 'Соотношение начислено/оплачено за % месяц %'
                ' года услуги % = % ', Mes, Year, Serv, Ratio;
        END IF;

    EXCEPTION -- обработчики исключений
        -- Выполняется только один из блоков WHEN
        WHEN NO_DATA_FOUND THEN
            RAISE NOTICE ' За % месяц % года нет оплаты услуги % ',
                Mes, Year, Serv;
        WHEN OTHERS THEN
            -- обработка всех остальных ошибок
            RAISE NOTICE 'Произошла другая ошибка: %', SQLERRM;
    END
$$;

/*
Результат выполнения:
За 9 месяц 2024 года нет оплаты услуги 4

Ошибки могут возникать в разделе объявлений, в исполняемом
разделе (области действия) и в разделе обработки исключений.

Примечание
В разделе обработки исключений могут быть обработаны только
ошибки, возникающие в исполняемом разделе текущего блока.
*/


/*
При работе с многоблочной структурой в PostgreSQL порядок
обработки ошибок следующий:
1) ошибка обрабатывается в ближайшем блоке с секцией EXCEPTION;
2) если секция EXCEPTION отсутствует, ошибка передается наружу
(во внешний блок);
3) если ошибка не обработана ни в одном блоке, она становится
необработанной и возвращается клиенту.

Пример DO-блока для определения номера квартала в зависимости
от номера месяца, с перехватом, подробной информацией об
пользовательской ошибке и ее обработкой при вызове из внешнего
блока:
*/

DO
$$
    <<A>>
        DECLARE
        Kv      INT;
        Mes     INT = 12; -- 20
        Code    TEXT;
        Msg     TEXT;
        Context TEXT;
    BEGIN
        BEGIN
            IF Mes NOT BETWEEN 1 AND 12
            THEN
                RAISE EXCEPTION 'Неверный номер месяца (%)', Mes
                    USING HINT = 'Номер месяца может быть от 1 до 12',
                        ERRCODE = 'P00001';
            END IF;
            IF Mes BETWEEN 1 AND 3
            THEN
                Kv = 1;
            ELSIF Mes BETWEEN 4 AND 6
            THEN
                Kv = 2;
            ELSIF Mes BETWEEN 7 AND 9
            THEN
                Kv = 3;
            ELSE
                Kv = 4;
            END IF;
            RAISE NOTICE 'Квартал %', Kv;
        END;
    EXCEPTION
        WHEN SQLSTATE 'P00001' THEN
            RAISE INFO 'Проблема с исходными данными';
            GET STACKED DIAGNOSTICS
                Code = RETURNED_SQLSTATE,
                Msg = MESSAGE_TEXT,
                Context = PG_CONTEXT;
            RAISE NOTICE 'Код ошибки: %. Текст сообщения об ошибке: %.',
                Code, Msg;
            RAISE NOTICE 'Контекст ошибки: %', Context;
            RAISE INFO 'Результат: %', Kv;
    END A
$$;

/*
Рассмотрим еще пример пользовательского исключения. Пусть
необходимо обеспечить выполнение требования: нельзя добавлять
новые выполненные заявки на ремонт, а также нельзя менять
признак погашения у погашенных ремонтных заявок:
*/

DO $$
    DECLARE
        Status_executed      Request.Executed %TYPE;
        R_requestid          Request.Requestid %TYPE     := 5;
        Status_execution_new Request.Executiondate %TYPE := NULL;
-- Status_execution_new
-- Request.Executiondate %TYPE := CURRENT_DATE;
    BEGIN
        SELECT Executed
        INTO Status_executed
        FROM Request
        WHERE Requestid = R_requestid;

        IF Status_executed
        THEN
            RAISE EXCEPTION USING ERRCODE = 60001;
        ELSE
            UPDATE Request
            SET Executed = TRUE
            WHERE Requestid = R_requestid;
        END IF;
        IF Status_execution_new IS NOT NULL
        THEN
            RAISE EXCEPTION USING ERRCODE = 60002;
        ELSE
            INSERT INTO Request
            VALUES (NEXTVAL('Gen_request'), '005488', 1, 2,
                    CURRENT_DATE, NULL, FALSE);
        END IF;
    EXCEPTION
        WHEN SQLSTATE '60001' THEN
            RAISE NOTICE 'Ошибка: нельзя изменять
        состояние погашенной заявки';
        WHEN SQLSTATE '60002' THEN
            RAISE NOTICE 'Ошибка: нельзя регистрировать
        выполненную заявку';
        WHEN OTHERS THEN
            RAISE NOTICE 'Код ошибки: %', SQLSTATE;
            RAISE NOTICE 'Причина ошибки %', SQLERRM;
    END $$;

/*
В результате выполнения DO-блока будет добавлена новая
невыполненная ремонтная заявка, а заявка с идентификатором 5
будет погашена. Попытка добавить новую выполненную заявку
закончится выдачей сообщения:

Ошибка: нельзя регистрировать выполненную заявку

Приведем заключительный пример инициирования ошибок,
определяемых сервером. В начале получим номер лицевого счета
абонента, подавшего определенную заявку, например с номером 5:
*/


DO $$
    DECLARE
        R_Accountid Request.Accountid %TYPE;
        --   R_Requestid Request.Requestid %TYPE := 5;
        R_Requestid Request.Requestid %TYPE := 25;
    BEGIN
        SELECT Accountid
        INTO STRICT R_Accountid
        FROM Request
        WHERE Requestid = R_Requestid;
        RAISE NOTICE 'Абонент = % Номер заявки = %', R_Accountid,
            R_Requestid;
    END $$;

/*
Результат выполнения:

Абонент = 080270 Номер заявки = 5

Для заявки с номером 25 результат выполнения:

SQL Error [P0002]: ОШИБКА: запрос не вернул строк
Где: функция PL/pgSQL inline_code_block, строка 6,
оператор SQL-оператор

Затем вычислим сумму значений платежей определенного абонента:
*/

/*
Затем вычислим сумму значений платежей определенного абонента:
*/


DO
$$
    DECLARE
        R_sum       INT;
        ---  R_AccountId Request.AccountId %TYPE := '126112';
        R_AccountId Request.AccountId %TYPE := '111111';
    BEGIN
        SELECT SUM(Paysum)
        INTO STRICT R_sum
        FROM Paysumma
        WHERE AccountId = R_AccountId;
        RAISE NOTICE 'Абонент = % Оплачено = %', R_AccountId, R_sum;
    END
$$;

/*
Результат выполнения:
Абонент = 126112 Оплачено = 3356
Для несуществующего абонента '111111' результат выполнения:
Абонент = 111111 Оплачено = <NULL>
Никакой ошибки не обнаружено.
Модифицируем предыдущий запрос для корректного решения задачи:
*/

DO
$$
    DECLARE
        R_sum       INT;
        -- R_AccountId Request.AccountId %TYPE := '126112';
        R_AccountId Request.AccountId %TYPE := '111111';
    BEGIN
        SELECT SUM(Paysum)
        INTO STRICT R_sum
        FROM Paysumma
        WHERE AccountId = R_AccountId;
        IF R_sum IS NULL
        THEN
            RAISE EXCEPTION NO_DATA_FOUND;
        END IF;
        RAISE NOTICE 'Абонент = % Оплачено = %', R_AccountId, R_sum;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            RAISE NOTICE 'Абонент = % не существует', R_AccountId;
    END
$$;


/*
Результат выполнения:
Абонент = 111111 не существует
*/


/*
#Курсоры

При программировании хранимых процедур, функций и триггеров очень
часто возникает необходимость выбрать информацию из БД и временно
ее сохранить перед выполнением каких-либо других действий. Для
таких целей в модулях на процедурных языках допускается
использовать запрос на выборку:

SELECT ... INTO <список_переменных>;

В большинстве случаев запрос к реляционной БД возвращает несколько
строк данных, но PL/pgSQL работает с каждой строкой отдельно!!!
При модификации, удалении или добавлении данных с помощью запросов
DML действия также могут выполняться над отдельной строкой
таблицы.
В этой ситуации на первый план выступает концепция
курсора.
Под курсором понимаются получаемый при выполнении запроса
результирующий набор и связанный с ним указатель текущей строки.

---

Курсор — это указатель на приватную область памяти, которая
выделяется сервером для обработки SQL-запроса.

Обычно курсоры используются для выбора из БД некоторого
подмножества хранимой в ней информации. В каждый момент времени
прикладной программой может быть обработана одна строка курсора.
После позиционирования курсора над этой строкой можно выполнять
различные действия.

Курсоры часто применяются в запросах SQL, встроенных в прикладные
программы, написанные на языках процедурного типа.

Таким образом курсоры применяются при необходимости итеративной
(построчной) обработки данных, в случае заранее неизвестного
количества обрабатываемых строк, а также для передачи данных
внешним программам.

Явный курсор, также называемый изменяемым или именованным курсором,
представляет собой объект, который разработчик может явно
объявлять, открывать и закрывать (в отличие от неявного курсора,
не требующего объявления, открытия и закрытия). Для управления
явным курсором используются команды:
DECLARE CURSOR,
OPEN,
FETCH,
CLOSE.

Примечание

Команды OPEN, FETCH и CLOSE, используемые для работы с явным
курсором, нельзя применять для работы с неявным курсором.

Доступ к курсорам в PL/pgSQL осуществляется через курсорные
переменные, которые всегда имеют специальный тип данных REFCURSOR.
Один из способов создать курсорную переменную, просто объявить ее
как переменную типа REFCURSOR. Другой способ заключается в
использовании синтаксиса объявления курсора, который в общем виде
выглядит так:

имя_курсора [ [ NO ] SCROLL ] CURSOR [ ( параметр ) ]
FOR запрос_SELECT;

Блок PL/pgSQL, в котором запрос SELECT может возвращать несколько
строк, требует использования явного курсора и команд OPEN,
FETCH, CLOSE для работы с ним либо использования специального курсорного
цикла FOR для поочередной обработки строк курсора в виде:

FOR имя_записи IN ...
LOOP ...
END LOOP;

Неявные курсы создаются PL/pgSQL автоматически при выполнении
SQL-запросов, для которых не объявлен явный курсор. Операции
открытия, выборки закрытия в таких курсах выполняются неявно.

Независимо от типа курсора работа с ним производится в три этапа:
1) открытие (синтаксический анализ, привязка переменных,
   установка указателя на первую строку, выполнение SQL-запроса);
2) выборка (выборка строки, перемещение указателя на следующую
   строку);
3) закрытие (освобождение области памяти, курсор становится
   недоступным).

Рассмотрим более подробно особенности реализации двух типов
курсоров в PostgreSQL.

Неявный курсор
Как известно, запрос SELECT возвращает НД, но приложения не всегда
могут эффективно работать с результирующим набором. Возникает
проблема доступа к каждой строке этой таблицы, которая может быть
решена при использовании неявного курсора.

В процедурном языке PL/pgSQL цикл для построчной обработки набора
данных неявного курсора организуется с помощью конструкции:

FOR имя_записи IN (<запрос_SELECT>)
LOOP
    <группа_операторов>
END LOOP;

Как следует из синтаксиса, набор данных курсора определяется
запросом SELECT, который может соединять данные из нескольких
таблиц, содержать условия поиска, сортировку и т. д.

Цикл FOR при обработке набора данных курсора помещает указатель на
текущую строку, к полям которой потом возможно обращение в теле
цикла. Например, анонимный блок с циклом FOR курсора может
выглядеть на PL/pgSQL следующим образом:
*/

DO
$$
    DECLARE
        Rez        RECORD;
        LAccountID VARCHAR(6);
    BEGIN
        FOR Rez IN (
                   SELECT DISTINCT A.AccountId
                   FROM Abonent A
                            INNER JOIN Paysumma USING (Accountid)
                   WHERE Paysum > 2340
                   )
            LOOP
                LAccountId := Rez.AccountId;
                RAISE NOTICE ' % ', LAccountId;
            END LOOP;
    END;
$$
/*
Результат выполнения:
015527
136169
*/


/*
#Явный курсор

Работа с явным курсором предполагает выполнение определенного
набора действий, стандартных для любой СУБД. В соответствии со
стандартом SQL при работе с курсорами выделяются следующие
основные действия:

- определение курсора, т. е. его объявление и связывание с ним
  запроса SELECT;
- открытие курсора, т. е. извлечение строк из БД и помещение их
  в курсор (в память);
- выборка данных из курсора и обработка выбранных строк (как
  правило, в цикле);
- закрытие курсора, после чего он становится недоступным;
- освобождение курсора, т. е. удаление курсора как объекта,
  поскольку его закрытие необязательно освобождает ассоциированную
  с ним память.

В любой СУБД объявление курсора должно помещаться в начале
триггера, ХФ, ХП или неименованного выполнимого блока, подобно
объявлению обычных локальных переменных. Само определение курсора
в разных реализациях может иметь некоторые отличия.

В PostgreSQL курсор без параметров определяется оператором
DECLARE, который имеет следующий синтаксис:

DECLARE
имя_курсора [BINARY] [ASENSITIVE | INSENSITIVE]
[[NO] SCROLL] CURSOR [{WITH | WITHOUT} HOLD]
FOR <запрос_SELECT>;

Курсор со свойством BINARY возвращает данные в двоичном, а не
текстовом формате. Свойства ASENSITIVE, INSENSITIVE курсора
определяют, будут ли произведены изменения нижележащих данных
курсора, выполненные в той же транзакции после объявления
курсора, видны в нем. INSENSITIVE означает, что они не будут
видны, а ASENSITIVE выбирает поведение, определяемое реализацией.
Указание SCROLL определяет, что курсор может прокручивать набор
данных и получать строки непоследовательно. Указание NO SCROLL,
напротив, определяет, что через курсор нельзя будет получать
строки в произвольном порядке. Предложение WITH HOLD определяет,
что курсор можно продолжать использовать после успешной фиксации
создавшей его транзакции!!! WITHOUT HOLD определяет, что курсор
нельзя будет использовать за рамками транзакции, создавшей его.
Если не указаны ни WITHOUT HOLD, ни WITH HOLD, по умолчанию
подразумевается WITHOUT HOLD.

Курсор с параметрами имеет следующий синтаксис:

DECLARE
имя_курсора CURSOR (имя_параметра тип_параметра, ...)
FOR <запрос_SELECT>;

После того как курсор определен в блоке процедурного языка, перед
использованием необходимо его открыть. Для открытия курса
используется оператор

OPEN имя_курсора [(аргумент [, ...])];

Оператор OPEN подготавливает курсор, загружает запрос SELECT и
извлекает строки из БД в память, активизируя первую из
извлеченных строк.

Для выборки данных из курсора используется оператор FETCH.
В PostgreSQL используется оператор FETCH вида

FETCH [DIRECTION [FROM | IN]] имя_курсора [INTO переменные];

Здесь DIRECTION определяет, как и сколько строк следует извлечь
из курсора. DIRECTION может быть пустым или принимать следующие
значения:
- NEXT — извлекает следующую строку (по умолчанию);
- PRIOR — извлекает предыдущую строку;
- FIRST — извлекает первую строку;
- LAST — извлекает последнюю строку;
- ABSOLUTE n — извлекает строку с абсолютным номером n (где n
  может быть и отрицательным, чтобы считать с конца);
- RELATIVE n — извлекает строку, которая находится на n позиций
  вперед или назад относительно текущей позиции;
- ALL — извлекает все оставшиеся строки;
- [FORWARD] n — извлекает n строк вперед;
- FORWARD ALL — извлекает все строки вперед;
- BACKWARD n — извлекает n строк назад;
- BACKWARD ALL — извлекает все строки назад.

FETCH получает строки через ранее созданный курсор. Курсор связан
с определенным положением, что и использует команда FETCH. Курсор
может располагаться перед первой строкой результата запроса, на
любой строке этого результата, либо после последней строки. При
создании курсор оказывается перед первой строкой. Когда FETCH
доходит до конца набора строк, курсор остается в положении после
последней строки, либо перед первой, при движении назад. После
команд FETCH ALL и FETCH BACKWARD ALL курсор всегда оказывается
после последней строки или перед первой, соответственно.

Формы NEXT, PRIOR, FIRST, LAST, ABSOLUTE и RELATIVE выбирают одну
строку после соответствующего перемещения курсора. Если в этом
положении строки не оказывается, возвращается пустой результат,
а курсор остается в достигнутом положении перед первой строкой
или после последней.

Формы FORWARD и BACKWARD получают указанное число строк, сдвигаясь
соответственно вперед или назад; в результате курсор оказывается
на последней выданной строке.

Формы RELATIVE 0, FORWARD 0 и BACKWARD 0 действуют одинаково —
они считывают текущую строку, не перемещая курсор, т. е.,
повторно выбирая строку, выбранную последней. Эта операция будет
успешна, только если курсор не расположен до первой или после
последней строки; в этом случае строка возвращена не будет.

Секция INTO сохраняет значения столбцов извлеченной строки в
заданные переменные.

В PostgreSQL курсор может использоваться как в процедурном языке
PL/pgSQL, так и вне него. Вне PL/pgSQL секция INTO недоступна,
а FETCH возвращает строки клиенту SQL сервера, аналогично тому,
как возвращаются результаты SELECT запроса.

Для закрытия курсора используется оператор

CLOSE имя_курсора;

При этом в различных СУБД по-разному происходит освобождение
выделенной для курсора памяти. В СУБД PostgreSQL при закрытии
курсора освобождение памяти происходит автоматически неявным
образом, и сразу она становится доступной для других операций:
открытие другого курсора и т. д.

Следующий код создает курсор Abn, содержащий данные всех
абонентов в алфавитном порядке по ФИО, затем извлекает первые
две строки из курсора и закрывает курсор:
*/
DECLARE
    Abn CURSOR WITH HOLD
    FOR SELECT *
        FROM Abonent
        ORDER BY Fio;
FETCH 2 Abn;
CLOSE Abn;


/*
Рассмотрим примеры работы с явными курсорами.
*/

DO
$$
    DECLARE
        Curs REFCURSOR; -- курсорная переменная
        Rez  RECORD;
    BEGIN
        OPEN Curs FOR SELECT Accountid, Fio
                      FROM Abonent
                      ORDER BY Accountid;
        LOOP
            FETCH Curs INTO Rez;
            EXIT WHEN NOT FOUND;
            RAISE NOTICE ' % ', Rez;
        END LOOP;
        CLOSE Curs;
    END
$$;

/*
Результат выполнения:

(005488,"Аксенов С. А.")
(015527,"Конюхов В. С.")
(080047,"Шубина Т. П.")
(080270,"Тимошкина Н. Г.")
(080613,"Лукашина Р. М.")
(115705,"Мищенко Е. В.")
(126112,"Маркова В. П.")
(136159,"Свирина З. А.")
(136160,"Шмаков С. В.")
(136169,"Петрова Е. К.")
(443069,"Стародубцев Е. В.")
(443690,"Тултупова М. И.")

или
*/


DO
$$
    DECLARE
        Acc   VARCHAR(6);
        Aname VARCHAR(30);
        Var   INTEGER;
        Curs CURSOR (Ac TEXT) FOR
            SELECT Accountid, Fio
            FROM Abonent
            WHERE LEFT(Accountid, 2) = Ac
            ORDER BY Accountid;
    BEGIN
        OPEN Curs('08');
        LOOP
            FETCH Curs INTO Acc, Aname;
            GET DIAGNOSTICS Var = ROW_COUNT;
            IF (Var = 0)
            THEN
                EXIT;
            END IF;
            RAISE NOTICE '% %', Acc, Aname;
        END LOOP;
        CLOSE Curs;
    END
$$;

/*
080047 Шубина Т. П.
080270 Тимошкина Н. Г.
080613 Лукашина Р. М.
*/


/*
В первом примере показано, как может быть организована выборка
данных с использованием явного курсора, доступ к которому
производится через курсорную переменную Curs. Организуется цикл
LOOP, внутри которого контекстная переменная FOUND проверяет,
возвращает ли последняя выборка (FETCH) из явного курсора строку
данных. Если нет, то происходит выход из цикла LOOP с помощью
оператора EXIT и закрытие курсора.

Второй пример отличается от первого тем, что запрос для курсора
определяет сразу три его определения, а не при его
открытии, и вместо контекстной переменной FOUND используется
системный индикатор состояния ROW_COUNT, обозначающий число
строк, извлеченных последней выполненной командой. Кроме того,
курсор имеет параметр, задающий первые две цифры номера лицевого
счета.
*/


/*
Работа с явным курсором в PostgreSQL может быть организована не
только с помощью команд OPEN, FETCH и CLOSE, но и с использованием
цикла FOR, который выполняет данные операции автоматически в
неявном виде. Цикл FOR явного курсора реализуется в формате

FOR имя_записи IN имя_курсора [(параметр [, ...])]
LOOP
    <группа_операторов>
END LOOP;

Например, предыдущий код может быть записан с циклом FOR в
следующем виде:
*/

DO
$$
    DECLARE
        V_acc   VARCHAR(6);
        V_aname VARCHAR(30);
        Curs CURSOR FOR SELECT Accountid, Fio
                        FROM Abonent
                        ORDER BY Accountid;
    BEGIN
        FOR C_rec IN Curs
            LOOP
                V_acc := C_rec.Accountid;
                V_aname := C_rec.Fio;
                RAISE NOTICE ' % % ', V_acc, V_aname;
            END LOOP;
    END
$$;

/*
В следующем примере курсора с параметром выводятся номера
лицевых счетов абонентов и значения их платежей за услугу с
идентификатором 4. При этом вычисляется сумма значений платежей
в диапазоне от 150 до 200, а при превышении суммы 400
производится выход из цикла.
*/

DO
$$
    DECLARE
        Var          RECORD;
        Sum_pay      Currency := 0;
        v_service_id INTEGER;
        Curs CURSOR (Serv Services.Serviceid%TYPE) FOR
            SELECT Accountid, Paysum, Serviceid
            FROM Paysumma
            WHERE Serviceid = Serv;
    BEGIN
        v_service_id = 4;
        RAISE NOTICE ' % %', 'Accountid', 'Paysum';
        FOR Var IN Curs(v_service_id)
            LOOP
                EXIT WHEN Sum_pay > 400;
                RAISE NOTICE ' % %',
                    Var.Accountid,
                    LPAD(Var.Paysum::TEXT, 9);
                IF Var.Paysum BETWEEN 150 AND 200
                THEN
                    Sum_pay := Sum_pay + Var.Paysum;
                END IF;
            END LOOP;
        RAISE NOTICE ' Сумма % , Услуга % ', Sum_pay, v_service_id;
    END
$$;


/*
Результат выполнения:

Accountid Paysum
015527 280.10
015527 311.30
080270 144.50
080270 150.00
080270 160.00
115705 253.85
126112 135.50
136159 49.38
136159 120.00
136169 228.44
443069 166.69
Сумма 476.69

Операции с открытым курсором:
1) выборка только по одной строке;
2) обращение к текущей строке курсора (только для простых
   запросов — 1 таблица, без группировки и сортировки);
3) обработка обычно выполняется в цикле (цикл FOR по курсору,
   цикл FOR по запросу без явного определения курсора);
4) закрытие курсора (явно или автоматически).

Пример анонимного блока с пропуском и выводом одной строки:
*/

DO
$$
    DECLARE
        Curs REFCURSOR;
        Rez  RECORD;
    BEGIN
        OPEN Curs FOR SELECT *
                      FROM Abonent
                      ORDER BY Accountid;
        MOVE Curs;
        FETCH Curs INTO Rez;
        RAISE NOTICE ' % ', Rez;
        CLOSE Curs;
    END;
$$

/*
Результат выполнения:

(015527,3,1,65,"Конюхов В. С.",761699)

Вывод всех строк (обычно производится в цикле):
*/

DO
$$
    DECLARE
        Curs REFCURSOR;
        Rez  RECORD;
    BEGIN
        OPEN Curs FOR SELECT *
                      FROM Abonent
                      ORDER BY Accountid;
        LOOP
            FETCH Curs INTO Rez;
            EXIT WHEN NOT FOUND;
            RAISE NOTICE ' % ', Rez;
        END LOOP;
        CLOSE Curs;
    END;
$$

/*
Результат выполнения:

(005488,3,4,1,"Аксенов С. А.",556893)
(015527,3,1,65,"Конюхов В. С.",761699)
(080047,8,39,36,"Шубина Т. П.",257842)
