/*
Курсор может использоваться не только с SELECT, но и с любым
запросом, который возвращает строки (INSERT, UPDATE, DELETE и
MERGE с секцией RETURNING). Например, обновить данные таблицы
Services из таблицы Services_new и вывести список выполненных
действий можно следующим образом:
*/

DO $$
    DECLARE
        Result RECORD;
        Merge_cursor CURSOR FOR
            MERGE INTO Services S
            USING Services_new S_new
            ON S.Serviceid = S_new.Serviceid
            WHEN NOT MATCHED BY SOURCE THEN
        DELETE
            WHEN NOT MATCHED BY TARGET THEN
        INSERT (Serviceid, Servicenm)
        VALUES (S_new.Serviceid, S_new.Servicenm)
            WHEN MATCHED AND S.Servicenm != S_new.Servicenm THEN
        UPDATE SET Servicenm = S_new.Servicenm
        RETURNING S.Serviceid, S.Servicenm;
    BEGIN
        OPEN Merge_cursor;
        LOOP
            FETCH NEXT FROM Merge_cursor INTO Result;
            EXIT WHEN NOT FOUND;
            RAISE NOTICE 'Обработанная услуга: ID = %, Name = %',
                Result.Serviceid, Result.Servicenm;
        END LOOP;
        CLOSE Merge_cursor;
    END $$;


select *
from Services;


/*
Результат выполнения:
Обработанная услуга: ID = 7, Name = Капитальный ремонт
Обработанная услуга: ID = 8, Name = Содержание жилья



Система управления БД PostgreSQL позволяет использовать в модулях
процедурного языка двунаправленные курсоры. Двунаправленный курсор,
который позволяет получать доступ к определенным записям набора
данных курсора, определяет опция SCROLL после имени курсора.

Если курсор определен как двунаправленный, то доступны следующие
параметры выборки оператора FETCH:
- NEXT возвращает строку в курсе сразу же за текущей строкой и
  перемещает указатель текущей строки на возвращенную строку.
  Если инструкция FETCH NEXT выполняет первую выборку в отно-
  шении курсора, то она возвращает первую строку в наборе
  данных. NEXT является параметром по умолчанию выборки из
  курсора. Если создается NO SCROLL курсор, то поддерживается
  только параметр выборки NEXT;
- PRIOR возвращает строку в курсе, находящуюся непосредственно
  перед текущей строкой, и перемещает указатель текущей строки
  на возвращенную строку. Если инструкция FETCH PRIOR выполняет
  первую выборку из курсора, то не возвращается никакая строка
  и положение курсора остается перед первой строкой;
- FIRST возвращает первую строку в курсе и делает ее текущей;
- LAST возвращает последнюю строку в курсе и делает ее текущей;
- ABSOLUTE <число>. При положительном значении возвращается
  строка, отстоящая на <число> строк от начала курсора,
  а возвращенная строка становится новой текущей строкой.
  Если <число> имеет отрицательное значение, то возвращается
  строка, отстоящая на <число> строк от конца курсора,
  а возвращенная строка становится новой текущей строкой.
  Если <число> равно 0, то не возвращается ни одна строка.
  Аргумент <число> должен быть целочисленной константой;
- RELATIVE <число>. При положительном значении возвращается
  строка, отстоящая на <число> строк от текущей строки,
  а возвращенная строка становится новой текущей строкой.
  Если <число> имеет отрицательное значение, то возвращается
  строка, предшествующая на <число> строк текущей строке,
  а возвращенная строка становится новой текущей строкой.
  Если <число> равно 0, то возвращается текущая строка.
  Если при первой выборке из курсора инструкция FETCH RELATIVE
  указана с аргументом <число> в отрицательном значении или
  равном 0, строки не возвращаются. Аргумент <число> должен
  быть целочисленной константой.

Пример явного двунаправленного курсора может быть таким:
*/

DO $$
    DECLARE
        Acc  VARCHAR(6);
        Name VARCHAR(30);
        Curs SCROLL CURSOR FOR
            SELECT Accountid, Fio
            FROM Abonent
            ORDER BY Accountid;
    BEGIN
        OPEN Curs;
        FETCH FIRST FROM Curs INTO Acc, Name; ---	FETCH FIRST	Переходит к первой строке
        RAISE NOTICE ' %  %', Acc, Name; ---FETCH LAST	Переходит к последней строке
        FETCH LAST FROM Curs INTO Acc, Name;
        RAISE NOTICE ' %  %', Acc, Name;
        CLOSE Curs;
    END $$;

/*
Результат выполнения:
005488  Аксенов С. А.
443690  Тулупова М. И.

В данном примере с помощью двунаправленного курсора сначала
выбирается и выводится первая запись набора данных (номер
лицевого счета и ФИО абонента с наименьшим номером лицевого
счета), а затем последняя (номер лицевого счета и ФИО абонента
с наибольшим номером лицевого счета).

Следует отметить еще одну важную особенность работы с курсорами.
Они позволяют обеспечить обновление или удаление строки, на
которой в данный момент установлен курсор, с помощью конструкции
WHERE CURRENT OF в запросе UPDATE или DELETE. В этом случае
<группа_операторов> при обновлении строки, на которой установлен
курсор, должна выглядеть так:

UPDATE базовая_таблица SET ... WHERE CURRENT OF имя_курсора;

При удалении строки, на которой установлен курсор,
<группа_операторов> должна выглядеть таким образом:

DELETE FROM базовая_таблица WHERE CURRENT OF имя_курсора;

За одну операцию обновления могут быть изменены несколько
столбцов текущей строки курсора, но все они должны принадлежать
одной таблице. Если выполняется удаление, то будет удалена
строка, установленная текущей в курсоре. Это может быть полезно
в ситуациях, когда нужно выполнить обновление или удаление
непосредственно после того, как строка была выбрана курсором,
без необходимости указывать дополнительные условия.
Предположим, требуется увеличить на 10 % каждое значение
начисления за определенную услугу. Используя курсор, это можно
сделать следующим образом:
*/

DO $$
    DECLARE
        Serv_record RECORD;
        Serv_cursor CURSOR FOR
            SELECT *
            FROM Nachislsumma_1
            WHERE Serviceid = 1;
    BEGIN
        OPEN Serv_cursor;
        LOOP
            FETCH NEXT FROM Serv_cursor INTO Serv_record;
            EXIT WHEN NOT FOUND;
            -- -- ← выходим, если FETCH ничего не вернул
            -- Увеличение начисления на 10 % для текущей строки
            UPDATE Nachislsumma_1
            SET Nachislsum = Nachislsum * 1.10
            WHERE CURRENT OF Serv_cursor;
        END LOOP;
        CLOSE Serv_cursor;
    END $$;

/*
Пример обработки ошибки при выполнении UPDATE из-за неверного
имени столбца:
*/

DO $$
    DECLARE
        Serv_record RECORD;
        Serv_cursor CURSOR FOR
            SELECT *
            FROM Nachislsumma_1
            WHERE Serviceid = 1;
    BEGIN
        OPEN Serv_cursor;
        LOOP
            FETCH NEXT FROM Serv_cursor INTO Serv_record;
            EXIT WHEN NOT FOUND;
            BEGIN
                -- Предположим, что у нас ошибка в названии колонки
                UPDATE Nachislsumma_1
                SET NonExistentColumn = Nachislsum * 1.10
                WHERE CURRENT OF Serv_cursor;
            EXCEPTION
                WHEN OTHERS THEN
                    RAISE NOTICE 'Error updating record: %, SQL Error: %',
                        Serv_record, SQLERRM;
            END;
        END LOOP;
        CLOSE Serv_cursor;
    EXCEPTION
        WHEN OTHERS THEN
            RAISE NOTICE 'Error with cursor or fetching data: %',
                SQLERRM;
    END $$;


/*
Обработка ошибки при открытии курсора из-за отсутствия таблицы:
*/
DO $$
    DECLARE
        Serv_record RECORD;
        Serv_cursor CURSOR FOR
            -- Предположим, что таблица не существует
            SELECT *
            FROM NonExistentTable
            WHERE Serviceid = 1;
    BEGIN
        OPEN Serv_cursor; -- Это вызовет ошибку
        LOOP
            FETCH NEXT FROM Serv_cursor INTO Serv_record;
            EXIT WHEN NOT FOUND;
            BEGIN
                UPDATE Nachislsumma_1
                SET Nachislsum = Nachislsum * 1.10
                WHERE CURRENT OF Serv_cursor;
            EXCEPTION
                WHEN OTHERS THEN
                    RAISE NOTICE 'Error updating record: %, SQL Error: %',
                        Serv_record, SQLERRM;
            END;
        END LOOP;
        CLOSE Serv_cursor;
    EXCEPTION
        WHEN OTHERS THEN
            RAISE NOTICE 'Error with cursor or fetching data: %',
                SQLERRM;
    END $$;

/*
1. Построчная обработка с ветвлением логики
-- Нельзя одним UPDATE, т.к. логика разная для каждой строки
FOR rec IN SELECT * FROM orders LOOP
    IF rec.amount > 10000 THEN
        UPDATE orders SET status = 'VIP', discount = 0.15 WHERE CURRENT OF cur;
    ELSIF rec.amount > 5000 THEN
        UPDATE orders SET status = 'REGULAR', discount = 0.10 WHERE CURRENT OF cur;
    ELSE
        UPDATE orders SET status = 'BASIC', discount = 0.05 WHERE CURRENT OF cur;
    END IF;
END LOOP;


2. Обновление с зависимостью от предыдущих строк
Например, расчет накопительного итога или баланса:

DECLARE running_balance NUMERIC := 0;
FOR rec IN SELECT * FROM transactions ORDER BY date LOOP
    running_balance := running_balance + rec.amount;
    UPDATE transactions SET balance = running_balance WHERE CURRENT OF cur;
END LOOP;


3. Необходимость WHERE CURRENT OF
Когда нужно обновить/удалить именно ту строку, которую только что прочитали, без повторного поиска:
-- Гарантированно обновляем ту же строку
UPDATE accounts SET balance = balance * 1.10 WHERE CURRENT OF cursor_name;


4. Прокрутка назад (SCROLL)
Когда нужен произвольный доступ к строкам набора:
DECLARE cur SCROLL CURSOR FOR SELECT * FROM employees ORDER BY salary DESC;
FETCH FIRST FROM cur;  -- Самый богатый
FETCH LAST FROM cur;   -- Самый бедный
FETCH ABSOLUTE 5 FROM cur;  -- Пятый по зарплате


Золотое правило
Используй курсор только когда:
-Нельзя выразить логику одним DML-запросом;
-Нужна построчная обработка с разной логикой для каждой строки;
-Важна обработка ошибок по строкам;
-Нужен произвольный доступ к строкам (SCROLL);


В заключение описания курсоров в процедурном языке следует
отметить, что в некоторых случаях, конечно, применение курсора
неизбежно, однако по возможности этого следует избегать и
работать со стандартными запросами обработки данных (SELECT,
UPDATE, INSERT, DELETE). Помимо того, что курсоры не позволяют
проводить операции изменения над всем объемом данных, скорость
выполнения операций обработки данных посредством курсора заметно
ниже, чем у стандартных средств SQL.
*/


/*

Хранимые процедуры

Хранимой процедурой (stored procedure) называется скомпилированная
подпрограмма произвольной длины на SQL или процедурном языке
PL/pgSQL, которая хранится в БД как часть метаданных.

SQL-программирование хранимых процедур

В PostgreSQL процедуры, созданные с использованием SQL, не могут
возвращать значения, строки или таблицы напрямую, как это делают
функции. Это принципиальное отличие от функций, которые возвращают
данные. Хранимые процедуры предоставляют следующие возможности:
- управлять транзакциями — внутри процедур можно явно начинать,
  подтверждать или откатывать транзакции;
- изменять состояние базы данных — выполнять операции вставки,
  обновления или удаления данных;
- выполнять сложные задачи, вызывая другие процедуры или функции.

Синтаксис команды определения ХП на SQL выглядит так:

CREATE [ OR REPLACE ] PROCEDURE
имя_процедуры (
    [ [ режим_параметра ] [ имя_параметра ]
    тип_параметра [
    DEFAULT | = ] выражение_по_умолчанию ]
    [, ...]
)
LANGUAGE SQL
<тело_процедуры>

где
<тело_процедуры>::=
BEGIN ATOMIC
    SQL запрос;
    SQL запрос;
...
    SQL запрос;
END;

Для вызова процедуры используется команда CALL:

CALL имя_процедуры ([аргумент])
[,...];


Следующая процедура просто обновляет данные в таблице:
*/
CREATE PROCEDURE Update_paysum
(
Acc TEXT, Serv INT, New_Paysum Currency, Emp_year Tyear
)
    LANGUAGE SQL
AS $$
UPDATE Paysumma
SET Paysum = Paysum * New_Paysum
WHERE Accountid = Acc
  AND Serviceid = Serv
  AND Payyear = Emp_year;
$$;


/*
Процедура Update_pasum принимает в качестве входных параметров:
идентификатор абонента, идентификатор услуги, процент изменения
оплат, год и обновляет информацию в базе данных. Выполнение
процедуры:
*/

CALL Update_Paysum('115705', 1, 0.9, 2023::Tyear);

select *
from Paysumma
where Accountid = '115705'
  and Payyear = 2023
  and Serviceid = 1;

/*
Это действие уменьшит на 10 % значения платежей за 2023 г.
абонента с номером '115705'.

Процедура может выполнять несколько операций, но не возвращать
данные, например:
*/


CREATE PROCEDURE Perform_year_end
(
Acc TEXT, New_paysum Currency, Serv INT, Emp_year INT
)
    LANGUAGE SQL
AS $$
-- Обновление платежей
UPDATE Paysumma
SET Paysum = Paysum * New_paysum
WHERE Accountid = Acc
  AND Serviceid = Serv
  AND Payyear = Emp_year;

-- Удаление старых заявок
DELETE
FROM Request
WHERE Executed
  AND Executiondate
    < (
      SELECT MAX(Paydate)
      FROM Paysumma
      ) - INTERVAL '3 year';

-- Добавление начисления
INSERT INTO Nachislsumma
VALUES (NEXTVAL('Gen_Nachislsumma'),
        Acc, Serv, 520.00, 12, Emp_year);
$$;

---Вызов:

CALL Perform_year_end('115705', 0.9, 1, 2022);

/*
Процедуры могут вызывать другие процедуры и функции, выполняемые
сложные последовательности действий:
*/


CREATE PROCEDURE Full_backup_procedure
(
Acc TEXT, Serv INT, New_paysum Currency, Emp_year INT
)
    LANGUAGE SQL
AS $$
-- Обновление платежей
    CALL Update_paysum(Acc, Serv, New_paysum, Emp_year);
-- Удаление старых заявок
    DELETE
    FROM Request
    WHERE Executondate <
          (
          SELECT MAX(Paydate)
          FROM Paysumma
          ) - INTERVAL '3 year'
      AND Executed;
-- Добавление начисления
    INSERT INTO Nachislsumma
    VALUES (NEXTVAL('Gen_Nachislsumma'),
            Acc, Serv, 520.00, 12, Emp_year);
    $$;

---Выполнение:

CALL Full_backup_procedure('115705', 1, 0.9, 2022);


/*
Программирование хранимых процедур на языке PL/pgSQL

Хранимая процедура (ХП) на PL/pgSQL — это именованный блок
процедурного языка, содержащий определенный набор инструкций.
Он обычно представляет собой последовательность SQL-команд и
SQL-запросов, выполняющих некоторую задачу.

Хранимые процедуры похожи на обыкновенные процедуры языков
высокого уровня, они могут иметь входные и выходные параметры,
использовать локальные переменные, внутри может быть объявлена
другая процедура или функция.

В них есть возможность производить вычисления и операции над
символьными данными, результаты которых могут присваиваться
переменным и параметрам. Кроме того, в ХП можно выполнять
стандартные операции с БД. Особенно важно то, что в ХП возможны
циклы и ветвления.

Хранимая процедура может быть вызвана:
- с клиента,
- из другой процедуры,
- функции,
- выполнимого блока или триггера.

Хранимые процедуры бывают следующих типов:

1) системные предназначены для выполнения различных
   административных действий. Системные ХП имеют специальный
   префикс, хранятся в системной БД и могут быть вызваны
   в контексте любой другой БД;

2) пользовательские реализуют какие-либо действия. Каждая ХП
   располагается в конкретной БД, где и выполняется;

3) временные существуют лишь некоторое время, после чего
   автоматически уничтожаются сервером. Они делятся на локальные
   и глобальные.

Основными функциями пользовательских хранимых процедур являются:

1) реализация сложной бизнес-логики предметной области;
2) обработка ошибок;
3) обеспечение целостности и согласованности БД.

Использование ХП имеет свои преимущества:

1) при создании текст процедуры оптимизируется и хранится в БД
   в компилированном виде. В таком виде процедура выполняется
   гораздо быстрее, чем в случае динамической компиляции каждой
   составляющей ее команды. Хранимые процедуры выполняются
   сервером, а не клиентом, что позволяет сократить сетевой
   трафик;

2) использование ХП часто позволяет значительно сократить объем
   кода клиентского приложения. Приложения, получающие доступ
   к одной и той же БД, могут совместно использовать одни и те же
   процедуры, и не нужно снова программировать одни и те же
   действия, благодаря чему уменьшается риск программных ошибок
   в клиентских приложениях и снижается время разработки новых
   программных продуктов;

3) если процедура модифицируется, то все внесенные изменения
   автоматически отражаются во всех приложениях, использующих
   процедуру, обеспечивая их согласованность;

4) в большинстве СУБД ХП считаются защищаемыми объектами,
   и им назначаются отдельные привилегии. Вместо того чтобы
   предоставить пользователю доступ к таблице БД напрямую,
   можно дать права ХП. Пользователь, вызывающий ХП, должен
   иметь право на ее выполнение;

5) в больших БД набор ХП может стать для прикладных программ
   основным средством доступа к БД. Часто вызов стандартной
   процедуры более понятен, чем выполнение последовательности
   SQL-команд (запросов);

6) возможности условной обработки, предоставляемые ХП, часто
   используются для реализации бизнес-логики в БД.

Бизнес-логика — это совокупность правил, принципов,
зависимостей поведения объектов предметной области (области
человеческой деятельности, которую система поддерживает).

Другими словами, бизнес-логика (деловая логика предметной
области) — это реализация правил и ограничений автоматизируемых
операций, реализация предметной области в информационной системе.

К ней относятся, например, формулы расчета ежемесячных плат
за жилищно-коммунальные услуги (в информационных системах ЖКХ),
автоматизированная отправка сообщений электронной почты
руководителю проекта по окончании выполнения частей задания
всеми подчиненными (в системах управления проектами), отказ
от отеля при отмене рейса авиакомпанией (в туристическом
бизнесе) и т. д.

В ХП можно реализовывать сложные алгоритмы обработки данных
внутри базы, причем во многих случаях использование ХП позволяет
четко отделять алгоритмы логики программы от алгоритмов обработки
данных.

Вместе с тем использование ХП имеет следующие недостатки:

1) большая часть работы выполняется на сервере, а меньшая —
   на клиентской;
2) логика приложения может дублироваться в серверном коде и код
   для ХП, тем самым усложняя процесс манипулирования данными;
3) поскольку синтаксис процедурных языков в разных СУБД
   существенно различается, то перенос БД с одной СУБД на другую
   может привести к проблемам.

Процедуру нельзя усложнять «снаружи», т. е. ее нельзя соединять,
отфильтровать, группировать и т. п.

Хранимые процедуры по-разному реализованы в разных СУБД.
Различают создание ХП и их вызов.

В PostgreSQL хранимые процедуры создаются запросом CREATE PROCEDURE,
имеющим синтаксис

CREATE [OR REPLACE] PROCEDURE имя_процедуры
([[<режим_параметра>] [имя_параметра] <тип_параметра>
[DEFAULT | =] выражение_по_умолчанию] [, ...]] )
LANGUAGE PLPGSQL
AS
$$
[<список_объявления>]
BEGIN
    <блок_исполнения>
    [EXCEPTION
    <блок_обработки_исключений>]
END;
$$

где

режим_параметра ::= [IN | OUT | INOUT]

Входные параметры хранимой процедуры указываются в круглых
скобках после имени создаваемой процедуры. Причем в качестве
входных параметров могут использоваться выражения. При объявлении
входных параметров допускается задавать значения по умолчанию,
например:

CREATE PROCEDURE p1(x INTEGER = 123)
AS ...

Подстановка значения по умолчанию происходит во время выполнения
процедуры.

Необязательный список объявления (раздел деклараций) служит для
объявления локальных переменных и курсоров.

Блок операторов представляет собой обязательный раздел исполнения
(раздел исполняемого кода), может содержать код для обработки
исключений. В разделе исполняемого кода могут использоваться
как обычные локальные переменные, определенные в разделе
деклараций, так и входные и выходные параметры.

Временные ХП могут быть вызваны только из того соединения,
в котором созданы. При создании такой процедуры ей необходимо
дать имя, начинающееся с pg_temp. Как и все временные объекты,
ХП этого типа автоматически удаляются при отключении пользователя,
перезапуске или остановке сервера.

Получить список хранимых процедур в PostgreSQL можно следующим
запросом:
*/


SELECT *
FROM information_schema.routines;


/*
Для изменения определения ХП в PostgreSQL используется запрос
ALTER PROCEDURE в следующем формате:

ALTER PROCEDURE имя_процедуры [[ [ <режим_параметра> ]
[ имя_параметра ] <тип_параметра> [, ...] ] ]
{<действие> [ ... ] [ RESTRICT ]
| RENAME TO новое_имя
| OWNER TO {новый_владелец | CURRENT_ROLE | CURRENT_USER
| SESSION_USER }
| SET SCHEMA новая_схема
| [NO] DEPENDS ON EXTENSION имя_расширения
}

Удаление хранимых процедур осуществляется запросом DROP PROCEDURE.
Запрос имеет такой формат:

DROP PROCEDURE [ IF EXISTS ] имя_процедуры
[[ [ <режим_параметра> ] [ имя_параметра ]
<тип_параметра> [, ...] ] ] [, ...]
[ CASCADE | RESTRICT ]

где IF EXISTS — не считать ошибкой, если процедура не существует;
CASCADE — автоматически удалять объекты, зависящие от данной
процедуры, и, в свою очередь, все зависящие от них объекты;

RESTRICT — отказать в удалении процедуры, если от нее зависят
какие-либо объекты. Это поведение по умолчанию.

Удалить хранимую процедуру можно лишь в том случае, если ее не
используют другие процедуры или триггеры!!!

Для возврата данных вызывающей клиентской программе в процедурах
используются выходные параметры!!!

Выходные параметры обычно используют, когда из хранимой процедуры
требуется получить одно значение или одну строку информации,
а не набор данных!!!
Для возвращения одной строки информации гораздо
выгоднее в смысле быстродействия использовать выходные параметры,
чем подготавливать набор данных.

Если все-таки необходимо получить из ХП набор данных, используют
несколько вариантов обхода проблемы невозможности использования
ХП в запросе SELECT:

1) оформить хранимую процедуру как функцию. Функции в PostgreSQL
   допустимо использовать в секции FROM запроса SELECT;

2) получить набор данных через временную таблицу;

3) получить многострочный результат за счет использования
   выходного параметра типа REFCURSOR.

Вызов ХП в PostgreSQL производится оператором CALL:

CALL имя_процедуры [( ] [ аргумент1 =>] <значение> ]
[ , [аргумент2 =>] <значение>... ] [ ) ];

Процедуру могут вызвать функция, процедура или блок DO.

Каждому параметру OUT или INOUT для процедуры должна
соответствовать переменная в операторе CALL, и этой переменной
по завершении процедуры будет присвоено возвращаемое процедурой
значение. Переменная, соответствующая выходному параметру,
может быть простой переменной или полем переменной составного
типа. Если выходное значение не нужно, вместо переменной можно
указать NULL.

Начнем с примера простой ХП, предназначенной для редактирования
значения в строке, идентифицируемой по первичному ключу,
с обработкой исключительной ситуации.
Например, запрос на создание
ХП Edit_disrepair с входными параметрами может быть таким:

*/


CREATE PROCEDURE Edit_disrepair
(
Failure_id Pkfield, Failure_nm TEXT
)
    LANGUAGE PLPGSQL
AS
$$
BEGIN
    IF (EXISTS
    (
    SELECT *
    FROM Disrepair
    WHERE Failureid = Failure_id
    ))
    THEN
        UPDATE Disrepair
        SET Failurenm = Failure_nm
        WHERE Failureid = Failure_id;
    ELSE
        RAISE 'Отсутствует строка для редактирования';
    END IF;
END $$;

/*Редактирование наименования неисправности с номером 3 путем вызова
ХП Edit_disrepair:
*/

CALL Edit_disrepair(3, 'Течет вода из водогрейной колонки');

/*
будет выполнено успешно, а попытка редактирования наименования
неисправности с номером 9
*/

CALL Edit_disrepair(9, 'Течет вода из водогрейной колонки');

/*
приведет к немедленному прекращению выполнения процедуры и откату
транзакции, а также выдаче следующего сообщения об исключительной
ситуации:

SQL Error [Р0001]: Ошибка: Отсутствует строка для редактирования
Где: функция PL/pgSQL edit_disrepair(pkfield, text), строка 10,
оператор RAISE
*/

/*
Рассмотрим другие примеры работы с процедурами. Пусть, например,
необходимо вывести с помощью ХП среднее значение оплат по
указанному лицевому счету, увеличенное в заданное число раз.
Для решения задачи создадим процедуру SummaryPay и на этом
примере продемонстрируем стандартное создание и использование ХП
с входными и выходными параметрами. DDL-скрипт создания процедуры:

*/

CREATE PROCEDURE SummaryPay
(
Laccountid VARCHAR(6), Koeff INT, OUT Resultsum Currency
)
    LANGUAGE PLPGSQL
AS
$$
BEGIN
    SELECT AVG(Paysum) * Koeff
    INTO Resultsum
    FROM Paysumma
    WHERE Accountid = Laccountid;
END $$;

/*
Выполним созданную процедуру с помощью следующего анонимного
блока:
*/

DO
$$
    DECLARE
        Vresultsum CURRENCY;
    BEGIN
        CALL SummaryPay('015527', 2, Vresultsum);
        RAISE NOTICE ' %', Vresultsum;
    END $$;

/*
Результат выполнения:
1508.80

В приведенном коде сначала объявляется локальная переменная
Vresultsum, в которую будет сохраняться значение выходного
параметра Resultsum процедуры. Затем вызывается процедура
с указанием значений входных параметров и сохранением выходного
параметра в локальную переменную. В операторе CALL имена
параметров опущены при вызове процедуры, т. е. выполняются
позиционное присвоение значений параметрам.
Вывод результата (1508.80) осуществляется с помощью оператора RAISE.

Примечание
Имена выходных параметров ХП и локальных переменных, принимающих
результаты, могут быть разными, однако типы данных и порядок
расположения должны совпадать!!!

Возвращаемое значение можно вывести и без использования
анонимного блока, для этого вместо выходных переменных необходимо
указать NULL:
*/
CALL SummaryPay('015527', 2, NULL);

/*
Процедура SummaryPay в приведенном примере возвращала одно
единственное значение в качестве результата. При попытке
организовать аналогичный образом работу с процедурой, возвращающей
многострочный набор данных, в результате будет все равно одна
единственная строка. Однако это не означает, что с помощью
процедуры нельзя получить многострочные результаты.

Рассмотрим следующий DDL-сценарий, который создает хранимую
процедуру с именем Listabonent в учебной БД:
*/

CREATE OR REPLACE PROCEDURE Listabonent
(
M INT, G INT
)
    LANGUAGE PLPGSQL
AS $$
DECLARE
    Item RECORD;
BEGIN
    FOR Item IN
        (
        SELECT A.Accountid,
               A.Fio,
               P.Paydate,
               P.Paysum,
               P.Paymonth,
               P.Payyear
        FROM Abonent  A,
             Paysumma P
        WHERE A.Accountid = P.Accountid
          AND P.Paysum > 1000
          AND P.Paymonth = M
          AND P.Payyear = G
        )
        LOOP
            RAISE NOTICE '% ', Item.Accountid || ' ' || Item.Fio || ' ' || Item.Paydate || ' ' || Item.Paysum || ' ' ||
                               Item.Paymonth || ' ' || Item.Payyear;
        END LOOP;
END;
$$;

/*
Процедура Listabonent выводит строку, состоящую из номера
лицевого счета абонента, ФИО абонента, даты оплаты, значения
оплаты, месяца и года, за которые производится оплата,
с значением, большим 1000. В теле процедуры входные параметры
M и G используются для отбора строк, содержащих информацию
о платах больше 1000, произведенных абонентом за заданный
месяц (M) указанного года (G).

Процедуры можно вызвать следующим запросом:
*/

CALL Listabonent(3, 2025);

/*
Процедуру Listabonent также можно реализовать с использованием
типа REFCURSOR в качестве типа выходного результата.
В таком случае скрипт создания процедуры должен быть следующий:
*/
drop procedure Listabonent;


CREATE OR REPLACE PROCEDURE Listabonent
(
M INT, G INT, OUT Currencycursor REFCURSOR
)
    LANGUAGE PLPGSQL
AS
$$
BEGIN
    OPEN Currencycursor FOR
        SELECT A.Accountid,
               A.Fio,
               P.Paydate,
               P.Paysum,
               P.Paymonth,
               P.Payyear
        FROM Abonent                   A
                 NATURAL JOIN Paysumma P
        WHERE P.Paysum > 1500
          AND P.Paymonth = M
          AND P.Payyear = G;
END $$;


/*
В приведенном скрипте для процедуры объявляется выходной параметр
Currencycursor типа REFCURSOR. С помощью оператора OPEN для
параметра создается соответствующий курсор, определяемый для
запроса SELECT.
*/

DO
$$
    DECLARE
        Mycursor  REFCURSOR;
        Accountid VARCHAR(6);
        Fio       TEXT;
        Paydate   DATE;
        Paysum    Currency;
        Paymonth  TMonth;
        Payyear   TYear;
    BEGIN
        CALL Listabonent(3, 2025, MyCursor);
        LOOP
            FETCH NEXT FROM Mycursor INTO Accountid,
                Fio, Paydate, Paysum, Paymonth, Payyear;
            IF NOT FOUND
            THEN
                EXIT;
            END IF;
            RAISE NOTICE '%', CONCAT_WS(' ', Accountid, Fio,
                                        Paydate, Paysum, Paymonth, Payyear);
        END LOOP;
        CLOSE Mycursor;
    END $$;

/*
Пакет объявляет локальную переменную Mycursor, после чего
выполняет процедуру Listabonent, присваивающую курсор локальной
переменной. Затем в цикле выбираются строки из курсора,
после чего он закрывается.


Решим задачу расчета остатка на начало заданного периода для
определенного абонента по заданной услуге. Под значением остатка
на начало заданного периода Begin_Ostatok будем понимать разницу
между суммами значений начислений (Nachislsum) и платежей (Paysum)
за каждый месяц всего периода, предшествующего заданному:

Begin_Ostatok = SUM(Nachislsum) - SUM(Paysum)

При этом положительное значение Begin_Ostatok считается
задолженностью, а отрицательное — переплатой.

DDL-скрипт процедуры Saldo для расчета и вывода значения остатка
на начало первого месяца заданного периода для заданного абонента
по заданной услуге:
*/


DROP PROCEDURE IF EXISTS saldo(
                              VARCHAR, pkfield, tmonth, tyear, currency, VARCHAR
);

-- Создаем процедуру заново
CREATE OR REPLACE PROCEDURE Saldo
(
IN p_account_id   VARCHAR, -- номер абонента
IN p_service_id   INTEGER, -- услуга
IN p_start_month  INTEGER, -- месяц начала периода
IN p_start_year   INTEGER, -- год начала периода
OUT p_balance     NUMERIC, -- остаток (долг/переплата)
OUT p_period_info VARCHAR -- текстовое описание периода
)
    LANGUAGE PLPGSQL
AS $$
BEGIN
    -- Формируем текстовое описание периода (например: 2024-03)
    p_period_info := p_start_year || '-' || LPAD(p_start_month::TEXT, 2, '0');

    -- Расчет остатка на начало периода
    SELECT COALESCE(
                   (
                   SELECT SUM(N.Nachislsum)
                   FROM Nachislsumma N
                   WHERE N.Accountid = p_account_id
                     AND N.Serviceid = p_service_id
                     AND (N.Nachislyear < p_start_year
                       OR (N.Nachislyear = p_start_year
                           AND N.Nachislmonth < p_start_month))
                   ), 0
           )
               -
           COALESCE(
                   (
                   SELECT SUM(P.Paysum)
                   FROM Paysumma P
                   WHERE P.Accountid = p_account_id
                     AND P.Serviceid = p_service_id
                     AND (P.Payyear < p_start_year
                       OR (P.Payyear = p_start_year
                           AND P.Paymonth < p_start_month))
                   ), 0
           )
    INTO p_balance;
END;
$$;

/*
Пример выполнения ХП:
*/

DO $$
    DECLARE
        balance     NUMERIC;
        period_info VARCHAR;
    BEGIN
        CALL Saldo('015527', 1, 3, 2024, balance, period_info);
        RAISE NOTICE 'Период: %, Остаток: %', period_info, balance;
    END $$;

---сигнатура процедуры
SELECT proname,
       pg_get_function_identity_arguments(oid) AS arguments
FROM pg_proc
WHERE proname = 'saldo';

/*
Рассмотрим следующий пример DDL-скрипта, демонстрирующий
возможности использования рекурсии в процедурах. В примере
выполняется расчет факториалов, для чего создаются таблица Ftable
и две процедуры с именами Factorial и FactorialSet [9].

Скрипт создания таблицы и процедур будет выглядеть так:
*/

CREATE TABLE Ftable
(
    Fnum   INT,
    Fvalue INT
);

CREATE OR REPLACE PROCEDURE Factorial
(
Num IN INT, N_factorial OUT INT
)
AS $$
DECLARE
    Num_less_one INT;
    Vn_factorial INT;
BEGIN
    IF (Num < 0)
    THEN
        RETURN;
    END IF;

    IF (Num = 1 OR Num = 0)
    THEN
        N_factorial := 1;
    ELSE
        Num_less_one := Num - 1;
        CALL Factorial(Num_less_one, Vn_factorial);
        N_factorial := Vn_factorial * Num;
    END IF;
END;
$$
    LANGUAGE PLPGSQL;

CREATE OR REPLACE PROCEDURE Factorialset
(
Minf INT, Maxf INT
)
AS $$
DECLARE
    i INT;
    f INT;
BEGIN
    DELETE FROM Ftable;
    IF (Maxf < Minf)
    THEN
        RETURN;
    END IF;
    i := Minf;
    WHILE (i <= Maxf)
        LOOP
            CALL Factorial(i, f);
            INSERT INTO Ftable (Fnum, Fvalue) VALUES (i, f);
            i := i + 1;
        END LOOP;
END;
$$
    LANGUAGE PLPGSQL;

/*
Таблица Ftable предназначена для хранения значений факториала.
В столбце Fnum хранится число, для которого вычисляется факториал,
а в столбце Fvalue — само значение факториала.

Если на входе процедуры ноль или единица, то значение факториала
(N_Factorial) принимается равным единице, и оператор RETURN
осуществляет возврат выходного параметра и выход из процедуры.
Если на входе целое положительное число, отличное от нуля или
единицы, то происходит рекурсивное вычисление факториала
с использованием соотношения:

Num! = Num * (Num - 1)!

Для типа INTEGER (тип выходного параметра) возможно вычисление
факториала (без переполнения разрядной сетки) для значения 12,
а для типа DOUBLE PRECISION — 170.

Процедура Factorial вычисляет значение факториала рекурсивным
методом. Рекурсивный вызов процедуры осуществляется при вызове
процедурой самой себя запросом CALL!!!

Чтобы вызвать процедуру Factorial и передать ей в качестве
параметра значение 12, необходимо выполнить запрос:
*/
CALL Factorial(12, NULL);

/*
Процедура FactorialSet предназначена для вычисления значений
факториала чисел из некоторого диапазона и занесения полученных
результатов в таблицу Ftable. Процедура получает в качестве
параметров первое (Minf) и последнее (Maxf) значения диапазона
вычисления факториала. В теле процедуры осуществляется цикл
от Minf до Maxf с шагом, равным единице. Для каждого значения
параметра цикла (локальная переменная i) вычисляется значение
факториала путем вызова процедуры Factorial. Число, для которого
вычислен факториал, и значение факториала заносятся в таблицу
Ftable. Например, чтобы вычислить пять значений факториала
чисел от 1 до 5, необходимо в интерактивном режиме выполнить
запрос:
*/

CALL Factorialset(1, 5);

/*
Расчет каждого значения
n	Расчет	 Результат
1!	1	1
2!	1 × 2	2
3!	1 × 2 × 3	6
4!	1 × 2 × 3 × 4	24
5!	1 × 2 × 3 × 4 × 5	120

*/

/*
Для просмотра результатов нужно выполнить запрос для таблицы
Ftable:
*/

SELECT *
FROM Ftable;

--Если же попытаться, например, выполнить:

CALL Factorial(13, NULL);

/*
то получится ошибка:

SQL Error [22003]: ОШИБКА: целое вне диапазона
Где: функция PL/pgSQL factorial(integer), строка 13,
оператор присваивание.


Таким образом, с помощью созданной процедуры Factorial можно
вычислить факториал числа, не превышающего 12.

Кроме того, в PostgreSQL максимальная глубина вложенности вызовов
хранимых процедур, включая рекурсивные вызовы, ограничена
параметром max_stack_depth, размер которого измеряется
в килобайтах. Если глубина рекурсии вызовов процедур больше,
чем разрешено параметром max_stack_depth, произойдет ошибка
"стек переполнен" (stack overflow), и вызов будет прерван.
В таком случае, возможно, потребуется изменить значение параметра
max_stack_depth в конфигурационном файле PostgreSQL
(например, postgresql.conf) и перезапустить сервер PostgreSQL.

Поэтому при проектировании и реализации рекурсивных хранимых
процедур в PostgreSQL важно учитывать ограничения глубины
вложенности и следить за использованием ресурсов стека.
*/


/*
Рассмотрим пример еще одного DDL-скрипта, создающего таблицу Saldo
и процедуру с именем ResultSaldo. Процедура ResultSaldo позволяет
для заданного абонента по заданной услуге подсчитать остаток
на конец каждого года определенного периода.

Скрипт:
*/

CREATE TABLE Saldo
(
    Account        VARCHAR(6) NOT NULL REFERENCES Abonent ON UPDATE CASCADE,
    Service        Pkfield    NOT NULL REFERENCES Services ON UPDATE CASCADE,
    Year           Tyear,
    Begin_ostatok  Currency,
    Nachisl        Currency,
    Pay            Currency,
    Result_ostatok Currency
);

/*
Процедура Resultsaldo:
*/

CREATE OR REPLACE PROCEDURE Resultsaldo
(
Var_account          VARCHAR(6),
Var_serv             PKFIELD,
Var_start_year       Tyear,
Var_final_year       Tyear,
Var_ostat            Currency,
OUT Var_result_ostat Currency
)
    LANGUAGE PLPGSQL
AS $$
DECLARE
    Var_begin_Ostatok      Currency = 0;
    Var_nach               Currency = 0;
    Var_pay                Currency = 0;
    Var_predbegin_ostatok  Currency = 0;
    Var_pred_nachisl       Currency = 0;
    Var_pred_pay           Currency = 0;
    Var_predresult_ostatok Currency = 0;
BEGIN
    IF Var_start_year > Var_final_year
    THEN
        Var_result_ostat = Var_ostat;
        RETURN;
    END IF;

    -- получение значений начислений и платежей
    -- для абонента за заданный год
    SELECT COALESCE(
                   (
                   SELECT SUM(N.Nachislsum)
                   FROM Nachislsumma N
                   WHERE N.Accountid = Var_account
                     AND N.Serviceid = Var_serv
                     AND N.Nachislyear = Var_start_year
                   GROUP BY N.Accountid, N.Serviceid, N.Nachislyear
                   ), 0),
           COALESCE(
                   (
                   SELECT SUM(P.Paysum)
                   FROM Paysumma P
                   WHERE P.Accountid = Var_account
                     AND P.Serviceid = Var_serv
                     AND P.Payyear = Var_start_year
                   GROUP BY P.Accountid, P.Serviceid, P.Payyear
                   ), 0)
    INTO Var_nach, Var_pay;

    -- изменение остатка
    Var_begin_ostatok = Var_ostat;
    Var_ostat = Var_ostat + (Var_nach - Var_pay);

    -- запись результата в таблицу Saldo
    SELECT Begin_ostatok, Nachisl, Pay, Result_ostatok
    INTO Var_predbegin_ostatok, Var_pred_nachisl,
        Var_pred_pay, Var_predresult_ostatok
    FROM Saldo
    WHERE Account = Var_account
      AND Service = Var_serv
      AND Year = Var_start_year;

    IF NOT FOUND
    THEN
        INSERT INTO Saldo
        VALUES (Var_account, Var_serv, Var_start_year,
                Var_begin_ostatok, Var_nach, Var_pay, Var_ostat);
    ELSIF (Var_predbegin_ostatok <> Var_begin_ostatok
        OR Var_pred_nachisl <> Var_nach
        OR Var_pred_pay <> Var_pay
        OR Var_predresult_ostatok <> Var_ostat)
    THEN
        UPDATE Saldo
        SET Begin_ostatok  = Var_begin_ostatok,
            Nachisl        = Var_nach,
            Pay            = Var_pay,
            Result_ostatok = Var_ostat
        WHERE Account = Var_account
          AND Service = Var_serv
          AND Year = Var_start_year;
    END IF;

    -- переход к следующему году
    Var_start_year = Var_start_year + 1;

    -- рекурсивный вызов процедуры для следующего года периода
    CALL Resultsaldo(Var_account, Var_serv, Var_start_year,
                     Var_final_year, Var_ostat, Var_result_ostat);
END $$;

/*
В данном скрипте сначала создается таблица Saldo для хранения
значений денежных остатков абонентов. В столбце Account этой
таблицы хранится номер лицевого счета абонента, в столбце
Service — код услуги, в столбце Year — год, за который
рассчитывается остаток, в столбце Begin_ostatok — значение
остатка на начало года, в столбце Nachisl — сумма, начисленная
за год, в столбце Pay — сумма, оплаченная за год, а в столбце
Result_ostatok — вычисленное значение остатка на конец года.

Процедура Resultsaldo рекурсивным методом вычисляет для
определенного абонента (Account) по указанной услуге (Serv)
значение денежного остатка как разницу между суммами значений
начислений и оплат за период, заданный начальным (Start_year)
и конечным (Final_year) годами. Значение начального остатка
(Ostat) задается при вызове процедуры, а затем в теле процедуры
его значение изменяется после извлечения запросом данных
о начислении и оплате за очередной год периода. После этого
анализируются данные таблицы Saldo. Если в таблице Saldo нет
данных о денежных остатках заданного абонента по указанной
услуге за определенный год, то выполняется вставка новой строки
в таблицу. Если такие данные есть, но хранимый в таблице
начальный остаток (Begin_ostatok), сумма начислений (Nachisl),
сумма оплат (Pay) или конечный остаток (Result_ostatok)
отличаются от вычисленных процедурой (соответственно
Begin_ostatok, Nach, Pay и Ostat), то происходит обновление
значений в таблице. Если же остатки совпадают, то модификация
данных таблицы не выполняется. После выполнения описанных
действий с данными таблицы Saldo происходит переход к следующему
году периода.

Рекурсивное выполнение процедуры осуществляется при вызове
процедурой самой себя запросом CALL. При каждом рекурсивном
вызове на вход поступают очередной год расчета (Start_year),
а также значение остатка, рассчитанное к моменту вызова (Ostat).

Выполнение процедуры продолжается до тех пор, пока год,
за который выполняется расчет (Start_year), не станет больше
года окончания заданного периода (Final_year). В таком случае
результирующее значение остатка за период (Result_ostat)
принимается равным входному начальному остатку (Ostat),
и оператор RETURN осуществляет возврат выходного параметра
и выход из процедуры.

Например, для вычисления денежного остатка абонента с номером
лицевого счета '015527' по услуге с кодом, равным 1, за период
с 2024 по 2025 г. при заданном нулевом начальном остатке можно
выполнить запрос:
*/

CALL ResultSaldo(
        '015527'::VARCHAR(6),
        1::Pkfield,
        2024::TYear,
        2025::TYear,
        0::Currency,
        NULL::Currency);

/*
Таким образом, на рисунке представлен результирующий остаток
абонента по услуге с кодом 1 на конец 2025 г. Расшифровка
полученного результата по годам периода в ходе выполнения
процедуры добавлена в таблицу Saldo. Для просмотра строк,
добавленных в таблицу Saldo, необходимо выполнить запрос:
*/

SELECT S.Account,
       S.Year,
       S.service,
       S.Begin_ostatok,
       S.Nachisl,
       S.Pay,
       S.Result_ostatok
FROM Saldo S
ORDER BY Year;

/*
Рассмотрим, в каких еще случаях может оказаться полезным
использование ХП. Выше отмечалось, что не рекомендуется
применение целевой таблицы в запросе DELETE с подзапросом.
Например, был приведен запрос DELETE, удаляющий информацию
обо всех оплатах тех абонентов, которыми было сделано более
восьми платежей. Такая задача может быть довольно просто
решена с помощью ХП. Скрипт создания процедуры будет таким:
*/

CREATE PROCEDURE Del
(
)
    LANGUAGE PLPGSQL
AS $$
DECLARE
    ---Fld VARCHAR(6);
    Cursacc CURSOR FOR
        SELECT Accountid
        FROM Paysumma
        GROUP BY Accountid
        HAVING COUNT(Payfactid) > 8;
BEGIN
    FOR A IN Cursacc
        LOOP
            DELETE
            FROM Paysumma
            WHERE Accountid = A.Accountid;
        END LOOP;
END $$;


-- 2. Для каждого счета нужно найти ТОП-3 платежа
explain analyze
SELECT a.Accountid, top.*
FROM Abonent        a
         JOIN LATERAL (
                  SELECT Paysum, Paydate
                  FROM Paysumma p
                  WHERE p.Accountid = a.Accountid
                  ORDER BY Paysum DESC
                  LIMIT 3
                  ) top ON TRUE;


explain analyze
WITH ranked AS (
               SELECT Accountid,
                      Paysum,
                      Paydate,
                      ROW_NUMBER() OVER (PARTITION BY Accountid ORDER BY Paysum DESC) AS rn
               FROM Paysumma
               )
SELECT Accountid, Paysum, Paydate
FROM ranked
WHERE rn <= 3;


/*
Все приведенные процедуры используют курсоры в том или ином виде.

В хранимых процедурах можно использовать запросы модификации
данных INSERT, UPDATE и DELETE, содержащие специальную секцию
для указания, что значения определенных столбцов в изменяемых
строках должны запоминаться в соответствующих переменных.
В PostgreSQL специальная секция представляет собой секцию
RETURNING, употребляемую в конце запросов модификации DML.

Секция RETURNING имеет формат:

RETURNING <список_столбцов> INTO <список_переменных>;

где
<список_столбцов> ::= <возвращаемый_элемент1> [[AS] псевдоним_элемента1]
    [<возвращаемый_элемент2> [[AS] псевдоним_элемента2]]...

Столбцы, указанные в <список_столбцов>, могут быть любыми
столбцами из целевой таблицы, в том числе обновляемыми.

Запросы модификации данных, использующие секцию RETURNING,
должны оперировать не более чем одной строкой набора данных.
Например, определение ХП, использующей запрос на удаление данных
с секцией RETURNING, может выглядеть так:
*/

CREATE PROCEDURE Save_Del
(
Req_id INT, OUT Raccountid VARCHAR(6), OUT Rdate DATE
)
    LANGUAGE PLPGSQL
AS
$$
BEGIN
    DELETE
    FROM Request
    WHERE Requestid = Req_id
    RETURNING Accountid, Incomingdate
        INTO Raccountid, Rdate;
END $$;

/*
ИЛИ ТАК:
*/

CREATE OR REPLACE PROCEDURE Save_Del
(
Req_id INT, OUT Raccountid VARCHAR(6), OUT Rdate DATE
)
    LANGUAGE PLPGSQL
AS
$$
BEGIN
    WITH Deleted AS (
                    DELETE FROM Request WHERE Requestid = Req_id
                        RETURNING Accountid, Incomingdate
                    )
    SELECT *
    INTO Raccountid, Rdate
    FROM Deleted;
END $$;

/*
Эта ХП удаляет информацию о ремонтной заявке с заданным номером
(Req_id). При этом номер лицевого счета абонента, подавшего
удаляемую заявку, и дата подачи этой заявки выводятся как
результат выполнения процедуры. Процедура может быть выполнена
с помощью запроса:
*/

CALL Save_Del(1::INT, NULL, NULL);

/*
В качестве заключительного примера приведем текст ХП,
реализующей добавление нового абонента с обработкой ошибок
некорректного ввода пользователем путем их перехвата по коду
SQLSTATE:
*/

CREATE OR REPLACE PROCEDURE Add_P
(
LAccounttid VARCHAR(6), LStreetid Pkfield
)
    LANGUAGE PLPGSQL
AS
$$
BEGIN
    INSERT INTO Abonent(Accountid, Streetid)
    VALUES (LAccounttid, LStreetid);
EXCEPTION
    WHEN SQLSTATE '23505' THEN
        RAISE 'Дублирование строки';
    WHEN SQLSTATE '23000' THEN
        RAISE 'Ограничение добавления строки';
END $$;

/*
При возникновении ошибки добавления строки в таблицу Abonent
производится замена системного текста ошибки пользовательским.
Например, при попытке ввода абонента с дублирующимся номером
лицевого счета:
*/

CALL Add_P('005488', 1);

/*
или улицей, отсутствующей в таблице Street:
*/

CALL Add_P('111111', 9);

/*
пользователю выдается соответственно сообщение
«Дублирование строки» или «Ограничение добавления строки».

Добавление абонента:
*/

CALL Add_P('111111', 3);

/*
происходит без ошибок.

Если модифицировать предыдущий скрипт следующим образом:
*/


CREATE TABLE Errors
(
    Excepid   INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    Username  VARCHAR(20) DEFAULT USER              NOT NULL,
    Date_time TIMESTAMP   DEFAULT CURRENT_TIMESTAMP NOT NULL,
    Proc      VARCHAR(10), -- имя источника ошибки
    Message   VARCHAR(80)  -- описание ошибки
);

CREATE PROCEDURE Excep_inser
(
Name_proc VARCHAR(10), Messages VARCHAR(80)
)
    LANGUAGE PLPGSQL
AS
$$
BEGIN
    INSERT INTO Errors(Proc, Message)
    VALUES (Name_proc, Messages);
END $$;



CREATE PROCEDURE Add_p
(
Laccounttid VARCHAR(6) DEFAULT NULL, Lstreetid Pkfield DEFAULT NULL
)
    LANGUAGE PLPGSQL
AS
$$
BEGIN
    IF Laccounttid IS NULL
    THEN
        -- Инициирование исключения
        RAISE 'Не заданы значения входных параметров';
    END IF;

    INSERT INTO Abonent(Accountid, Streetid)
    VALUES (Laccounttid, Lstreetid);

EXCEPTION
    WHEN SQLSTATE '23505' THEN
        CALL Excep_inser('Add_p', 'Дублирование строки');
    WHEN SQLSTATE '23000' THEN
        CALL Excep_inser('Add_p', 'Ограничение добавления строки');
END $$;

/*
то полная информация (имя пользователя, дата и время, имя ХП,
описание ошибки) о возникающих ошибках будет помещаться
в специальный журнал ошибок (таблица Errors) посредством вызова
ХП Excep_inser.

Приведем примеры работы ХП.
*/

CALL Add_p('444444', 3);
-- Нет ошибки. Таблица Errors пустая, в таблицу Abonent добавлена
-- строка.

CALL Add_p('444444', 3);
-- Возникает исключительная ситуация дублирования строки
-- в таблице Abonent. В таблицу Errors добавляется строка
-- с описанием ошибки. С таблицей Abonent ничего не происходит.

CALL Add_p('555555', 25);
-- Возникает исключительная ситуация нарушения ограничения
-- ссылочной целостности INSERT:RESTRICT (см. лекц. 1.2).
-- В таблицу Errors добавлена строка с описанием ошибки.
-- С таблицей Abonent ничего не происходит.

CALL Add_p();
-- Возникает исключительная ситуация отсутствия значений входных
-- параметров процедуры Add_p. Выполнение ее прерывается.


select *
from Errors;

/*
Важно отметить, что в отличие от предыдущей реализации,
только в последнем случае пользователю выдается сообщение
об ошибке.


Наличие журнала ошибок, возникающих в результате некорректных
действий пользователя или сбоев и дефектов, позволит разработчику
БД достаточно быстро локализовать и устранить конкретную ошибку!!!
*/


/*
Хранимые функции

В различных СУБД, поддерживающих процедурные языки, существует
возможность создавать с их использованием не только ХП, но также
и функции. Процедурная (хранимая) функция (ХФ) представляет собой
подпрограмму, которая принимает входные параметры, выполняет,
например числовые вычисления, результат которых возвращается
в виде значения функции. В качестве значения может
выступать единственное значение, множество значений (строка),
таблица. Кроме того, ХФ может выполнять какие-то действия
с данными и не возвращать значение.

В PostgreSQL можно разрабатывать функции на языке декларативного
программирования (SQL-функции), на языках процедурного
программирования (PL/pgSQL, PL/Tcl, PL/Perl, PL/Python),
а также на языке C.

SQL-программирование хранимых функций

Запрос на определение SQL-функции имеет следующий синтаксис:

CREATE [OR REPLACE] FUNCTION имя_функции
(
    [ <режим_параметра> ] [имя_параметра] тип_данных_параметра
    [, ...]
)
[RETURNS {тип_данных_результата | VOID]
| RETURNS TABLE {имя_столбца тип_столбца [, ...]}]
AS
$$
<тело_функции>
$$
LANGUAGE SQL;

где режим_параметра:
- IN (входной);
- OUT (выходной);
- INOUT (входной и выходной);
- VARIADIC (переменный — массив входящих параметров).

По умолчанию подразумевается IN. За единственным аргументом
VARIADIC могут быть только аргументы OUT.

Синтаксис команды CREATE FUNCTION требует, чтобы тело функции
было записано как строковая константа!!!
Обычно строковую константу заключают в знаки долларов «$$».

Тело функции содержит последовательность SQL-запросов
(INSERT, UPDATE, DELETE, MERGE и SELECT), разделенных символом «;».
В простейшем случае такие функции возвращают результат последнего
запроса в последовательности!!!

Если последний запрос вообще
не вернет строки, будет возвращен NULL.
Последней строкой в теле функции должен быть запрос SELECT,
возвращающий какие-то данные, или оператор RETURNING,
возвращающий результат с типом возврата функции.

Типом возвращаемых данных (возможно, дополненный схемой) может
быть базовый, составной или доменный тип, либо ссылка на тип
столбца таблицы. Для определения функции SQL, выполняющей
действия, но не возвращающую полезное значение, необходимо
объявить ее как возвращающую тип VOID. Кроме того, аргументы OUT
и INOUT нельзя использовать с секцией RETURNS TABLE.

Параметры в заголовке SQL-функции можно указывать в виде имен
и типов или типов, а в теле — соответственно в виде имен
или номеров (старый вариант):
- $1 — первый параметр;
- $2 — второй параметр и т. д.

Синтаксис запроса вызова SQL-функции следующий:
*/


SELECT возвращаемые_элементы
FROM имя_функции(аргументы);

/*
или
*/

SELECT имя_функции(аргументы);

/*
Например, для вычисления длины окружности заданного радиуса:
*/

CREATE FUNCTION Pir2
(
    Par FLOAT
)
    RETURNS FLOAT
AS $$
SELECT 2 * PI() * Par;
$$
    LANGUAGE SQL;

/*
Вызов функции:
*/

SELECT Pir2(2) AS "Длина окружности";

/*
или
*/

SELECT *
FROM Pir2(2) AS "Длина окружности";

/*
Также можно отказаться от имен параметров и обращаться к ним
по номерам:
*/

CREATE FUNCTION S2c2
(
INTEGER, INTEGER
)
    RETURNS FLOAT
AS $$
SELECT POWER(COS(PI() / $1), 2) + POWER(SIN(PI() / $2), 2);
$$
    LANGUAGE SQL;

/*
или в смешанной форме так:
*/

CREATE OR REPLACE FUNCTION S2c2
(
INT, P INT
)
    RETURNS FLOAT
AS $$
SELECT POWER(COS(PI() / $1), 2) + POWER(SIN(PI() / P), 2);
$$
    LANGUAGE SQL;

/*
и даже так:
*/

CREATE OR REPLACE FUNCTION S2c2
(
S INT, P INT
)
    RETURNS FLOAT
AS $$
SELECT POWER(COS(PI() / $1), 2) + POWER(SIN(PI() / P), 2);
$$
    LANGUAGE SQL;

select *
from S2c2(2, 2);

/*
Пример функции с выходным параметром:
*/

CREATE OR REPLACE FUNCTION S2c2
(
S INTEGER, P INTEGER, OUT Rez FLOAT
)
AS $$
SELECT POWER(COS(PI() / $1), 2) + POWER(SIN(PI() / $2), 2);
$$
    LANGUAGE SQL;

/*
Примеры вызовов:
*/

SELECT S2c2(4, 4) AS "SIN(x)↑2 + COS(x)↑2";

---или

SELECT *
FROM S2c2(4, 4) AS "SIN(x)↑2 + COS(x)↑2";


/*
В качестве простейшего примера приведем скрипт скалярной функции
Avgsql, вычисляющей среднее значение платежей для абонента
с заданным номером лицевого счета:

*/

CREATE OR REPLACE FUNCTION Avgsql
(
    Acc VARCHAR(6)
)
    RETURNS Currency -- тип возвращаемого значения
AS $$
SELECT AVG(Paysum) -- результат
FROM Paysumma
WHERE Accountid = Acc;
$$
    LANGUAGE SQL;



CREATE OR REPLACE FUNCTION PaymentStats
(
    Acc VARCHAR(6)
)
    RETURNS TABLE
            (
                avg_payment Currency,
                max_payment Currency
            )
AS $$
SELECT AVG(Paysum), MAX(Paysum)
FROM Paysumma
WHERE Accountid = Acc;
$$
    LANGUAGE SQL;


CREATE OR REPLACE FUNCTION PaymentStats
(
    Acc VARCHAR(6)
)
    RETURNS RECORD
AS $$
SELECT AVG(Paysum), MAX(Paysum)
FROM Paysumma
WHERE Accountid = Acc;
$$
    LANGUAGE SQL;



-- Функция возвращает ВСЕ платежи абонента
CREATE OR REPLACE FUNCTION GetPayments
(
    Acc VARCHAR(6)
)
    RETURNS SETOF Paysumma -- возвращает таблицу (много строк)
    LANGUAGE SQL
AS $$
SELECT *
FROM Paysumma
WHERE Accountid = Acc
ORDER BY Paydate DESC;
$$;

/*
Правило: если функция объявлена с RETURNS
(не RETURNS TABLE и не RETURNS SETOF), PostgreSQL ожидает,
что запрос в теле функции вернет одну строку с одной колонкой.

Результатом вызова функции в следующем запросе:
*/

SELECT Avgsql('005488') AS "Среднее";

/*
будет среднее значение плат абонента с номером лицевого счета
'005488'.

Пример вызова с параметром:
*/

SELECT Avgsql(:Par) AS "Среднее";

/*
Можно выполнять не только одиночные вызовы функции, но и
использовать их в контексте запроса, например так:
*/

SELECT Accountid, Fio, Avgsql(Accountid) AS "Среднее"
FROM Abonent;

/*
Результатом выполнения такого запроса является набор данных
с номером лицевого счета, ФИО и средним значением плат каждого
абонента.

Хранимые функции, возвращающие одно единственное значение,
могут использоваться в качестве табличного выражения.
В таком случае запрос выполняется так, будто функция возвращает
таблицу с одной строкой и одним столбцом:
*/

SELECT Accountid, Fio, "Среднее".*
FROM Abonent
         CROSS JOIN LATERAL Avgsql(Accountid) AS "Среднее";

/*
Этот запрос выдаст тот же результат, что и предыдущий.

Решим задачу добавления в таблицу Paysumma генерируемого столбца
Paydayweek с названием дня платежа выполнением следующего
скрипта:
*/


CREATE OR REPLACE FUNCTION Paydayweek_f
(
    I_date DATE
)
    RETURNS TEXT
AS $$
SELECT (CASE
            WHEN I_date IS NULL
                THEN 'Nodate'
            ELSE TO_CHAR(I_date, 'Day')
        END);
$$
    LANGUAGE SQL IMMUTABLE;

ALTER TABLE Paysumma
    ADD Paydayweek VARCHAR(15)
        GENERATED ALWAYS AS (Paydayweek_f(Paydate)) STORED;

/*
ИЛИ НА РУССКОМ:
*/

CREATE OR REPLACE FUNCTION Paydayweek_f
(
    I_date DATE
)
    RETURNS TEXT
AS $$
SELECT (CASE
            WHEN I_date IS NULL
                THEN 'Nodate'
            ELSE
                CASE EXTRACT(DOW FROM I_date)
                    WHEN 0
                        THEN 'Воскресенье'
                    WHEN 1
                        THEN 'Понедельник'
                    WHEN 2
                        THEN 'Вторник'
                    WHEN 3
                        THEN 'Среда'
                    WHEN 4
                        THEN 'Четверг'
                    WHEN 5
                        THEN 'Пятница'
                    WHEN 6
                        THEN 'Суббота'
                END
        END);
$$
    LANGUAGE SQL IMMUTABLE;

ALTER TABLE Paysumma
    ADD Paydayweek VARCHAR(15)
        GENERATED ALWAYS AS (Paydayweek_f(Paydate)) STORED;
---STORED	Результат вычисления ФИЗИЧЕСКИ хранится на диске
--GENERATED ALWAYS AS (...)	Значение колонки ВЫЧИСЛЯЕТСЯ automatically
---IMMUTABLE означает, что функция всегда возвращает один и тот же результат для одних и тех же входных данных.

select *
from Paysumma;

/*
Это достигается определением хранимой функции с категорией
изменчивости IMMUTABLE с последующим вызовом ее
в запросе ALTER TABLE. Решение данной задачи с помощью
DML-триггера.

Следующим примером может быть SQL-функция, изменяющая значения
всех платежей заданного абонента, и возвращающая с помощью
RETURNING первое изменение значение:
*/

CREATE OR REPLACE FUNCTION Op
(
Acc TEXT, Deb NUMERIC
)
    RETURNS NUMERIC
AS $$
UPDATE Paysumma
SET Paysum = Paysum - Deb
WHERE Accountid = Acc
RETURNING Paysum;
$$
    LANGUAGE SQL;

/*
Пример запроса на выполнение функции:
*/


SELECT *
FROM Op('136169', 50.00);

/*
В случае наличия параметров OUT или INOUT, секцию RETURNS можно
опустить. Если она присутствует, она должна согласовываться
с типом результата, выводимым из выходных параметров:
в качестве возвращаемого типа, указывается RECORD или
SETOF определенный тип, если выходных параметров несколько,
либо тип единственного выходного параметра.
Указание SETOF показывает, что функция возвращает множество,
а не единственный элемент. Например:
*/

CREATE FUNCTION Ab_nls
(
    Acc TEXT
)
    RETURNS SETOF Abonent
AS $$
SELECT *
FROM Abonent
WHERE Accountid = $1;
$$
    LANGUAGE SQL;

/*
Вызов:
*/

SELECT *
FROM Ab_nls('005488');

/*
Или с SETOF RECORD:
*/

CREATE OR REPLACE FUNCTION Acc_sum
(
Acc TEXT, OUT Serviceid INT, OUT Summ NUMERIC
)
    RETURNS SETOF RECORD
AS $$
SELECT Serviceid, SUM(Paysum) AS Summ
FROM Paysumma
WHERE Accountid = $1
GROUP BY Accountid, Serviceid;
$$
    LANGUAGE SQL;

/*
Вызов:
*/

SELECT *
FROM Acc_sum('005488');


/*
Кроме того, можно объявить функцию с указанием таблицы
RETURNS TABLE (столбцы). В этом случае будут возвращены все
строки таблицы:
*/

CREATE OR REPLACE FUNCTION Acc_ph
(
)
    RETURNS TABLE
            (
                Acc TEXT,
                Ph  TEXT
            )
AS $$
SELECT Accountid, Phone
FROM Abonent
WHERE Phone IS NOT NULL;
$$
    LANGUAGE SQL;

/*
Вызов:
*/

SELECT *
FROM Acc_ph();

/*
или
*/

CREATE OR REPLACE FUNCTION Acc_pay
(
    Acc TEXT
)
    RETURNS TABLE
            (
                Accountid TEXT,
                Fio       TEXT,
                Servicenm TEXT,
                Paydate   DATE,
                Paysum    NUMERIC
            )
AS $$
SELECT P.Accountid,
       A.Fio,
       S.Servicenm,
       P.Paydate,
       P.Paysum
FROM Paysumma                P
         INNER JOIN Abonent  A USING (Accountid)
         INNER JOIN Services S USING (Serviceid)
WHERE P.Accountid = Acc;
$$
    LANGUAGE SQL;

/*
Пример вызова:
*/

SELECT *
FROM Acc_pay('136160');


/*
Иногда полезно присваивать параметрам значение по умолчанию.
Оно указывается после имени параметра и его типа данных
в следующем виде:

{DEFAULT | =} выражение_по_умолчанию

В этом случае можно не передавать соответствующий аргумент
при вызове функции:
*/

CREATE OR REPLACE FUNCTION Acc_df
(
    Acc TEXT DEFAULT '005488'
)
    RETURNS TABLE
            (
                Acc TEXT,
                Ph  TEXT
            )
AS $$
SELECT Accountid, Phone
FROM Abonent
WHERE Accountid = Acc;
$$
    LANGUAGE SQL;

/*
Примеры вызова:
*/

SELECT *
FROM Acc_df();
SELECT *
FROM Acc_df('126112');

/*
Например:
*/

CREATE OR REPLACE FUNCTION Listabonent
(
    IN Pay Currency
)
    RETURNS TABLE
            (
                Laccountid VARCHAR(6),
                Lfio       VARCHAR(30),
                Ldate      DATE,
                Lsum       Currency,
                Lmonth     Tmonth,
                Lpay       Tyear
            )
AS $$
SELECT A.Accountid,
       A.Fio,
       P.Paydate,
       P.Paysum,
       P.Paymonth,
       P.Payyear
FROM Abonent                 A
         INNER JOIN Paysumma P USING (Accountid)
WHERE P.Paysum > Pay;
$$
    LANGUAGE SQL;

/*
Пример использования:
*/

SELECT *
FROM Listabonent(1500);


/*
Здесь совпадают количество и порядок следования выходных
параметров и столбцов в запросе. При этом типы данных также
у них совпадают. Так как в теле функции не указан общий тип
возвращаемых данных функций (т. е. не указана команда RETURNS),
функция будет возвращать только первую строку из результирующего
набора данных. Именно поэтому в этом примере вернется только
одна строка, хотя запрос возвращает не одну, а 15 строк.

Приведем пример ХФ (SQL), которая выполняет не только
запрос-выборку всех данных всех абонентов с расшифровкой
наименования улицы, но и запрос-действие добавления новой строки
в таблицу Abonent:
*/

CREATE OR REPLACE FUNCTION Ins_sel
(
Acc VARCHAR(6), Str Pkfield, Hn SMALLINT, Fn SMALLINT, Fi VARCHAR(20), Ph VARCHAR(15)
)
    RETURNS TABLE
            (
                Accountid VARCHAR(6),
                Streetid  Pkfield,
                Houseno   SMALLINT,
                Flatno    SMALLINT,
                Fio       VARCHAR(20),
                Phone     VARCHAR(15)
            )
AS $$
INSERT INTO Abonent
VALUES (Acc, Str, Hn, Fn, Fi, Ph);
SELECT *
FROM Abonent;
-- DELETE FROM Abonent WHERE Accountid = Acc;
$$
    LANGUAGE SQL;

/*
Используем созданную функцию как обычную таблицу с соединением
с другой таблицей:
*/

SELECT Accountid, Streetnm, Houseno, Flatno, Fio, Phone
FROM Ins_Sel(
             '111111'::VARCHAR(6),
             1::Pkfield,
             2::SMALLINT,
             3::SMALLINT,
             '720336'::VARCHAR(15)
     )               I
         JOIN Street S ON I.Streetid = S.Streetid;
-- явное условие

/*
или с вводимыми значениями параметров:
*/

SELECT Accountid, Streetnm, Houseno, Flatno, Fio, Phone
FROM Ins_Sel(
             :Nls::VARCHAR(6),
             :St::Pkfield,
             :D::smallint,
             :Kv::SMALLINT,
             :Fio::VARCHAR(20),
             :Ph::VARCHAR(15)
     )
         NATURAL JOIN Street;

/*
Самым популярным, удобным, понятным и самым правильным способом
возвращения табличных данных в PostgreSQL является способ
с использованием конструкции RETURNS TABLE, при которой
объявляется структура возвращаемых табличных данных, т. е.
*/

CREATE OR REPLACE FUNCTION Listabonent
(
    Pay Currency
)
    RETURNS TABLE
            (
                Laccountid VARCHAR(6),
                Lfio       VARCHAR(30),
                Ldate      DATE,
                Lsum       Currency,
                Lmonth     Tmonth,
                Lpay       TYear
            )
AS $$
SELECT Accountid, Fio, Paydate, Paysum, Paymonth, Payyear
FROM Abonent
         NATURAL JOIN Paysumma
WHERE Paysum > Pay;
$$
    LANGUAGE SQL;

/*
Запрос к ХФ Listabonent:
*/

SELECT *
FROM Listabonent(1500);

/*
Функция ListAbonent возвращает строку, состоящую из номера
лицевого счета абонента (Laccountid), ФИО абонента (Lfio),
даты оплаты (Ldate) и значения оплаты (Lsumn), а также месяца
(Lmonth) и года (Lpay), за которые производится оплата,
со значением, большим 1500.

Создадим в качестве примера SQL-функцию для работы с составным
типом:
*/

-- Создаем тип
CREATE TYPE Date_month_year AS
(
    P_date  DATE,
    P_month INT,
    P_year  INT
);

CREATE OR REPLACE FUNCTION M_y
(
    A Date_month_year
)
    RETURNS RECORD
AS $$
SELECT EXTRACT(MONTH FROM A.P_date),
       ROW (A.P_date, A.P_month, A.P_year)::Date_month_year;
$$
    LANGUAGE SQL;

/*
Выполнить эту ХФ можно следующим запросом (рис. 9.10):
*/

SELECT Payfactid, Accountid, M_y(D_m_y)
FROM Paysumma_1;

/*
Результат вызова ХФ, возвращающей RECORD значения

В теме 4 при обсуждении независимых вложенных запросов был
рассмотрен запрос, вычисляющий различные метрики платежной
активности абонентов. Поскольку все эти метрики имеют схожую
функциональность, можно создать единую "обертку" в виде
функции:
*/

CREATE OR REPLACE FUNCTION Getaverage_abonent_by
(
    Groupby TEXT
)
    RETURNS DECIMAL
AS $$
WITH Pdates AS (
               SELECT GENERATE_SERIES(MIN(P.Paydate), MAX(P.Paydate), '1 DAY') AS Dates
               FROM Paysumma P
               ),
     Grouped AS (
               SELECT TO_CHAR(D.Dates, Groupby),
                      COUNT(DISTINCT Accountid) AS Acc
               FROM Paysumma              p
                        RIGHT JOIN Pdates D ON D.Dates = P.Paydate
               GROUP BY TO_CHAR(D.Dates, Groupby)
               )
SELECT ROUND(AVG(Acc), 2)
FROM Grouped;
$$
    LANGUAGE SQL;

/*
После чего эту функцию можно использовать для расчета любой
метрики:
*/

SELECT GetAverage_abonent_by('YYYY-MM-DD') AS Daa,
       GetAverage_abonent_by('YYYY-WW')    AS Waa,
       GetAverage_Abonent_by('YYYY-MM')    AS Maa,
       GetAverage_abonent_by('YYYY')       AS Yaa;



WITH Pdates AS (
               SELECT GENERATE_SERIES(MIN(P.Paydate), MAX(P.Paydate), '1 DAY') AS Dates
               FROM Paysumma P
               ),
     Grouped AS (
               SELECT TO_CHAR(D.Dates, 'YYYY-MM-DD'),
                      COUNT(DISTINCT Accountid) AS Acc
               FROM Paysumma              p
                        RIGHT JOIN Pdates D ON D.Dates = P.Paydate
               GROUP BY TO_CHAR(D.Dates, 'YYYY-MM-DD')
               )
SELECT ROUND(AVG(Acc), 2)
FROM Grouped;


/*
Программирование хранимых функций на языке PL/pgSQL

В теле функции на PL/pgSQL кроме запросов SQL могут применяться
конструкции языка, представляющего собой процедурное расширение
SQL. Это могут быть операторы присваивания, условные операторы,
циклы, обработка ошибок. Основными
составными частями определения функции являются:
-имя,
-параметры,
-тип возвращаемого значения,
-тело,
-секция обработки ошибок.

Формат тела хранимой функции на языке PL/pgSQL, дополненный
разделами объявления и обработки ошибок, следующий:

DECLARE
    объявления
BEGIN
    <тело_функции>
[EXCEPTION
    <блок_исключений>]
END;
$$
LANGUAGE PLPGSQL;

В разделе EXCEPTION обрабатываются ошибки:

WHEN условие THEN
    RAISE EXCEPTION 'Сообщение об ошибке';

где условие — наименование ошибки.

Функция RAISE уровня EXCEPTION генерирует исключение и выдает
сообщение об ошибке.

Локальные переменные и курсоры, используемые в теле
PL/pgSQL-функции, объявляются в блоке DECLARE:

имя_переменной1 тип_переменной1;
[имя_переменной2 тип_переменной2; ...]

Результат возвращается оператором
RETURN,
RETURN NEXT
или RETURN QUERY.

В теле функции PL/pgSQL обязательно должен быть
хотя бы один оператор RETURN, кроме случаев, когда тип результата
VOID или функция имеет выходные параметры.
Оператор RETURN прекращает выполнение и возвращает значение выражения:

RETURN <выражение>

Для функций на PL/pgSQL, возвращающих SETOF определенный тип,
отдельные элементы возвращаемого значения формируются оператором:

RETURN NEXT <выражение>

или

RETURN QUERY <запрос>

а финальный оператор RETURN без аргументов завершает выполнение
функции. RETURN NEXT используется как со скалярными, так
и с составными типами данных.

Для составного типа результат функции возвращается в виде таблицы.
RETURN QUERY добавляет результат выполнения запроса к результату
функции.


Операторы RETURN NEXT и RETURN QUERY можно свободно смешивать в теле
функции, в этом случае их результаты будут объединены.
Эти операторы не выполняют возврата из функции, а только
добавляют строки в результирующее множество. Затем выполнение
продолжается со следующего оператора в функции. Успешное
выполнение RETURN NEXT и RETURN QUERY формирует множество строк
результата. Для выхода из функции используется RETURN, обязательно
без аргументов (или можно просто дождаться окончания выполнения
функции).
RETURN QUERY имеет и другой формат:

RETURN QUERY EXECUTE строка-команды [USING выражение [, ...]];

предназначенный для динамического выполнения запроса. В текст
запроса можно добавить параметры, используя USING, так же,
как и с командой EXECUTE.

Для функции с выходными параметрами достаточно использовать
RETURN NEXT без аргументов. При каждом исполнении RETURN NEXT
текущие значения выходных параметров сохраняются для последующего
возврата в качестве строки результата.

В качестве простейшего примера приведем скрипт скалярной функции
Acc_avg_pay, вычисляющей среднее значение платежей для абонента
с заданным номером лицевого счета.
*/

CREATE OR REPLACE FUNCTION Acc_avg_pay
(
    Acc VARCHAR(6)
)
    RETURNS Currency -- тип возвращаемого значения
AS $$
BEGIN
    RETURN (
           SELECT AVG(Paysum) -- результат
           FROM Paysumma
           WHERE Accountid = Acc
           );
END;
$$
    LANGUAGE PLPGSQL;

/*
или
*/

CREATE OR REPLACE FUNCTION Acc_avg_pay
(
    Acc VARCHAR(6)
)
    RETURNS Currency -- тип возвращаемого значения
    LANGUAGE PLPGSQL
AS $$
DECLARE
    Var_acc_avg_pay Currency;
BEGIN
    SELECT AVG(Paysum)
    INTO Var_acc_avg_pay -- результат
    FROM Paysumma
    WHERE Accountid = Acc;
    RETURN Var_acc_avg_pay;
END;
$$;

/*
или
*/

CREATE OR REPLACE FUNCTION Acc_avg_pay
(
    Acc VARCHAR(6)
)
    RETURNS Currency
    LANGUAGE PLPGSQL
AS $$
DECLARE
    Var_acc_avg_pay Currency;
BEGIN
    SELECT AVG(Paysum)
    FROM Paysumma
    WHERE Accountid = Acc
    INTO Var_acc_avg_pay; -- результат
    RETURN Var_acc_avg_pay;
END;
$$;

/*
Хранимые функции, возвращающие единственное значение, вызываются
так же, как и обычные внутренние функции. Количество и типы
аргументов должны соответствовать определению функции.
Результатом вызова функции в следующем запросе:
*/

SELECT Acc_avg_pay('005488') AS "Среднее";

/*
будет среднее значение плат абонента с номером лицевого счета
'005488', или с параметром так:
*/

SELECT Acc_avg_pay(:Par) AS "Среднее";

/*
Можно выполнять не только одиночные вызовы функции, но и
использовать их в контексте запроса, например так:
*/

SELECT Accountid, Fio, Acc_avg_pay(Accountid) AS "Среднее"
FROM Abonent;

/*
Хранимые функции, возвращающие одно единственное значение, могут
также использоваться в качестве табличного выражения. В таком
случае запрос выполняется так, будто функция возвращает таблицу
с одной строкой и одним столбцом:



Пошагово:
Берется первая строка из Abonent (например, Accountid = '005488')
Вызывается функция Acc_avg_pay('005488') — она возвращает одно число (средний платеж)
Это число "заворачивается" в таблицу с одной строкой и одной колонкой
CROSS JOIN соединяет строку абонента с результатом функции
"Среднее".* разворачивает эту строку (фактически просто число)
Процесс повторяется для каждого абонента
*/

SELECT Accountid, Fio, "Среднее".*
FROM Abonent
         CROSS JOIN LATERAL Acc_avg_pay(Accountid) AS "Среднее";

/*
Выше рассмотрены способы создания табличных функций
с использованием языка SQL. Однако иногда возникает необходимость
в таких функциях задействовать некую логику (ветвления, циклы,
переменные), иными словами, все возможности языка PL/pgSQL.

Рассмотрим возвращение табличных данных через выходные параметры.
Функции, возвращающие табличные данные на PL/pgSQL, создаются
немного по-другому, поэтому эти способы мы рассмотрим отдельно.
Сразу необходимо отметить, что способы объявления структуры
возвращаемых табличных данных будут точно такими же, как те,
которые мы уже встречали в случае с функциями на SQL, например,
использование OUT-параметров с RETURNS SETOF RECORD или
RETURNS TABLE, поскольку это не относится к языку, на котором
будет написана табличная функция. С глобальной точки зрения
способов возврата табличных данных на PL/pgSQL всего два —
это RETURN QUERY и RETURN NEXT, и именно RETURN QUERY является
наиболее популярным и предпочтительным вариантом возвращения
табличных данных.

Суть способа в том, что объявляется структура возвращаемых
табличных данных — любым способом, будь то указание названия
таблицы или определение структуры непосредственно в функции,
а в теле функции используется инструкция RETURN QUERY, после
которой располагается запрос, формирующий возвращаемые табличные
данные. При этом, конечно же, в определении функции указывается,
что функция написана с использованием языка PL/pgSQL, а в теле
функции можно использовать любые конструкции языка PL/pgSQL.

Для выборки данных в виде таблицы применяется тип TABLE.
Рассмотрим следующий DDL-сценарий, который создает функцию
без входных параметров с именем List_abonent, возвращающую
таблицу:
*/

CREATE OR REPLACE FUNCTION List_abonent
(
)
    RETURNS TABLE
            (
                Laccountid VARCHAR(6),
                Lfio       VARCHAR(30),
                Ldate      DATE,
                Lsum       Currency,
                Lmonth     TMonth,
                Lpay       TYear
            )
AS $$
BEGIN
    RETURN QUERY
        SELECT A.Accountid,
               A.Fio,
               P.Paydate,
               P.Paysum,
               P.Paymonth,
               P.Payyear
        FROM Abonent                 A
                 INNER JOIN Paysumma P USING (Accountid)
        WHERE P.Paysum > 1500;
END
$$
    LANGUAGE PLPGSQL;

/*
Пример вызова :
*/

SELECT *
FROM List_abonent();

/*
Следующий запрос демонстрирует возможность вызова ХФ в секции FROM
запроса, на котором основано определяемое представление:
*/

CREATE VIEW P_listab
AS
SELECT *
FROM List_abonent();

/*
Результат выполнения запроса
*/

SELECT *
FROM P_listab;

/*
Вторым способом возвращения табличных данных на PL/pgSQL является
способ с использованием инструкции RETURN NEXT. Суть данного
способа в том, что данные в результирующую таблицу добавляются
построчно с помощью инструкции RETURN NEXT. Данный способ
предпочтителен в тех случаях, когда каждая строка результирующего
набора данных подвергается какой-то обработке!!!
Например, все те случаи, когда данные накапливаются с помощью цикла,
т. е. что-то перебирается и что-то куда-то складывается:
*/

CREATE OR REPLACE FUNCTION List_abonent
(
    Pay Currency
)
    RETURNS TABLE
            (
                Laccountid VARCHAR(6),
                Lfio       VARCHAR(30),
                Ldate      DATE,
                Lsum       Currency,
                Lmonth     TMonth,
                Lpay       TYear
            )
AS $$
DECLARE
    Var_r RECORD;
BEGIN
    FOR Var_r IN (
                 SELECT A.Accountid,
                        A.Fio,
                        P.Paydate,
                        P.Paysum,
                        P.Paymonth,
                        P.Payyear
                 FROM Abonent                 A
                          INNER JOIN Paysumma P USING (Accountid)
                 WHERE P.Paysum > Pay
                 )
        LOOP
            Laccountid := Var_r.Accountid;
            Lfio := Var_r.Fio;
            Ldate := Var_r.Paydate;
            Lsum := Var_r.Paysum;
            Lmonth := Var_r.Paymonth;
            Lpay := Var_r.Payyear;
            RETURN NEXT;
        END LOOP;
END
$$
    LANGUAGE PLPGSQL;

/*
Оператор RETURN NEXT добавляет строку в возвращаемую таблицу,
значения столбцов строки извлекаются из текущих значений выходных
переменных.

В функции List_abonent производятся следующие действия:

1) запрос SELECT формирует неявное соединение таблиц Abonent,
   Paysumma и возвращает НД;
2) неявный курсор FOR Var_r IN... LOOP для каждой строки таблицы
   результатов, сформированной запросом SELECT, выполняет блок
   операторов, который следует за секцией LOOP;
3) в данном случае выполняется один оператор RETURN NEXT.

Чтобы выбрать значения, возвращаемые функцией List_abonent,
необходимо выполнить запрос;
*/

SELECT *
FROM List_abonent(2280);

/*
Результат, возвращаемый данной функцией, может быть легко получен
с помощью запроса SELECT без оформления ХФ. Однако использование
даже такой несложной функции вместо обычного запроса SELECT дает
ряд преимуществ (простота доступа, сокращение объема кода
клиентского приложения и другие, описанные ранее), не говоря уже
о функциях, реализующих более сложные алгоритмы.
*/


/*
В PostgreSQL при возврате множества значений используется тип
SETOF [RECORD], например так:
*/

CREATE OR REPLACE FUNCTION List_abonent
(
    Str TEXT
)
    RETURNS SETOF Abonent
AS $$
BEGIN
    RETURN QUERY
        SELECT *
        FROM Abonent
        WHERE Streetid = (
                         SELECT Streetid
                         FROM Street
                         WHERE Streetnm = Str
                         );
END;
$$
    LANGUAGE PLPGSQL;

/*
Выведем все данные абонентов, проживающих на заданной улице:
*/

SELECT *
FROM List_abonent('МОСКОВСКОЕ ШОССЕ');


/*
В качестве следующего примера преобразуем ХП Factorial,
вычисляющую факториал числа, в функцию F_factorial.
Запрос на определение такой функции более компактный, чем
определение аналогичной ХП:
*/

drop function F_factorial;
CREATE OR REPLACE FUNCTION F_factorial
(
    Num INT
)
    RETURNS NUMERIC
    LANGUAGE PLPGSQL
AS $$
DECLARE
    result NUMERIC;
BEGIN
    IF (Num < 0)
    THEN
        RETURN NULL;
    END IF;
    IF (Num = 0 OR Num = 1)
    THEN
        RETURN 1;
    ELSE
        CALL Factorial(Num, result); -- ← вызов процедуры через CALL
        RETURN result; -- ← возвращаем полученное значение
    END IF;
END;
$$;

/*
Созданную функцию F_factorial можно вызвать соответственно так:
*/

SELECT F_factorial(3);

/*
или с параметром
*/

SELECT F_factorial(:N);

/*
Результат выполнения запроса будет аналогичен представленному

Важно отметить, что в отличие от ХП, скалярная функция может
быть указана в любом месте выражения, в том числе в вычисляемых
столбцах и определениях ограничений CHECK, например:
*/

SELECT *
FROM Paysumma
LIMIT F_factorial(3);

/*
Примером определения функции с выходным параметром может
следующий скрипт:
*/

CREATE OR REPLACE FUNCTION Err_exception
(
    OUT Rez INTEGER
)
    LANGUAGE PLPGSQL
AS $$
DECLARE
    Code    TEXT;
    Msg     TEXT;
    Context TEXT;
BEGIN
    Rez = COUNT(*) FROM Abonent;
END;
$$;

/*
Примеры вызова:
*/

SELECT *
FROM Err_exception();
SELECT Err_exception();


CREATE OR REPLACE FUNCTION Err_exception
(
    OUT Rez INT
)
    LANGUAGE PLPGSQL
AS $$
DECLARE
    Code    TEXT;
    Msg     TEXT;
    Context TEXT;
BEGIN
    SELECT COUNT(*) FROM Abonent INTO Rez;
EXCEPTION
    WHEN OTHERS THEN
        Rez := 0;
        GET STACKED DIAGNOSTICS
            Code := RETURNED_SQLSTATE,
            Msg := MESSAGE_TEXT,
            Context := PG_CONTEXT;
        RAISE NOTICE 'Код ошибки: %. Текст сообщения об ошибке:
%. Контекст ошибки: %', Code, Msg, Context;
END;
$$;

/*
В приведенном скрипте создается ХФ с выходным параметром,
в которой производится расчет количества строк в таблице.
С помощью оператора GET STACKED DIAGNOSTICS осуществляется
диагностика возникающих ошибок. В последнем случае, так как
таблица Abonen не определена, выполнение функции в следующем
DO-блоке:
*/

DO $$
    DECLARE
        Rez INTEGER;
    BEGIN
        SELECT E.Rez INTO Rez FROM Err_exception() AS E;
        RAISE NOTICE 'Результат: %', Rez;
    END; $$;

/*
дает результат, равный 0, и полную информацию о возникшей ошибке:

Код ошибки: 42P01. Текст сообщения об ошибке: отношение "abonen"
не существует. Контекст ошибки: функция PL/pgSQL err_exception(),
строка 12, оператор GET STACKED DIAGNOSTICS SQL-оператор:
"SELECT E.Rez FROM Err_exception() AS E"
функция PL/pgSQL inline_code_block, строка 5, оператор SQL-оператор
Результат: 0

Рассмотрим пример DDL-сценария создания функции List_abonent
с входными параметрами M и G и перехватом некоторых ошибок.
Входные параметры используются для отбора строк, содержащих
информацию о платах больше 1500, произведенных абонентом
за заданный месяц (M) указанного года (G):
*/


CREATE OR REPLACE FUNCTION List_abonent
(
M TMonth, G Tyear
)
    RETURNS TABLE
            (
                L_accountid VARCHAR(6),
                L_fio       VARCHAR(30),
                L_date      DATE,
                L_sum       Currency,
                L_month     Tmonth,
                L_pay       Tyear
            )
    LANGUAGE PLPGSQL
AS $$
BEGIN
    -- Инициирование исключения
    -- если месяц не задан, выводится соответствующее сообщение
    IF M IS NULL
    THEN
        RAISE EXCEPTION 'Не задан месяц';
    END IF;

    -- Инициирование исключения
    -- если год не задан, то выводится предупреждение
    IF G IS NULL
    THEN
        RAISE EXCEPTION 'Не задан год';
    END IF;

    RETURN QUERY
        SELECT A.Accountid,
               A.Fio,
               P.Paydate,
               P.Paysum,
               P.Paymonth,
               P.Payyear
        FROM Abonent  A,
             Paysumma P
        WHERE A.Accountid = P.Accountid
          AND P.Paysum > 1500
          AND P.Paymonth = M
          AND P.Payyear = G;
END $$;

/*
Проверочные запросы могут быть следующими:
*/

SELECT *
FROM List_abonent(NULL::Tmonth, NULL::Tyear);
SELECT *
FROM List_abonent(12::Tmonth, NULL::Tyear);
SELECT *
FROM List_abonent(13::Tmonth, 2022::Tyear);

/*
Если функция определена с указанием входных параметров, то их
задание при выводе функции в запросе SELECT является обязательным.
Например, чтобы вывести все сведения о значениях плат, больших
1500, за март 2025 г., необходимо выполнить запрос
*/

SELECT *
FROM List_abonent(2::Tmonth, 2025::Tyear);

/*
Результат выполнения запроса к модифицированной
функции List_abonent

Набор данных, возвращаемый ХФ, можно использовать в соединении
с базовой таблицей, например:
*/

SELECT *
FROM Nachislsumma                                        N
         INNER JOIN List_abonent(3::Tmonth, 2025::Tyear) s
         ON N.Accountid = S.L_accountid
WHERE N.Nachislyear = S.L_pay
  AND N.Nachislmonth = S.L_month;

/*
Запрос вызова ХФ может быть параметризированным, например таким:
*/

SELECT *
FROM List_abonent(:Par_1::Tmonth, :Par_2::Tyear);

/*
Рассмотрим пример функции, в которой используется обновляемый
явный курсор для позиционированного удаления и обновления строк
таблицы.
Создадим функцию Exec_Req, которая путем
позиционированной модификации строк таблицы Request удаляет
все невыполненные ремонтные заявки, а все непогашенные ремонтные
заявки преобразует в погашенные.
При этом в таблицу Executor заносится дополнительная информация
по исполнителям, для которых последним произведено удаление
или погашение заявок. Соответствующий DDL-скрипт выглядит так:
*/

ALTER TABLE Executor
    ADD Info VARCHAR(40);


DROP FUNCTION IF EXISTS Exec_Req(
);

CREATE OR REPLACE FUNCTION Exec_Req
(
)
    RETURNS TABLE
            (
                Ecode Pkfield,
                Ename VARCHAR(20),
                Einfo VARCHAR(40)
            )
    LANGUAGE PLPGSQL
AS $$
DECLARE
    Edate DATE;
    Exec  BOOLEAN;
    Req CURSOR FOR
        SELECT Executorid, Executiondate, Executed
        FROM Request;
BEGIN
    OPEN Req;
    LOOP
        FETCH Req INTO Ecode, Edate, Exec;
        IF NOT FOUND
        THEN
            EXIT;
        END IF;
        IF Edate IS NULL
        THEN
            DELETE FROM Request WHERE CURRENT OF Req;
            UPDATE Executor
            SET Info = 'DEL_NotExec'
            WHERE Executorid = Ecode;
        ELSIF NOT Exec
        THEN
            UPDATE Request SET Executed = TRUE WHERE CURRENT OF Req;
            UPDATE Executor
            SET Info = 'UPD_Executed'
            WHERE Executorid = Ecode;
        END IF;
    END LOOP;
    CLOSE Req;
    RETURN QUERY
        SELECT Executorid, Fio, Info
        FROM Executor
        ORDER BY Executorid;
END;
$$;

/*
В начале скрипта с помощью запроса ALTER TABLE в таблицу Executor
добавляется столбец Info. После этого создается функция Exec_Req,
в которой сначала явным курсором Req выполняется выборка строк
из таблицы Request, а затем проверяется ряд условий.

Если очередная ремонтная заявка не выполнена (Edate IS NULL),
то происходит ее позиционированное удаление, а в таблице Executor
столбец Info получает значение 'DEL_NotExec' (признак того,
что для данного исполнителя удалены невыполненные заявки).

Если выполненная ремонтная заявка не погашена (NOT Exec),
то происходит позиционированное обновление (Executed = TRUE)
той строки, на которой установлен курсор Req.


Затем в таблице Executor происходит обновление столбца
Info. Столбец Info получает значение 'UPD_Executed' (признак того,
что для данного исполнителя непогашенные ранее заявки погашены).

Если очередная ремонтная заявка и выполнена, и погашена,
то позиционированная модификация строки в таблице Request
не выполняется и для исполнителя соответствующей заявки в таблице
Executor столбец Info не обновляется (содержит NULL).

Затем курсор Reg закрывается, и с помощью RETURN QUERY
возвращается содержимое таблицы Executor.

Функция Exec_reg выполняется с помощью запроса:
*/

SELECT *
FROM Exec_Req();

SELECT current_database();

SELECT proname
FROM pg_proc
WHERE proname ILIKE '%exec%';

/*
Результат работы функции Exec_Reg

Предыдущие примеры ХФ были просто на манипулирование данными
таблиц. С целью получения новых сведений рассмотрим пример
решения задачи получения информации о начислениях, платежах
и денежных остатках у заданного абонента по заданной услуге
на начало и на конец каждого месяца определенного периода.

Под значением оборота начислений за заданный период Nachisl
будем понимать сумму всех значений начислений (Nachislsum)
за рассматриваемый период:

Nachisl = SUM(Nachislsum)

а под значением оборота платежей за заданный период Pay —
сумму всех значений платежей (Paysum) за рассматриваемый период:

Pay = SUM(Paysum)

Под значением остатка на конец заданного периода Result_ostatok
будем понимать остаток на начало этого периода (Begin_ostatok)
плюс оборот начислений за заданный период (Oborot_nachisl)
и минус оборот платежей за этот же период (Oborot_pay), т.е.:

Result_ostatok = Begin_ostatok + Oborot_nachisl - Oborot_pay

Непременным условием является равенство сальдо на начало
определенного периода и сальдо на конец предшествующего периода.
В качестве отчетного периода может использоваться как один,
так и несколько месяцев.

Представим решение данной задачи в трех вариантах.
Первый вариант DDL-скрипта в виде единого модуля без вложений
может быть следующим:
*/

CREATE FUNCTION oborot_saldo_vedomost
(
Argaccount VARCHAR(6), Argserviceid Pkfield, Argmonth Tmonth, Argnyear Tyear, Argfmonth Tmonth, Argfyear Tyear
)
    RETURNS TABLE
            (
                Nachislmonth   Tmonth,
                Nachislyear    Tyear,
                Begin_ostatok  Currency,
                Nachisl        Currency,
                Pay            Currency,
                Result_ostatok Currency
            )
    LANGUAGE PLPGSQL
AS $$
BEGIN
    SELECT
        -- вычисление остатка на начало 1-го месяца периода

        -- сумма начислений на начало 1-го месяца периода
        (COALESCE((
                  SELECT SUM(N.Nachislsum) SumNach
                  FROM Nachislsumma N
                  WHERE N.Accountid = Argaccount
                    AND N.Serviceid = Argserviceid
                    AND (N.Nachislyear < Argnyear
                      OR (N.Nachislyear = Argnyear
                          AND N.Nachislmonth < Argmonth))
                  ), 0)
            -
            -- сумма оплат на начало 1-го месяца периода
         COALESCE((
                  SELECT SUM(P.Paysum) SumPay
                  FROM Paysumma P
                  WHERE P.Accountid = Argaccount
                    AND P.Serviceid = Argserviceid
                    AND (P.Payyear < Argnyear
                      OR (P.Payyear = Argnyear
                          AND P.Paymonth < Argmonth))
                  ), 0))
    INTO Begin_ostatok;

    LOOP
        SELECT
            -- начисление за месяц
            COALESCE((
                     SELECT SUM(Na.Nachislsum)
                     FROM Nachislsumma Na
                     WHERE Na.Accountid = Argaccount
                       AND Na.Serviceid = Argserviceid
                       AND Na.Nachislyear = Argnyear
                       AND Na.Nachislmonth = Argmonth
                     ), 0),
            -- оплата за месяц
            COALESCE((
                     SELECT SUM(Pa.Paysum)
                     FROM Paysumma Pa
                     WHERE Pa.Accountid = Argaccount
                       AND Pa.Serviceid = Argserviceid
                       AND Pa.Payyear = Argnyear
                       AND Pa.Paymonth = Argmonth
                     ), 0)
        INTO Nachisl, Pay;

        -- вычисление остатка на конец месяца
        Result_ostatok = Begin_ostatok + (Nachisl - Pay);
        Nachislmonth = Argmonth;
        Nachislyear = Argnyear;
        RETURN NEXT;
        Begin_ostatok = Result_ostatok;

        IF Argmonth = Argfmonth AND Argnyear = Argfyear
        THEN
            RETURN;
        END IF;

        IF Argmonth = 12
        THEN
            Argnyear = Argnyear + 1;
            Argmonth = 1;
        ELSE
            Argmonth = Argmonth + 1;
        END IF;
    END LOOP;
END;
$$;

/*
Функция Oborot_saldo_vedomost для определенного абонента
(Argaccount) по указанной услуге (Argserviceid) по каждому месяцу,
попадающему в заданный период (от месяца Argmonth в Argnyear году
до месяца Argfmonth в Argfyear году), вычисляет и выводит:

1) значение денежного остатка на начало первого месяца периода
   (Begin_ostatok);
2) сумму значений начислений за каждый месяц периода (Nachisl);
3) сумму значений плат за каждый месяц периода (Pay);
4) значение денежного остатка на конец каждого месяца периода
   (Result_ostatok).

При каждом проходе цикла запрос возвращает одну строку
с информацией за очередной месяц. Информация выводится по каждому
месяцу анализируемого периода, а не только по тем месяцам,
за которые есть начисление или оплата в таблицах соответственно
Nachislsumma или Paysumma. В цикле также происходит переход
к следующему месяцу. Работа функции заканчивается после того,
как будет выведена информация за последний месяц заданного
периода (месяц Argfmonth, год Argfyear).

Например, чтобы вывести информацию о начислениях, оплатах
и об остатках у абонента с номером лицевого счета '015527'
по услуге с кодом 1 за период с января 2024 г. по май 2025 г.
включительно, необходимо выполнить запрос:
*/

SELECT *
FROM oborot_saldo_vedomost(
        '015527', 1::PkField,
        1::TMonth, 2024::TYear,
        5::TMonth, 2025::TYear
     );


/*
Использование параметризированного запроса позволит обеспечить
более высокую гибкость при задании кода услуги:
*/

SELECT *
FROM Oborot_saldo_vedomost('015527', :Par::Pkfield,
                           1::Tmonth, 2024::Tyear,
                           5::Tmonth, 2025::Tyear);

/*
Во втором варианте решения представим вышеприведенную функцию
в виде трех функций, чтобы показать возможность вызова одной
функции из другой.
Приведем скрипты функций для последовательного решения следующих
задач:

1) расчет и вывод значения остатка на начало заданного периода
   (Saldo_n);
2) расчет и вывод значений оборотов начислений и плат в разрезе
   месяцев заданного периода (Oborot_vedomost);
3) расчет и вывод значений остатков на начало и конец каждого
   месяца заданного периода, а также значений оборотов начислений
   и плат за каждый месяц заданного периода (Oborot_Saldo_vedomost).

DDL-скрипт функции Saldo_n для расчета и вывода значения остатка
на начало первого месяца заданного периода для заданного абонента
по заданной услуге:
*/

CREATE OR REPLACE FUNCTION Saldo_n
(
Argaccount VARCHAR(6), Argserviceid Pkfield, Argmonth Tmonth, Argnyear Tyear
)
    RETURNS TABLE
            (
                Nachislmonth  Tmonth,
                Nachislyear   Tyear,
                Begin_ostatok Currency
            )
    LANGUAGE PLPGSQL
AS
$$
BEGIN
    -- вычисление остатка на начало 1-го месяца периода
    -- сумма начислений на начало 1-го месяца периода
    SELECT (COALESCE((
                     SELECT SUM(N.Nachislsum) SumNach
                     FROM Nachislsumma N
                     WHERE N.Accountid = Argaccount
                       AND N.Serviceid = Argserviceid
                       AND (N.Nachislyear < Argnyear
                         OR (N.Nachislyear = Argnyear
                             AND N.Nachislmonth < Argmonth))
                     ), 0)
        -
        -- сумма оплат на начало 1-го месяца периода
            COALESCE((
                     SELECT SUM(P.Paysum) SumPay
                     FROM Paysumma P
                     WHERE P.Accountid = Argaccount
                       AND P.Serviceid = Argserviceid
                       AND (P.Payyear < Argnyear
                         OR (P.Payyear = Argnyear
                             AND P.Paymonth < Argmonth))
                     ), 0))
    INTO Begin_ostatok;

    Nachislmonth = Argmonth;
    Nachislyear = Argnyear;
    RETURN NEXT;
END;
$$;

/*
Функция Saldo_n для определенного абонента (Argaccount)
по указанной услуге (Argserviceid) рассчитывает и выводит значение
денежного остатка (Begin_ostatok) на начало заданного месяца
(Argmonth, Argnyear) как разницу между суммами всех значений
начислений и плат за весь период, предшествующий заданному
месяцу.

Например, чтобы вывести значение остатка на начало марта 2024 г.
у абонента с номером лицевого счета '015527' по услуге с кодом 1,
необходимо выполнить запрос:
*/

SELECT *
FROM Saldo_n('015527', 1::Pkfield, 3::Tmonth, 2024::Tyear);

/*
Анализируя результаты выполнения запроса,можно установить,
что у абонента с лицевым счетом '015527' на начало января 2024
по услуге с кодом 1, имеется переплата, равная 1.68 условных единиц.

Используя созданную ХФ можно достаточно просто вычислить
значения остатков на начало, например первого и последнего
месяцев заданного периода:
*/

SELECT *
FROM Saldo_n('015527', 1::Pkfield, 1::Tmonth, 2024::Tyear)
UNION
SELECT *
FROM Saldo_n('015527', 1::Pkfield, 12::Tmonth, 2025::Tyear)
ORDER BY 1;

/*
DDL-скрипт функции Oborot_vedomost для расчета и вывода значений
оборотов начислений (Nachisl) и плат (Pay) за заданный месяц
имеет следующий вид:
*/

CREATE OR REPLACE FUNCTION Oborot_vedomost
(
Argaccount VARCHAR(6), Argserviceid Pkfield, Argmonth Tmonth, Argnyear Tyear
)
    RETURNS TABLE
            (
                Nachisl Currency,
                Pay     Currency
            )
    LANGUAGE PLPGSQL
AS
$$
BEGIN
    SELECT
        -- сумма начислений за месяц
        COALESCE((
                 SELECT SUM(Na.Nachislsum)
                 FROM Nachislsumma Na
                 WHERE Na.Accountid = Argaccount
                   AND Na.Serviceid = Argserviceid
                   AND Na.Nachislyear = Argnyear
                   AND Na.Nachislmonth = Argmonth
                 ), 0),
        -- сумма плат за месяц
        COALESCE((
                 SELECT SUM(Pa.Paysum)
                 FROM Paysumma Pa
                 WHERE Pa.Accountid = Argaccount
                   AND Pa.Serviceid = Argserviceid
                   AND Pa.Payyear = Argnyear
                   AND Pa.Paymonth = Argmonth
                 ), 0)
    INTO Nachisl, Pay;

    RETURN NEXT;
END;
$$;

/*
Функция Oborot_vedomost для определенного абонента (Argaccount)
по указанной услуге (Argserviceid) за заданный месяц выводит
суммы значений начислений (Nachisl) и плат (Pay).

Например, следующий запрос выдаст оборотную ведомость абонента
с номером лицевого счета '015527' по услуге с кодом 1 за февраль
2024 года:
*/

SELECT *
FROM Oborot_vedomost('015527', 1::Pkfield, 2::Tmonth, 2024::Tyear);


/*
DDL-скрипт функции Oborot_saldo_vedomost, отвечающей за:
- расчет и вывод значений остатков на начало каждого месяца заданного периода,
- расчет и вывод значений остатков на конец каждого месяца заданного периода,
- а также значений оборотов начислений и платы
за каждый месяц заданного периода:
*/

CREATE OR REPLACE FUNCTION Oborot_saldo_vedomost
(
Argaccount VARCHAR(6), Argserviceid PkField, Argmonth Tmonth, Argyear Tyear, Argfmonth Tmonth, Argfyear Tyear
)
    RETURNS TABLE
            (
                Nachislmonth   Tmonth,
                Nachislyear    Tyear,
                Begin_ostatok  Currency,
                Nachisl        Currency,
                Pay            Currency,
                Result_ostatok Currency
            )
    LANGUAGE PLPGSQL
AS
$$
BEGIN
    -- вычисление остатка на начало 1-го месяца периода
    SELECT *
    FROM Saldo_n(Argaccount, Argserviceid, Argmonth, Argyear)
    INTO Nachislmonth, Nachislyear, Begin_ostatok;

    SELECT *
    FROM Oborot_vedomost(Argaccount, Argserviceid, Argmonth, Argyear)
    INTO Nachisl, Pay;

    Result_ostatok = Begin_ostatok + (Nachisl - Pay);
    Nachislmonth = Argmonth;
    Nachislyear = Argyear;
    RETURN NEXT;

    -- выборка значений начислений и плат за каждый месяц периода
    -- и расчёт остатка на конец месяца
    LOOP
        IF Argmonth = Argfmonth AND Argyear = Argfyear
        THEN
            RETURN;
        END IF;

        IF Argmonth = 12
        THEN
            Argyear = Argyear + 1;
            Argmonth = 1;
        ELSE
            Argmonth = Argmonth + 1;
        END IF;

        -- выборка значений начислений и плат за каждый месяц периода
        SELECT *
        FROM Oborot_vedomost(Argaccount, Argserviceid, Argmonth, Argyear)
        INTO Nachisl, Pay;

        -- вычисление остатка на конец месяца
        Begin_ostatok = Result_ostatok;
        Result_ostatok = Begin_ostatok + (Nachisl - Pay);
        Nachislmonth = Argmonth;
        Nachislyear = Argyear;
        RETURN NEXT;
    END LOOP;
END;
$$;

/*
Пример вызова:
*/

SELECT *
FROM Oborot_saldo_vedomost(
        '015527', 1::PkField,
        1::Tmonth, 2022::Tyear,
        12::Tmonth, 2025::Tyear
     );


/*
Приведем текст DDL-скрипт функции, осуществляющей проверку того,
является ли входная строка вещественным числом:
*/


CREATE OR REPLACE FUNCTION Istr
(
    Str VARCHAR(255)
)
    RETURNS TABLE
            (
                Ir FLOAT
            )
    LANGUAGE PLPGSQL
AS
$$
BEGIN
    -- Правильное регулярное выражение для целых и дробных чисел
    IF (Str ~ '^[+-]?([0-9]+\.?[0-9]*|\.[0-9]+)$')
    THEN
        Ir = Str::FLOAT;
        RETURN NEXT;
    ELSE
        RAISE EXCEPTION 'Не число: %', Str;
    END IF;
EXCEPTION
    WHEN SQLSTATE '22P02' THEN
        RAISE EXCEPTION 'Пустая строка';
END;
$$;

/*
Здесь проверка входной строки на число осуществляется с помощью
регулярного выражения. Функция возвращает вещественное число или
сообщает путем вызова исключения, что входная строка не является
числом. Оператор WHEN обрабатывает ошибку при задании пустой
строки в качестве параметра (код ошибки равен 22P02).

Примеры вызова функции Istr:
*/

SELECT *
FROM Istr('25');
SELECT *
FROM Istr('25.54');
SELECT *
FROM Istr('-25.5');
SELECT *
FROM Istr((+123.45)::TEXT);
SELECT *
FROM Istr('SQL');
SELECT *
FROM Istr('');
SELECT *
FROM Istr(:Par);

/*
Если входному параметру Str присвоить значение по умолчанию:
*/

drop function Istr

CREATE OR REPLACE FUNCTION Istr
(
    Str VARCHAR(255) = 'Здравствуйте'
)
    RETURNS TABLE
            (
                Ir FLOAT
            )
    LANGUAGE PLPGSQL
AS
$$
BEGIN
    -- Правильное регулярное выражение для целых и дробных чисел
    IF (Str ~ '^[+-]?([0-9]+\.?[0-9]*|\.[0-9]+)$')
    THEN
        Ir = Str::FLOAT;
        RETURN NEXT;
    ELSE
        RAISE EXCEPTION 'Не число: %', Str;
    END IF;
EXCEPTION
    WHEN SQLSTATE '22P02' THEN
        RAISE EXCEPTION 'Пустая строка';
END;
$$;

/*
то выполнять эту функцию можно без аргументов:
*/

SELECT *
FROM Istr();

/*
В этом варианте проверяется на соответствие регулярному выражению
либо передаваемое значение параметра, либо значение по умолчанию
при отсутствии параметра. Такой подход является более гибким
по сравнению с представленным ранее благодаря возможности вызова
функции без параметра.

Функция, в отличие от ХП, может быть усложнена как "внутри",
так и "снаружи", т. е. она поддается:
-сортировке,
-группировке,
-соединению.

Следует отметить, что PostgreSQL позволяет вызывать функции
с именованными параметрами, используя позиционную или именованную
нотации.
В позиционной нотации вызов функции записывается
со значениями аргументов в том же порядке, в каком они определены
в объявлении функции.
В именованной нотации аргументы соответствуют параметрам функции
по имени и могут быть записаны в любом порядке.

В любой нотации параметры, которые имеют значения по умолчанию,
заданные в объявлении функции, вообще не нужно записывать
при вызове. Но это особенно полезно в именованной нотации,
так как любая комбинация параметров может быть опущена, в то
время как в позиционной нотации параметры могут быть опущены
только справа налево.

PostgreSQL также поддерживает смешанную нотацию, в которой
сочетаются позиционная и именованная нотации.
В этом случае сначала записываются позиционные параметры, а после них
появляются именованные параметры.

Следующие примеры иллюстрируют использование всех трех нотаций,
используя следующее определение функции:
*/

CREATE FUNCTION Executed_or_not_executed
(
A VARCHAR(6), B VARCHAR(6), U BOOLEAN DEFAULT FALSE
)
    RETURNS TABLE
            (
                Acc   VARCHAR(6),
                Incom DATE
            )
    LANGUAGE plpgsql
AS
$$
BEGIN
    IF ($3)
    THEN
        RETURN QUERY
            SELECT AccountId, Incomingdate
            FROM Request
            WHERE (AccountId = $1 OR AccountId = $2)
              AND Executed;
    ELSE
        RETURN QUERY
            SELECT AccountId, Incomingdate
            FROM Request
            WHERE (AccountId = $1 OR AccountId = $2)
              AND NOT Executed;
    END IF;
END;
$$;

/*
Функция Executed_or_not_executed имеет два обязательных параметра
A и B. Кроме того, есть один необязательный параметр U, который
по умолчанию имеет значение FALSE.
Функция выдает ID абонента и дату регистрации погашенных и непогашенных его заявок
в зависимости от параметра U.

Позиционная нотация — это традиционный механизм передачи
аргументов в функции PostgreSQL:
*/

SELECT *
FROM Executed_or_not_executed('005488'::VARCHAR(6), '115705'::VARCHAR(6), TRUE);

/*
Все аргументы указаны по порядку. Результатом является погашение
заявки, поскольку U указан как TRUE.
*/

SELECT *
FROM Executed_or_not_executed('005488'::VARCHAR(6), '115705'::VARCHAR(6));

/*
Здесь параметр U опущен, поэтому он получает значение по умолчанию
FALSE, что приводит к выводу непогашенных заявок.
В позиционной записи аргументы можно опускать справа налево, если они имеют
значения по умолчанию.

В именованной нотации имя каждого аргумента указывается с помощью
"=>", чтобы отделить его от выражения аргумента, например:
*/

SELECT *
FROM Executed_or_not_executed(A => '005488', B => '115705');
SELECT *
FROM Executed_or_not_executed(A => '005488', B => '115705', U => TRUE);
SELECT *
FROM Executed_or_not_executed(A => '005488', U => TRUE, B => '115705');
SELECT *
FROM Executed_or_not_executed(U => true, B => '115705', A => '005488');

/*
Смешанная нотация сочетает в себе позиционную и именную нотации.
Однако, как уже упоминалось, именованные аргументы не могут
предшествовать позиционным аргументам.
Например:
*/

SELECT *
FROM Executed_or_not_executed('005488', '115705', U => TRUE);

/*
В приведенном выше запросе аргументы А и В указаны позиционно,
а U — по имени. В более сложной функции, имеющей множество
параметров, имеющих значения по умолчанию, именованная или
смешанная нотация может сэкономить много времени на написание
и снизить вероятность ошибки.

Удаление функции в PostgreSQL производится следующим запросом:

DROP FUNCTION [IF EXISTS] имя_функции
[([(<режим_параметра>) [имя_параметра]] тип_данных_параметра
[, ... ] ) ] [, ... ]
[CASCADE | RESTRICT]

Кроме имени функции необходимо указать типы ее аргументов, так как
в БД могут существовать несколько функций с одним именем, но
с разными списками аргументов.

После изучения хранимых функций и процедур целесообразно показать
различия между ними.
Основные различия в PostgreSQL приведены далее в таблице.

Хранимые функции и процедуры в PostgreSQL служат различным целям:

1.функции, как правило, используются для вычисления и возвращения
значений.
2.процедуры чаще применяются для выполнения операций, осуществляемых над данными с возможностью
управления транзакциями.
Поддерживают механизм обработки исключений с использованием блоков EXCEPTION, что позволяет
обрабатывать ошибки и исключительные ситуации в рамках
исполнения функции и процедуры.

Выбор между использованием функций или процедуры в большей степени зависит от конкретной
задачи, которую нужно решить. Версии PostgreSQL, начиная с 11,
усиливают гибкость и возможности разработчиков благодаря
улучшениям в механизмах управления транзакциями и обработки
исключений, предоставляя разработчикам мощные инструменты для
создания различных процедур и функций, позволяющих реализовывать
как простые, так и сложные логики обработки данных.
*/

/*
Различие между хранимыми процедурами и функциями

+----------------------+------------------------------------------+----------------------------------------------+
| Параметр             | Процедуры                                | Функции                                      |
+----------------------+------------------------------------------+----------------------------------------------+
| Входные параметры    | Могут принимать                          | Могут принимать                              |
| Возвращаемое значение| Не предназначены для возврата данных.    | Могут возвращать значения базовых типов,     |
|                      | Используются для выполнения задач,       | составных типов, наборы строк или таблицы.   |
|                      | включающих изменения в БД или управление | Подходят для использования в запросах, где   |
|                      | транзакциями.                            | требуется обработка и возврат данных.        |
+----------------------+------------------------------------------+----------------------------------------------+
| Использование в      | Нельзя вызвать напрямую в SQL-запросах.  | Можно вызывать непосредственно в SQL-запро-  |
| запросах SELECT      | Вызываются с помощью CALL.               | сах, так как возвращают результаты.          |
+----------------------+------------------------------------------+----------------------------------------------+
| Транзакции           | Позволяют управлять транзакциями         | Менее гибкие в управлении транзакциями,      |
|                      | (BEGIN, COMMIT, ROLLBACK).               | но могут быть использованы внутри транзакций |
+----------------------+------------------------------------------+----------------------------------------------+
| DML-операции         | Идеально подходят для выполнения         | Нет, но могут вызывать хранимые процедуры    |
|                      | операций, влияющих на данные.            |                                              |
+----------------------+------------------------------------------+----------------------------------------------+
| Исключения           | Поддерживают                             | Поддерживают                                 |
+----------------------+------------------------------------------+----------------------------------------------+
*/


/*
Динамический SQL

При создании приложений на процедурных языках часто возникает
ситуация, когда структура SQL-запросов заранее не определена
и может изменяться в зависимости от каких-либо условий. Для
решения ситуаций подобного типа используется механизм, называемый
динамическим SQL (DSQL).

Суть этого механизма заключается в том, что запросы внутри блоков
процедурного языка формируются в виде текстовых строк
непосредственно во время работы программы, что позволяет получить
более широкие возможности для работы с ними. Такие запросы могут
принимать параметры, значения которых передаются из переменных
процедурного языка.

Процедурный язык PL/pgSQL предоставляет возможность выполнения
динамических запросов в теле модуля с помощью оператора EXECUTE
в сочетании с функцией FORMAT, а также командой GET DIAGNOSTICS.

Динамический SQL-запрос может быть:

1) селективным запросом, возвращающим набор данных;
2) DML-запросом, содержащим операторы добавления, изменения или
   удаления строк из таблиц;
3) выполнением ХП;
4) вызовом ХФ;
5) DDL-выражением, содержащим операторы создания, изменения или
   удаления объектов БД: доменов, таблиц, представлений, ХП, ХФ.
   При этом нельзя выполнить оператор создания и удаления БД.

В таком случае запрос записывается как <строка>, которая может
быть сконструирована как локальная переменная в теле модуля или же
передана внешним приложением или ХП в качестве входного аргумента
для другой ХП. Оператор EXECUTE может применяться как в ХФ и ХП,
так и в триггерах и выполняемых блоках на PL/pgSQL.

Синтаксис оператора EXECUTE:

EXECUTE <строка> [INTO [STRICT] переменные] [USING выражение [, ...]];

где строка — это выражение, формирующее строку (типа TEXT)
с текстом запроса, который нужно выполнить; переменные — это либо
список переменных, разделенных запятыми, либо одна переменная
составного типа, куда будут помещены результаты запроса;
выражения формируют значения, которые будут вставлены в запрос.

Можно выделить в синтаксисе две формы использования оператора
EXECUTE:
    - Первая форма (простейшая) представлена синтаксисом:

EXECUTE <строка>;

В этой форме оператор EXECUTE выполняет запрос SQL, записанный как
строка, который производит какое-то действие, но не возвращает
строки данных. Такой запрос может представлять собой следующее:
1) запрос DML (INSERT, DELETE, UPDATE, MERGE);
2) CALL;
3) любой запрос DDL, за исключением CREATE DATABASE и DROP DATABASE.
*/

/*
Например, если создать процедуру:
*/



CREATE PROCEDURE One_sample
(
Sql VARCHAR(60), Account VARCHAR(30)
)
    LANGUAGE PLPGSQL
AS
$$
BEGIN
    EXECUTE Sql || quote_literal(Account);
    ---quote_literal — это встроенная функция PostgreSQL, которая добавляет кавычки
    -- вокруг строки и экранирует специальные символы.
END;
$$;

/*
ТО ВЫПОЛНИТЬ ЕЕ МОЖНО С ПОМОЩЬЮ ОПЕРАТОРА:
*/

-- Выполнение ХП
CALL One_sample('DELETE FROM Request WHERE Accountid = ', '005488');

/*
Вторая форма оператора EXECUTE имеет формат

EXECUTE <строка>
INTO <имя_переменной1> [, <имя_переменной2> ...] [STRICT]

В этом случае строка представляет собой запрос, возвращающий
одиночную строку данных. Если указано ключевое слово STRICT,
запрос должен вернуть не более одной строки, в противном случае
возникает исключение, если ключевое слово не указано, запрос
может вернуть более одной строки, но в заданные переменные будут
записаны данные только из первой строки.

Пример создания хранимой процедуры, использующей вторую форму
синтаксиса оператора EXECUTE:
*/

CREATE PROCEDURE Two_sample
(
Colname VARCHAR(50), TableName VARCHAR(50), OUT Maxim NUMERIC(15, 2)
)
    LANGUAGE PLPGSQL
AS
$$
BEGIN
    -- селективный запрос, возвращающий значение, сохраняемое
    -- в переменной с помощью конструкции EXECUTE INTO
    EXECUTE 'SELECT MAX(' || Colname || ') FROM ' || TableName INTO Maxim;
END;
$$;

/*
Процедура Two_sample определяет в указанной таблице БД
максимальное значение в заданном столбце, имеющем числовой тип
данных.

Процедура может быть выполнена следующим оператором:
*/

CALL Two_sample('Paysum', 'Paysumma', NULL);

/*
Оператор EXECUTE не позволяет извлечь более одной строки.
Для извлечения множества строк PostgreSQL предоставляет оператор
FOR ... IN EXECUTE, выполняющий цикл по строкам, возвращаемым
динамическим запросом.

Оператор имеет следующий синтаксис:

[ <<метка>> ]
FOR переменные IN EXECUTE запрос [ USING выражение [, ... ] ]
LOOP
    операторы
END LOOP [ метка ];

Где переменные — либо список переменных, либо одна переменная
составного типа, в которую на каждой итерации цикла записываются
значения текущей строки.
Вместо переменной составного типа можно
также указать переменную типа RECORD. Тогда набор столбцов
у переменной будет определен автоматически на основе результата
выполнения запроса.

Рассмотрим ХФ, в которой применяется оператор FOR ... IN EXECUTE.
Пример создания такой функции:
*/

CREATE FUNCTION Three_sample
(
Textfield VARCHAR(10), Tablename VARCHAR(10), Ascdesc VARCHAR(4)
)
    RETURNS TABLE
            (
                Line VARCHAR(20)
            )
    LANGUAGE PLPGSQL
AS
$$
DECLARE
    Oneline VARCHAR(50);
BEGIN
    -- селективный запрос
    Oneline = 'SELECT ' || Textfield || ' FROM ' || Tablename || ' ORDER BY 1 ';
    IF Ascdesc = 'DESC'
    THEN
        Oneline = Oneline || 'DESC';
    END IF;
    FOR Line IN EXECUTE Oneline
        LOOP
            RETURN NEXT;
        END LOOP;
END;
$$;

/*
Данная функция производит вывод значений столбца таблицы,
имена которых задаются соответственно значениями 1-го и 2-го
параметров, в порядке, определяемом значением 3-го параметра.
*/

/*
Функция Three_Sample может быть выполнена с помощью запроса:
*/

SELECT *
FROM Three_sample('Fio', 'Abonent', 'ASC');

/*
Результатом такого выполнения является вывод значений столбца
Fio таблицы Abonent, упорядоченных в обратном алфавитном порядке.

Вызов функции через динамический SQL имеет смысл в следующих
случаях:

1) когда имя функции или ее параметры определяются динамически
   (например, из переменной);
2) когда вызов функции является частью более сложного динамического
   SQL-запроса.

При этом необходимо учитывать следующие ограничения:

1) если функция возвращает набор строк (таблицу), работать с ее
   результатом через динамический SQL становится сложнее. Обычно
   в таких случаях используется курсор или временная таблица;
2) если функция возвращает сложный тип (например, RECORD),
   требуется явно указать структуру результата.

Если функция принимает аргументы, их можно передать в строку
динамического SQL. Для этого рекомендуется использовать функцию
quote_literal() или quote_ident() для безопасного формирования
строки, например:
*/

DO $$
    DECLARE
        Param1 TEXT := 'Fio';
        Param2 TEXT := 'Abonent';
        Param3 TEXT := 'ASC';
        Result TEXT;
    BEGIN
        -- Вызов функции с параметрами
        EXECUTE 'SELECT Three_sample(' ||
                quote_literal(Param1) || ', ' ||
                quote_literal(Param2) || ', ' ||
                quote_literal(Param3) || ')'
            INTO Result;
        -- Вывод результата
        RAISE NOTICE 'Function result: %', Result;
    END;
$$ LANGUAGE PLPGSQL;

/*
Результат выполнения:
Function result: Аксенов С. А.

В PostgreSQL оператор EXECUTE поддерживает применение
параметризированных запросов. Ссылки на параметры обозначаются
как $1, $2 и т. д. Например, в случае применения
параметризированного запроса ХП One_Sample может быть представлена таким образом:
*/

CREATE PROCEDURE One_sample
(
Sql VARCHAR(255), Account VARCHAR(30)
)
    LANGUAGE PLPGSQL
AS
$$
BEGIN
    -- DML-запрос
    EXECUTE Sql USING Account;
END;
$$;

/*
а выполнить ее можно так:
*/

CALL One_sample('DELETE FROM Request WHERE Accountid = $1', '005488');

/*
В параметризированных запросах поддерживаются только безымянные
параметры!!!

При использовании параметризированных запросов необходимо
учитывать, что если при присваивании значения параметру
передается выражение (например, USING I + 1), то значение
этого выражения вычисляется только один раз.

Динамические запросы можно выполнять и на внешней БД, но для
этого используется не оператор EXECUTE, а функция DBLINK.
По умолчанию функция DBLINK не доступна, чтобы подключить ее,
необходимо выполнить запрос:
*/

CREATE EXTENSION DBLINK;

/*
Примечание
Если база данных находится на другом сервере, то необходимо
добавить хост и порт в параметры подключения!!!

При использовании функции DBLINK необходимо задать имена и типы
столбцов, возвращаемых функцией.

Реализацию выборки информации из другой БД можно продемонстрировать
на следующем примере.
Пусть на том же компьютере следующим скриптом
создана БД Images\public, в которой, для хранения изображений
(например фото абонента) определена таблица Abonentimages:
*/

CREATE DATABASE Images WITH OWNER 'postgres' ENCODING 'UTF8';


drop table Abonentimages
CREATE TABLE Abonentimages
(
    ID_image INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    Lshet    VARCHAR(6),
    Image    BYTEA
);

/*
В таблицу Abonentimages добавлена строка следующим запросом:
*/

INSERT INTO Abonentimages (Lshet, Image)
VALUES (:Shet, pg_read_binary_file(:Photo));


/*
Если в учебной БД создать хранимую функцию:
*/

drop FUNCTION Photo;

CREATE OR REPLACE FUNCTION Photo
(
)
    RETURNS TABLE
            (
                Account VARCHAR(6),
                Image   BYTEA
            )
    LANGUAGE SQL
AS $$

-- и подключиться к другой БД следующим образом:

SELECT *
FROM DBLINK('dbname=images user=postgres password=*************',
            'SELECT Lshet, Image FROM public.abonentimages')
         AS T(Account VARCHAR(6), Image BYTEA);
$$;

/*
то для отображения номера лицевого счета и фото абонента достаточно
выполнить ХФ, например так:
*/

SELECT *
FROM dblink('dbname=demo_one user=postgres password=************',
            'SELECT company_sk, company_name, created_at FROM dwh.dim_company')
         AS t(
              company_sk INTEGER,
              company_name VARCHAR(100),
              created_at DATE
        );

SELECT *
FROM Photo();

/*
Далее представлены простые примеры выполнения динамического запроса
в DO-блоке.
*/

DO
LANGUAGE PLPGSQL $$
    DECLARE
        Rec     RECORD;
        Account TEXT := '005488';
        Sql     TEXT := 'SELECT Fio FROM Abonent WHERE Accountid = $1';
    BEGIN
        EXECUTE Sql INTO Rec USING Account;
        -- EXECUTE - выполняет динамический SQL из переменной Sql
        -- INTO Rec - результат запроса помещается в переменную Rec
        -- USING Account - значение переменной Account подставляется
        -- вместо $1 в запросе
        -- Безопасный способ передачи данных (защита от SQL-инъекций)
        RAISE NOTICE 'ФИО: %', Rec;
    END;
$$;

/*
Результат выполнения:

ФИО: ("Аксенов С. А.")

Или:
*/

DO
$$
    DECLARE
        Oneline   VARCHAR(50);
        Textfeld  VARCHAR(10) = 'Fio';
        Tablename VARCHAR(10) = 'Abonent';
        Ascdesc   VARCHAR(4)  = 'DESC';
        Line      VARCHAR(20);
        Rec       RECORD;
    BEGIN
        Oneline = 'SELECT ' || Textfeld || ' FROM ' || Tablename || ' ORDER BY 1 ';
        IF (Ascdesc = 'DESC')
        THEN
            Oneline = Oneline || 'DESC';
        END IF;

        FOR Rec IN EXECUTE Oneline
            LOOP
                RAISE NOTICE '% ', Rec;
            END LOOP;
    END $$;

/*
Результат выполнения:

("Шубина Т. П.")
("Шмаков С. В.")
("Тулупова М. И.")
("Тимошкина Н. Г.")
("Стародубцев Е. В.")
("Свирина З. А.")
("Мищенко Е. В.")
("Маркова В. П.")
("Лукашина Р. М.")
("Конюхов В. С.")
("Денисова Е. К.")
("Аксенов С. А.")

Получить тот же результат можно с курсором:
*/
DO
$$
    DECLARE
        Oneline   VARCHAR(50);
        Textfeld  VARCHAR(10) = 'Fio';
        Tablename VARCHAR(10) = 'Abonent';
        Ascdesc   VARCHAR(4)  = 'DESC';
        Cur       REFCURSOR;
        Rec       RECORD;
    BEGIN
        Oneline = 'SELECT ' || Textfeld || ' FROM ' || Tablename || ' ORDER BY 1 ';
        IF (Ascdesc = 'DESC')
        THEN
            Oneline = Oneline || 'DESC';
        END IF;
        OPEN Cur FOR EXECUTE Oneline;
        LOOP
            FETCH Cur INTO Rec;
            EXIT WHEN NOT FOUND;
            RAISE NOTICE '% ', Rec;
        END LOOP;
    END $$;

/*
В хранимой функции:
*/

CREATE OR REPLACE FUNCTION Fi_acc
(
    Acc TEXT
)
    RETURNS TEXT
    LANGUAGE PLPGSQL AS $$
DECLARE
    Fi      TEXT;
    Fio_acc TEXT := 'SELECT Fio FROM Abonent WHERE Accountid = $1';
BEGIN
    EXECUTE Fio_acc INTO Fi USING Acc;
    RETURN Fi;
END;
$$;

/*
Вызов:
*/
EXPLAIN analyze
SELECT Fi_acc('005488');

/*
Результат выполнения:
*/

CREATE OR REPLACE FUNCTION Err_exception
(
Tabl TEXT, OUT Rez INTEGER
)
    LANGUAGE PLPGSQL
AS $$
DECLARE
    -- Переменные для хранения информации об ошибке
    Code    TEXT; -- Код SQLSTATE ошибки (например, '42P01')
    Msg     TEXT; -- Текст сообщения об ошибке
    Context TEXT; -- Контекст ошибки (строка, функция)
BEGIN
    -- ВНУТРЕННИЙ БЛОК (для перехвата ошибок)
    BEGIN
        -- Формируем динамический SQL-запрос
        -- $1 заменяется на значение параметра Tabl
        -- Пример: 'SELECT COUNT(*) FROM Abonent'
        Code = 'SELECT COUNT(*) FROM ' || $1;

        -- Выводим сформированный запрос для отладки
        RAISE NOTICE '%', Code;

        -- Выполняем динамический запрос
        -- Результат (количество строк) помещается в OUT параметр Rez
        -- USING Tabl безопасно подставляет имя таблицы
        EXECUTE Code INTO Rez USING Tabl;

        -- БЛОК ОБРАБОТКИ ОШИБОК
    EXCEPTION
        -- WHEN OTHERS - перехватывает любые ошибки
        WHEN OTHERS THEN
            -- Если ошибка, возвращаем NULL вместо количества строк
            Rez := NULL;

            -- GET STACKED DIAGNOSTICS - получает детальную информацию об ошибке
            -- Аналог: "Расскажи мне подробности о том, что пошло не так"
            GET STACKED DIAGNOSTICS
                Code = RETURNED_SQLSTATE, -- Код ошибки (например, '42P01')
                Msg = MESSAGE_TEXT, -- Текст ошибки
                Context = PG_CONTEXT;
            -- Где произошла ошибка

            -- Выводим информацию об ошибке в консоль
            -- Три % заменяются на Code, Msg, Context
            RAISE NOTICE 'Код ошибки: %.
            Текст сообщения об ошибке: %.
            Контекст ошибки: %', Code, Msg, Context;
    END;
END;
$$;


/*
Вызов:
*/

DO $$
    DECLARE
        Rez INTEGER;
    BEGIN
        SELECT E.Rez
        INTO Rez
        FROM Err_exception('Abonent'::TEXT) AS E;
        RAISE NOTICE 'Result: %', Rez;
    END;
$$;

/*
Результат выполнения:

SELECT COUNT(*) FROM Abonent
Result: 12

Вызов с ошибкой:
*/

DO $$
    DECLARE
        Rez INTEGER;
    BEGIN
        SELECT E.Rez
        INTO Rez
        FROM Err_exception('Abonen'::TEXT) AS E;
        RAISE NOTICE 'Result: %', Rez;
    END;
$$;

/*
ЗАМЕЧАНИЕ. Код ошибки: 42P01. Текст сообщения об ошибке:
отношение "abonen" не существует. Контекст ошибки:
функция PL/pgSQL err_exception(text), строка 14,
оператор GET STACKED DIAGNOSTICS SQL-оператор:
"SELECT e.Rez FROM Err_exception('Abonen'::TEXT) AS e"
функция PL/pgSQL inline_code_block, строка 5, оператор SQL-оператор

ЗАМЕЧАНИЕ: Result: <NULL>

Пример с передачей текста запроса в ХФ:
*/

CREATE OR REPLACE FUNCTION One_Sample
(
Sq TEXT, Account TEXT
)
    RETURNS TEXT
    LANGUAGE PLPGSQL AS $$
DECLARE
    Fi TEXT;
BEGIN
    RAISE NOTICE 'Запрос: % %;', $1, $2;
    EXECUTE $1 || $2 INTO Fi USING Sq, Account;
    RETURN Fi;
END;
$$;

/*
Выполнить ее можно, например с помощью следующего запроса:
*/

SELECT One_Sample('SELECT Fio FROM Abonent WHERE Accountid='::TEXT, $$'005488'$$::TEXT);

/*
Результат выполнения:

Запрос: SELECT Fio
FROM Abonent
WHERE Accountid= '005488';
*/


/*
Динамический SQL полезен, когда структура запросов или их параметры
определяются во время выполнения. Однако его нужно использовать
осторожно. Небезопасное использование имен объектов и строковых
значений в динамическом SQL может привести к серьезным проблемам,
включая SQL-инъекции, ошибки синтаксиса и непредсказуемое
поведение. Например, последствия SQL-инъекций могут быть следующими:

- злоумышленник может получить доступ к конфиденциальной информации;
- злоумышленник может изменить или удалить данные в БД;
- злоумышленник может выполнить произвольные команды на сервере БД.

Для предотвращения этих и других проблем рекомендуется использовать
специальные функции, параметризованные запросы, проверку и валидацию
входных данных, а также избегать конкатенации строк!!! для построения
запросов. Эти меры помогут обеспечить безопасность и корректность
выполнения динамического SQL.

Для безопасного формирования динамических запросов можно
использовать функцию FORMAT !!!, которая формирует запрос в соответствии
со строкой формата:

FORMAT(строка_формата [, аргумент][, ...])

где строка_формата — строка, содержащая текст и спецификаторы
формата; аргумент — значения, которые будут вставлены в строку
формата на места спецификаторов.

Функция FORMAT поддерживает несколько спецификаторов формата,
которые определяют, как аргументы будут вставлены в строку формата:

%S — вставляет строковое значение без экранирования;
%I — вставляет идентификатор (например, имя таблицы или столбца)
      с автоматическим экранированием;
%L — вставляет строковый литерал с автоматическим экранированием;
%% — вставляет символ процента (%).

Для добавления динамически нового столбца в указанную таблицу можно
использовать такую ХФ:
*/

CREATE OR REPLACE FUNCTION Add_column_to_table
(
Table_name TEXT, Column_name TEXT, Column_type TEXT
)
    RETURNS VOID
    LANGUAGE PLPGSQL AS $$
BEGIN
    EXECUTE FORMAT(
            'ALTER TABLE %I ADD COLUMN %I %s',
            Table_name, Column_name, Column_type
            );
END;
$$;


/*
В данной функции %I, правильно экранируя имена таблиц и столбцов,
защищает от инъекций.

Пример добавления столбца email в таблицу abonent:
*/

SELECT Add_column_to_table('abonent', 'email', 'VARCHAR(50)');

select *
from abonent;

/*
Следующий DO-блок также демонстрирует формирование безопасного
динамического запроса за счет вставки строкового литерала
с автоматическим экранированием:
*/

DO $$
    DECLARE
        User_input TEXT := 'Аксенов С. А.';
    BEGIN
        RAISE NOTICE '%', FORMAT('SELECT * FROM Abonent WHERE Fio = %L;', User_input);
    END $$;

/*
Результат выполнения:
*/
SELECT *
FROM Abonent
WHERE Fio = 'Аксенов С. А.';

/*
При использовании оператора EXECUTE получать информацию о выполнении
SQL-запросов, такую как количество затронутых строк, статус выполнения
запросов, а также выполнять запросы с динамически формируемыми именами
таблиц, столбцов и условий можно с помощью команды GET DIAGNOSTICS.
В следующей ХФ вставляются данные в таблицу, имя которой передается
динамически, а после выполнения выдается количество вставленных строк:
*/

CREATE OR REPLACE FUNCTION Insert_into_dynamic
(
Table_name TEXT, Sequence_name TEXT, Id_column TEXT, Name_column TEXT, Fios TEXT[]
)
    RETURNS INT AS $$
DECLARE
    Row_c INT; -- переменная для хранения количества вставленных строк
BEGIN
    -- проверка существования таблицы
    IF EXISTS
    (
    SELECT 1
    FROM pg_tables
    WHERE tablename = Table_name
    )
    THEN
        -- формирование и выполнение динамического запроса
        -- для вставки данных
        EXECUTE FORMAT(
                'INSERT INTO %I (%I, %I) SELECT NEXTVAL(''%I''), UNNEST($1)',
                Table_name, Id_column, Name_column, Sequence_name
                ) USING Fios;

        -- получение количества затронутых строк
        GET DIAGNOSTICS Row_c = ROW_COUNT;
        -- возврат количества вставленных строк
        RETURN Row_c;
    ELSE
        -- если таблица не существует, выбрасывается ошибка
        RAISE EXCEPTION 'Таблица "%" не существует', Table_name;
    END IF;
END;
$$
    LANGUAGE PLPGSQL;


/*
Здесь с помощью функции FORMAT формируется динамический запрос INSERT,
где:
- %I используется для экранирования идентификаторов (имён таблиц и колонок);
- NEXTVAL('%I') получает следующее значение из последовательности;
- UNNEST($1) преобразует массив значений в набор строк для вставки.

-- выполнение
*/

SELECT Insert_into_dynamic(
               'executor', -- имя таблицы
               'gen_executor', -- имя последовательности
               'executorid', -- имя столбца для id
               'fio', -- имя столбца для name
               ARRAY ['Иванов И. И.', 'Сидоров А. В.', 'Козлов К. С.']
       );

SELECT proname, pg_get_function_identity_arguments(oid)
FROM pg_proc
WHERE proname = 'insert_into_dynamic';

/*
Результат выполнения:

insert_into_dynamic:
3
*/
select *
from Executor

/*
В заключение следует отметить, что операторы выполнения динамических
запросов добавляют гибкости модулям на процедурных языках, но с риском
ошибок. Такие операторы следует применять только в случае невозможности
получить нужные результаты другими средствами, или когда это действительно
улучшает выполнение запроса (что маловероятно).

При использовании оператора динамического выполнения нужно помнить
о его особенностях:

- во время компиляции синтаксический анализатор не может проверить
  синтаксис запроса в строке аргумента; !!!
- во время компиляции возвращаемые значения не проверяются на соответствие
  типов данных (например, строка '1234' может быть преобразована в целое
  число, а строка 'абв' вызовет ошибку преобразования), поэтому они должны
  быть внимательно проверены разработчиком, чтобы избежать непредсказуемых
  исключений преобразования данных при последующем выполнении процедуры;
- не проверяются зависимости или существование защиты для предотвращения
  удаления или изменения таблиц и столбцов;
- операции динамического выполнения работают медленно, потому что
  встроенный оператор должен подготавливаться на сервере каждый раз перед
  выполнением.
*/


/*
Программирование триггеров
Триггеры DML

Общие сведения

Триггер — это особый вид процедуры программной обработки события
в БД, вызываемой автоматически без непосредственного участия
пользователя. В большинстве случаев реализуются триггеры для
обработки событий, связанных с таблицей БД !!!

Триггеры — важнейший механизм для активных баз данных, которые
являются не пассивными системами хранения, а активно реагируют
на изменения в данных путем генерации различных событий и их
обработки.

Триггеры используются в частности для решения следующих задач:

1) реализация на сервере бизнес-логики в рамках концепции
   активных баз данных;
2) обеспечение сложных бизнес-правил и дополнение встроенных
   механизмов ссылочной целостности;
3) осуществление аудита доступа к объектам БД и функционирования
   системы путем создания прозрачных файлов протоколов;
4) автоматизация некоторых задач администрирования баз данных
   (сбор статистики о доступе к данным; автоматическое обновление
   индексов или данных в связанных таблицах);
5) организация сбора статистики о доступе к объектам БД
   (например, подсчет числа операций INSERT, UPDATE, DELETE
   для таблицы; логирование запросов или действий пользователей);
6) управление DDL действиями с помощью EVENT TRIGGERS (создание,
   изменение, удаление и переименование);
7) управление DML операциями (вставка, модификация и удаление)
   и их предотвращением;
8) автоматическая генерация выводных значений столбцов;
9) оповещение других модулей о том, что делать в случае изменения
   информации в БД;
10) организация каскадных воздействий на таблицы БД;
11) управление и перенаправление DML операций, когда они изменяют
    данные в представлении.

Триггеры применяются, как правило, для автоматической поддержки
сложных правил целостности и дополнительной защиты БД. Стандартные
возможности защиты данных — роли и привилегии — задают, какие
именно запросы языка DML может выполнять конкретный пользователь
над конкретной таблицей. В дополнение к этому триггер может
ограничить операции DML, например, в некоторый промежуток времени
или определенные дни недели.

Все современные СУБД поддерживают триггеры, ожидающие какого-то
события БД и реагирующие выполнением определенной последовательности
действий, но, кроме того, некоторые СУБД поддерживают особые виды
триггеров.

В большинстве современных СУБД существует, как правило, три вида
триггеров:
- триггеры DML;
- триггеры DDL;
- системные триггеры (на уровне БД).

В PostgreSQL существует только два вида:
- триггеры DML
- событийные триггеры, выполняющие роль DDL-триггеров и частично
заменяющие системные триггеры в других СУБД.

Триггеры DML исполняются СУБД автоматически при проведении операций
изменения данных.
При создании такой триггер связывается с одной
таблицей или представлением БД. Триггер DML фактически является
обработчиком события на изменение данных в базе!!!

ВАЖНО: Триггеры не могут быть созданы для системных таблиц, хотя и могут
обращаться к ним!!!


Триггеры DML предоставляют возможность производить некоторые
определяемые пользователем действия при выполнении над данными
заданной таблицы или представления трех операций: удаления (DELETE),
изменения (UPDATE) и вставки (INSERT [и иногда TRUNCATE]).
Один и тот же триггер может отслеживать разные виды операций (например, вставку
и изменение), причем операцию можно отслеживать до и после ее выполнения.

Событийные триггеры активируются в ответ на различные события языка
DDL (CREATE, ALTER, DROP и т. д.), а также других событий, таких как
вход в БД.

Если триггеры DML реагируют на изменение данных в базе,
то триггеры DDL реагируют на изменение схемы БД и не привязаны
к конкретным таблицам или строкам, а работают на уровне всей базы
данных.

Системные триггеры также не связываются с конкретным объектом БД.
Они исполняются при подключении к БД или отключении от нее и других
событиях. Формально в PostgreSQL аналогом системных триггеров являются
событийные триггеры, но на данный момент поддерживается только
для отслеживания входа пользователей в базу данных (LOGIN). Хотя
в PostgreSQL формально нет системных триггеров, их можно реализовать
с помощью событийных триггеров.

Использование триггеров в любой СУБД имеет ряд преимуществ:

- возможность автоматической проверки триггерами DML корректности
  данных, соответствующих сложным бизнес-правилам, которые нельзя
  выразить декларативно;
- создание более гибкой системы поддержки целостности БД, которую
  невозможно реализовать декларативно;
- сокращение объема поддержки приложений, поскольку изменения
  триггеров автоматически отражаются во всех приложениях,
  использующих связанные с триггерами таблицы, без необходимости
  их повторной сборки и компиляции;
- возможность контролировать информацию посредством создания системы
  автоматической фиксации изменений данных в таблицах БД, схемы БД,
  а также пользователей, производящих эти изменения (ведение журнала
  изменений). В PostgreSQL для DDL-операций используются событийные
  триггеры.
  Для отслеживания изменений схемы БД и пользователей могут
  быть полезны сторонние инструменты (например, расширение pgAudit
  в PostgreSQL);
- автоматическое оповещение других программ о том, что необходимо
  сделать в случае изменения информации в таблицах БД. Такой подход
  полезен для интеграции с внешними системами или микросервисами;
- публиковать информацию о различных событиях как внутри СУБД
  (например, через NOTIFY), так и через внешние системы.

SHOW shared_preload_libraries;

В следующих случаях использование триггеров нецелесообразно:

- если бизнес-логика проста или не зависит от целостности БД,
  то лучше обрабатывать обновления и логирование на уровне приложения;
- триггеры могут негативно сказаться на производительности, особенно
  если они выполняют сложные операции или если БД подвергается
  высокой нагрузке;
- если логика требует управления транзакциями или может вызвать
  конфликты транзакций, лучше выполнить эту логику в приложении,
  где можно более гибко управлять транзакциями;
- для проверки условий часто достаточно декларативных механизмов
  базы данных, таких, например, как CHECK CONSTRAINT.

Триггеры DML

Триггеры DML вызываются при выполнении запросов INSERT, UPDATE,
DELETE или TRUNCATE. Допускается создание триггера, реагирующего
на два или три запроса.

Вариантов срабатывания триггера три:

1) перед выполнением события, вызывающего срабатывание (BEFORE);
2) после выполнения события, вызывающего срабатывание (AFTER);
3) вместо выполнения события, вызывающего срабатывание (INSTEAD OF).

Комбинирование первых двух вариантов с заданием срабатывания для
каждой строки или всего запроса дает четыре возможных реализации
триггера: перед запросом, перед строкой, после запроса и после
строки.

При этом СУБД PostgreSQL позволяет создавать DML триггеры на уровне:
-строки (FOR EACH ROW)
или
-на уровне операции (FOR EACH STATEMENT).

ROW-триггеры срабатывают один раз для каждой строки, которая
затрагивается операцией INSERT, UPDATE или DELETE. Доступ к содержимому
изменяемой строки через контекстные переменные типа RECORD:

1) NEW — содержит данные новой строки (для INSERT и UPDATE);
2) OLD — содержит данные старой строки (для UPDATE и DELETE).

Это позволяет изменять данные строки перед их записью (например,
нормализовать данные или выполнять вычисления).

Полезны для операций, требующих проверки, модификации или обработки
каждой затронутой строки. Часто используются для проверки целостности
данных, автоматического заполнения столбцов, или сложных вычислений
на основе данных строки.

STATEMENT-триггеры срабатывают один раз для всей операции INSERT,
UPDATE или DELETE (вне зависимости от количества строк, затронутых
этой операцией). Они полезны для:

- логирования массовых изменений;
- выполнения операций, зависящих от всей транзакции;
- триггеров, не требующих привязки к отдельным строкам.

Среди триггеров DML отдельно можно выделить триггеры INSTEAD OF,
позволяющие реализовать операции манипулирования данными для
представлений, которые естественным образом их не допускают
(например, для обновления представлений, ссылающихся на столбцы
из нескольких базовых таблиц). Применять триггеры INSTEAD OF следует
с осторожностью из-за многочисленных потенциальных проблем,
связанных с модификацией данных в базовых таблицах представления.

Триггеры DML применяются для обеспечения ссылочной целостности,
целостности данных и целостности, определяемой пользователем,
т. е. бизнес-правил на уровне таблицы. С точки зрения информационной
системы: бизнес-правило — это указание, определяющее или ограничивающее
определенный аспект бизнеса. Бизнес-правила представляют собой условия
соответствия данных предметной области.

Бизнес-правила реализуются как специализированный вид логики,
описывающий ограничения на образ действий, которые система может
выполнять.

Определение триггера

С любым событием, вызывающим изменение содержимого таблицы
(представления), можно связать определенные действия, которые СУБД
будет автоматически выполнять при каждом возникновении события.

Триггер DML — это предварительно определенное действие или
последовательность действий, автоматически производимых при
выполнении запросов обновления, добавления или удаления данных
к определенной таблице (представлению) БД.

Триггер создается для заданной таблицы (представления) и сохраняется
в БД как часть метаданных. Он является мощным инструментом контроля
изменений данных в БД, а также помогает автоматизировать операции,
которые должны выполняться в этом случае. Триггер выполняется после
проверки правил обновления данных.

Триггер включает в себя два ключевых компонента:

1) событие, которое определяет, при каком действии над таблицей
   (или представлением) триггер должен срабатывать;
2) действие, реализующее логику, которая должна быть выполнена
   при наступлении события (например, проверка данных, запись
   в журнал, обновление связанных таблиц и т. д.).

В СУБД PostgreSQL структура триггера включает следующие основные
секции:

1) имя триггера, которое должно быть уникальным в пределах таблицы
   или схемы;
2) определение таблицы (или представления), для которой создается
   триггер;
3) событие или события, при наступлении которых триггер срабатывает
   (например, INSERT, UPDATE, DELETE, TRUNCATE). В некоторых СУБД
   события делятся на этапы выполнения (BEFORE или AFTER);
4) тело триггера — вызываемая триггерная функция, содержащая
   SQL-запросы и (или) процедурные операторы, реализующие бизнес-логику
   (например, проверка условий, запись в журнал, обновление связанных
   таблиц).

Предусмотренное действие производится за счет выполнения определенной
операции или последовательности операций, с помощью которых
реализуется логика, требуемая для удовлетворения ограничений.

События возникают при изменении содержимого таблицы (представления).
Действие, вызываемое событием, задается последовательностью запросов
SQL и оператором процедурного языка СУБД.

Триггеры являются частью работы транзакции, в которой событие DML
изменяет состояние строки. Если транзакция успешно подтверждается,
то все действия триггеров принимаются. Если будет выполнен откат
транзакции, то все действия триггера будут отменены.

Упрощенный синтаксис запроса на создание DML-триггера в PostgreSQL:

CREATE [ OR REPLACE ] [ CONSTRAINT ] TRIGGER имя
{ BEFORE | AFTER | INSTEAD OF } { событие [ OR ... ] }
ON имя_объекта
[ REFERENCING { { OLD | NEW } TABLE [ AS ] имя_переходной_таблицы }
  [ ... ] ]
[ FOR [ EACH ] { ROW | STATEMENT } ]
[ WHEN (условие) ]
EXECUTE FUNCTION имя_функции ();

где

<событие> ::= { DELETE | INSERT | UPDATE | TRUNCATE }

Определение триггера состоит из заголовка и тела. Заголовок содержит:

- имя создаваемого триггера;
- имя таблицы или модифицируемого представления, для которых создается
  триггер;
- описание связи с событиями, при наступлении которых триггер должен
  сработать.

DML-триггеры могут реагировать как на построчное изменение
(множественное срабатывание), так и единожды на все изменения сразу.
Секция FOR EACH определяет, как будет выполняться триггерная функция:
один раз для каждой строки или для SQL-оператора. Если не указано
ничего, подразумевается FOR EACH STATEMENT (для оператора).
Для триггеров ограничений можно указать только FOR EACH ROW.

Синтаксис запроса на создание построчного триггера DML:

CREATE [ OR REPLACE ] [ CONSTRAINT ] TRIGGER имя
{ BEFORE | AFTER | INSTEAD OF } { событие [ OR ... ] }
ON имя_объекта
FOR EACH ROW
[ WHEN (условие) ]
EXECUTE FUNCTION имя_функции ();

где событие:

- INSERT;
- UPDATE [ OF имя_столбца [, ...] ];
- DELETE.

Когда указывается параметр CONSTRAINT, то создается триггер ограничения.
Он подобен обычным триггерам, но отличается тем, что время его
срабатывания можно изменить командой SET CONSTRAINTS:

SET CONSTRAINTS { ALL | имя [, ...] } { DEFERRED | IMMEDIATE }

где при IMMEDIATE ограничения проверяются в конце каждого оператора,
а при DEFERRED — откладываются до фиксации транзакции, например:

BEGIN;
SET CONSTRAINTS ALL DEFERRED;
-- Операции, временно нарушающие целостность
COMMIT; -- Проверка всех ограничений здесь

Триггеры ограничений должны быть триггерами типа AFTER ROW для обычных
(не сторонних) таблиц. Они могут срабатывать либо в конце оператора,
вызвавшего целевое событие, либо в конце содержащей его транзакции;
в последнем случае они называются отложенными. Срабатывание ожидающего
отложенного триггера можно вызвать немедленно, воспользовавшись
командой SET CONSTRAINTS. Предполагается, что триггеры ограничений будут
генерировать исключения при нарушении ограничений.

Логическое условие WHEN определяет, вызывать триггер или нет.
В триггерах на уровне строк условия WHEN могут проверять старые
и (или) новые значения столбцов в строке.

Определение триггера в PostgreSQL начинают с создания триггерной
функции (процедуры), которая будет вызываться при изменении данных
или событиях в БД. Триггерная функция создается командой CREATE
FUNCTION. При этом у функции не должно быть аргументов, а типом
возвращаемого значения должен быть псевдотип TRIGGER (для триггеров,
срабатывающих при изменениях данных) или EVENT_TRIGGER (для триггеров,
срабатывающих при событиях в базе).

Построчный триггер реагирует многократно, т. е. триггерная функция
выполняется столько раз, сколько строк было затронуто. При этом он
может срабатывать как до обработки (BEFORE) очередной строки, так
и после нее (AFTER). Например, условия возбуждения триггера на вставку
могут быть такими:

- BEFORE INSERT — до вставки;
- AFTER INSERT — после вставки;
- BEFORE INSERT OR UPDATE — до вставки или модификации.

Объектом может быть таблица или представление. Для таблицы можно
использовать триггер как до, так и после события. Для представления
также можно применять триггер как до, так и после выполнения оператора,
но вместо строчного триггера используется триггер на изменение
INSTEAD OF.

Синтаксис построчной триггерной функции:

CREATE OR REPLACE FUNCTION имя_функции() RETURNS TRIGGER
AS
$$
DECLARE
    ...
BEGIN
    ...
EXCEPTION
    ...
    RETURN...
END;
$$
LANGUAGE PLPGSQL;

Внутри триггерной функции доступны контекстные переменные TG_имя
Контекстные переменные в триггерных функциях

| Имя                | Тип данных | Описание |
|--------------------|------------|----------|
| NEW                | RECORD     | Новая строка базы данных, созданная командой INSERT или UPDATE при срабатывании триггера уровня строки (ROW). Переменная используется для модификации новых записей |
| OLD                | RECORD     | Старая строка базы данных, оставшаяся после выполнения команды DELETE или UPDATE при срабатывании триггера уровня строки (ROW) |
| TG_NAME            | name       | Имя сработавшего триггера |
| TG_WHEN            | TEXT       | Строка, содержащая BEFORE, AFTER или INSTEAD OF в зависимости от определения триггера |
| TG_LEVEL           | TEXT       | Строка, содержащая ROW или STATEMENT в зависимости от уровня триггера, указанного в определении |
| TG_OP              | TEXT       | Строка, содержащая INSERT, UPDATE или DELETE в зависимости от операции, вызвавшей срабатывание триггера |
| TG_RELID           | OID        | Идентификатор объекта таблицы, в которой сработал триггер |
| TG_TABLE_SCHEMA    | name       | Имя схемы, содержащей таблицу, для которой сработал триггер |
| TG_TABLE_NAME      | name       | Имя таблицы, для которой сработал триггер |
| TG_NARGS           | INTEGER    | Количество аргументов триггерной функции, указанных в определении триггера |
| TG_ARGV[]          | Массив TEXT | Аргументы, указанные в команде CREATE TRIGGER. Индексация массива начинается с нуля |

Практика возврата из триггерной функции заключается в следующем.

BEFORE-триггер срабатывает в процессе выполнения операции непосредственно
перед действием над строкой. При этом возвращаемым значением может быть
строка (возможно измененная). Если BEFORE-триггер возвращает NULL,
то сама операция будет отменена, а AFTER-триггеры не будут активированы.

BEFORE INSERT и BEFORE UPDATE-триггеры могут изменить строку через
контекстную переменную NEW, и тогда имеющиеся AFTER-триггеры будут уже
работать с измененной строкой.

Если BEFORE-триггер не будет изменять строку, то необходимо вернуть NEW.

В случае BEFORE-триггера, реагирующего на DELETE, возврат не имеет
значения (кроме NULL: отменит DELETE).

AFTER-триггер срабатывает после обработки строки. При этом возвращаемое
значение игнорируется.

Функция должна возвращать NULL или строку, соответствующую структуре
таблицы, к которой привязан триггер. В общем случае разные триггеры
могут вызывать одну и ту же триггерную функцию, что позволяет сократить
объем кода.

Следует отметить, при выполнении DELETE-триггера переменная NEW имеет
значение NULL, так что если BEFORE-триггер выполнит DELETE, то
возвращается OLD.

Возвращаемое значение из построчного AFTER-триггера (или из BEFORE
и из AFTER триггеров на утверждение) игнорируется и может возвращаться
NULL.

В случае построчного AFTER-триггера или триггера на утверждение для
отмены операции необходимо выполнить команду RAISE EXCEPTION.

Рассмотрим пример создания построчного триггера для логирования
временной метки и имени пользователя последнего изменения или добавления
строки в таблице Abonent_1:
*/

SELECT *
INTO Abonent_1
FROM Abonent;

-- Сначала необходимо добавить столбцы, хранящие временную метку
-- и имя пользователя:

ALTER TABLE Abonent_1
    ADD D_update Timestamp;
ALTER TABLE Abonent_1
    ADD U_update TEXT;

-- Затем необходимо определить триггерную функцию:

CREATE OR REPLACE FUNCTION Changes_abonent
(
)
    RETURNS TRIGGER
AS
$$
BEGIN
    NEW.D_update = NOW();
    NEW.U_update = SESSION_USER;
    RETURN NEW;
END
$$
    LANGUAGE PLPGSQL;

-- И, наконец, создать сам триггер:

CREATE OR REPLACE TRIGGER Changes_on_abonent
    BEFORE INSERT OR UPDATE
    ON Abonent_1
    FOR EACH ROW
EXECUTE FUNCTION Changes_abonent();

/*
Во время своего выполнения функция Changes_abonent получает копию
вставляемой или обновленной строки с помощью переменной NEW,
изменяет у строки значения столбцов D_update и U_update и возвращает
измененную строку.

Проверим работу триггера при обновлении данных следующим запросом:
*/

UPDATE Abonent_1
SET Phone = '326127'
WHERE Accountid = '136159';

/*
а работу триггера при добавлении данных таким запросом:
*/

INSERT INTO Abonent_1 (Accountid, Fio, Streetid, Houseno, Flatno, Phone)
VALUES ('111111', 'Ушаков М. И.', 7, 4, 2, '267218');

/*
Результат просмотра некоторых столбцов обновленной таблицы Abonent_1
запросом:
*/

SELECT Accountid, Fio, Phone, D_update, U_update
FROM Abonent_1;

/*
Синтаксис запроса на создание триггера DML на уровне оператора:

CREATE [ OR REPLACE ] TRIGGER имя
{ BEFORE | AFTER } { событие }
ON имя_таблицы
[ REFERENCING { { OLD | NEW } TABLE [ AS ] имя_переходной_таблицы } [ ... ] ]
FOR EACH STATEMENT
[ WHEN (условие) ]
EXECUTE FUNCTION имя_функции ();

где событие:
- INSERT;
- UPDATE [ OF имя_столбца [, ...] ];
- DELETE;
- TRUNCATE.

Ключевое слово REFERENCING непосредственно предшествует объявлению
одного или двух имен, по которым можно будет обращаться к переходным
отношениям с образом-до-изменения или с образом-после-изменения,
образуемым при выполнении целевого оператора.

Секция FOR EACH STATEMENT определяет, что триггерная функция будет
выполняться для SQL-оператора.

В этом случае должна быть создана переходная таблица, на которую можно
ссылаться.

Для триггеров AFTER STATEMENT доступны контекстные переменные
к переходным таблицам OLD TABLE (для UPDATE, DELETE) и NEW TABLE
(для INSERT, UPDATE). Эти переменные предоставляют доступ ко всем
строкам таблицы, обрабатываемым операцией. В OLD будет их старое
состояние, а в NEW — новое.

Триггеры на уровне оператора также могут содержать условие WHEN,
хотя для них это не столь полезно, так как в этом условии нельзя
ссылаться на какие-либо значения в таблице.

BEFORE-триггер срабатывает до операции. При этом возвращаемое
значение игнорируется.

Триггерная функция для триггера на уровне оператора выполняется
единожды.

Рассмотрим еще один пример триггера для логирования изменений данных
таблицы Abonent_1:
*/

DROP TABLE IF EXISTS Abonent_1 CASCADE;
SELECT *
INTO Abonent_1
FROM Abonent;

/*
но теперь будем сохранять информацию не в самой таблице Abonent_1,
а в новой таблице, специально созданной для логирования, Abonent_audit.
Запрос на создание этой таблицы следующий:
*/

CREATE TABLE Abonent_audit
(
    IZ           CHAR(1) NOT NULL,
    User_changed TEXT    NOT NULL,
    Time_stamp   TIMESTAMP,
    Accountid    VARCHAR(6),
    Streetid     Pkfield,
    Houseno      SMALLINT,
    Flatno       SMALLINT,
    Fio          VARCHAR(20),
    Phone        VARCHAR(15)
);


/*
Запрос на создание триггерной функции:
*/
DROP TRIGGER IF EXISTS Audit_abonent_insert ON Abonent_1;
DROP TRIGGER IF EXISTS Audit_abonent_update ON Abonent_1;
DROP TRIGGER IF EXISTS Audit_abonent_delete ON Abonent_1;

DROP FUNCTION IF EXISTS Audit_abonent(
);

CREATE OR REPLACE FUNCTION Audit_abonent
(
)
    RETURNS TRIGGER
    LANGUAGE PLPGSQL
AS $$
BEGIN
    IF TG_OP = 'INSERT'
    THEN
        INSERT INTO Abonent_audit (IZ, User_changed, Time_stamp, Accountid, Streetid, Houseno, Flatno, Fio, Phone)
        SELECT 'I',
               SESSION_USER,
               NOW(),
               Nt.accountid,
               Nt.streetid,
               Nt.houseno,
               Nt.flatno,
               Nt.fio,
               Nt.phone
        FROM New_table AS Nt;
    ELSIF TG_OP = 'UPDATE'
    THEN
        INSERT INTO Abonent_audit (IZ, User_changed, Time_stamp, Accountid, Streetid, Houseno, Flatno, Fio, Phone)
        SELECT 'U',
               SESSION_USER,
               NOW(),
               Nt.accountid,
               Nt.streetid,
               Nt.houseno,
               Nt.flatno,
               Nt.fio,
               Nt.phone
        FROM New_table AS Nt;
    ELSIF TG_OP = 'DELETE'
    THEN
        INSERT INTO Abonent_audit (IZ, User_changed, Time_stamp, Accountid, Streetid, Houseno, Flatno, Fio, Phone)
        SELECT 'D',
               SESSION_USER,
               NOW(),
               Ot.accountid,
               Ot.streetid,
               Ot.houseno,
               Ot.flatno,
               Ot.fio,
               Ot.phone
        FROM Old_table AS Ot;
    END IF;
    RETURN NULL;
END;
$$;


/*Проверка количества колонок*/
SELECT column_name, ordinal_position
FROM information_schema.columns
WHERE table_name = 'abonent_audit'
ORDER BY ordinal_position;

SELECT column_name, ordinal_position
FROM information_schema.columns
WHERE table_name = 'abonent_1'
ORDER BY ordinal_position;

/*
Поскольку в триггерной функции используются переходные таблицы,
вместо одного триггера на все три события обновления данных
необходимо создать три отдельных триггера для запросов INSERT,
UPDATE и DELETE:
*/

CREATE OR REPLACE TRIGGER Audit_abonent_insert
    AFTER INSERT
    ON Abonent_1
    REFERENCING NEW TABLE AS New_table
    FOR EACH STATEMENT
EXECUTE FUNCTION Audit_abonent();

CREATE OR REPLACE TRIGGER Audit_abonent_update
    AFTER UPDATE
    ON Abonent_1
    REFERENCING NEW TABLE AS New_table
    FOR EACH STATEMENT
EXECUTE FUNCTION Audit_abonent();

CREATE OR REPLACE TRIGGER Audit_abonent_delete
    AFTER DELETE
    ON Abonent_1
    REFERENCING OLD TABLE AS Old_table
    FOR EACH STATEMENT
EXECUTE FUNCTION Audit_abonent();

/*
Проверим работу триггеров, выполнив следующие запросы (рис. 10.2 и 10.3),
предварительно удалив результаты предыдущего примера:
*/

INSERT INTO Abonent_1 (Accountid, Fio, Streetid, Houseno, Flatno, Phone)
VALUES ('111111', 'Ушаков М. И.', 7, 4, 2, '267218');

UPDATE Abonent_1
SET Phone = '326127'
WHERE Accountid = '136159';

DELETE
FROM Abonent_1
WHERE Accountid = '111111';

/*
Просмотр результатов:
*/

SELECT Iz,
       User_changed AS User,
       Time_stamp,
       Accountid    AS Acc,
       Streetid     AS St,
       Houseno      AS Hn,
       Flatno       AS Fn,
       Fio,
       Phone
FROM Abonent_audit;

/*
Рассмотрим пример триггера для одного события. Пусть бизнес-правило
требует перед удалением строк в таблице Executor_1:
*/

SELECT *
INTO Executor_1
FROM Executor;

/*
Сохранять в таблице History информацию о ФИО всех исполнителей
ремонтных заявок и дате, до которой данная информация была актуальна.
Скрипт триггера Executor_Delete, реализующего это бизнес-правило,
будет выглядеть следующим образом:
*/

-- Создание таблицы
-- =============================================================================
-- 1. СОЗДАНИЕ ТАБЛИЦЫ History (для хранения истории)
-- =============================================================================

-- Команда CREATE TABLE создаёт новую таблицу в базе данных
CREATE TABLE History
(
    -- Объявление колонки Id: целое число, будет автоматически генерироваться
    -- GENERATED BY DEFAULT AS IDENTITY означает, что значение можно указать
    -- вручную, но если не указать, PostgreSQL сгенерирует его автоматически
    -- PRIMARY KEY означает, что эта колонка - уникальный идентификатор строки
    Id            INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,

    -- Колонка Executor_list: тип TEXT (текст неограниченной длины)
    -- Будет хранить список ФИО всех исполнителей, разделённых запятыми
    Executor_list TEXT,

    -- Колонка Fixdate: тип TIMESTAMP (дата и время с точностью до миллисекунд)
    -- Будет хранить момент времени, когда была создана эта запись истории
    Fixdate       TIMESTAMP
);

-- =============================================================================
-- 2. СОЗДАНИЕ ТРИГГЕРНОЙ ФУНКЦИИ F_history
-- =============================================================================

-- CREATE OR REPLACE FUNCTION - создаёт новую функцию или заменяет существующую
-- F_history - имя функции
-- () - функция не принимает входных параметров
-- RETURNS TRIGGER - функция возвращает тип TRIGGER (обязательно для триггера)
CREATE OR REPLACE FUNCTION F_history
(
)
    RETURNS TRIGGER
AS
$$
-- Начало тела функции (обозначается символами "$_$")
DECLARE
    -- Блок объявления локальных переменных (видим только внутри функции)
    -- Line - строковая переменная для накопления списка ФИО исполнителей
    -- TEXT - тип переменной (текст неограниченной длины)
    Line TEXT;

-- Fiocursor - объявление курсора (итератора по строкам результата запроса)
-- CURSOR FOR - ключевые слова, означающие "курсор для запроса"
-- SELECT Fio FROM Executor_1 - запрос, который выбирает все ФИО из таблицы
-- Важно: на момент работы курсора удаление ещё НЕ ПРОИЗОШЛО (BEFORE DELETE)
    Fiocursor CURSOR FOR SELECT Fio
                         FROM Executor_1;

BEGIN
    -- Начало исполняемой части функции

-- Присваивание переменной Line пустой строки
-- Инициализация перед циклом, чтобы не было "мусора" от предыдущих вызовов
    Line := '';

    -- FOR i IN Fiocursor LOOP ... END LOOP - цикл по всем строкам курсора
    -- На каждой итерации переменная i получает следующую строку результата
    -- i.Fio - обращение к колонке Fio в текущей строке курсора
    FOR i IN Fiocursor
        LOOP
        -- Конкатенация (склеивание) строк:
        -- Line := Line || i.Fio || ', '
        -- Берём текущее значение Line, добавляем ФИО, затем запятую и пробел
        -- Результат сохраняем обратно в Line
        -- Пример: после первой итерации: "Иванов И.И., "
        --          после второй: "Иванов И.И., Петров П.П., "
            Line := Line || i.Fio || ', ';
        END LOOP;
    -- Конец цикла

-- INSERT INTO History - команда вставки новой строки в таблицу History
-- (Executor_list, Fixdate) - перечисление колонок, в которые вставляем
-- VALUES (Line, CURRENT_TIMESTAMP) - значения для вставки:
--   Line - накопленный список ФИО (например, "Иван, Пётр, ")
--   CURRENT_TIMESTAMP - встроенная функция, возвращает текущие дату и время
    INSERT INTO History (Executor_list, Fixdate)
    VALUES (Line, CURRENT_TIMESTAMP);

    -- RETURN NULL - возврат значения из триггерной функции
-- NULL означает "никакого изменения строки"
-- Для BEFORE DELETE STATEMENT возвращаемое значение ИГНОРИРУЕТСЯ
-- Удаление ВСЁ РАВНО ПРОИЗОЙДЁТ после работы триггера
    RETURN NULL;
END;
-- Конец тела функции
$$
-- LANGUAGE PLPGSQL - указывает, что функция написана на языке PL/pgSQL
    LANGUAGE PLPGSQL;

-- =============================================================================
-- 3. СОЗДАНИЕ ТРИГГЕРА Executor_delete
-- =============================================================================

-- CREATE OR REPLACE TRIGGER - создаёт новый триггер или заменяет существующий
-- Executor_delete - имя триггера
-- BEFORE DELETE - момент срабатывания: ПЕРЕД выполнением операции DELETE
-- ON Executor_1 - триггер привязан к таблице Executor_1
-- EXECUTE FUNCTION F_history() - при срабатывании вызвать функцию F_history()
CREATE OR REPLACE TRIGGER Executor_delete
    BEFORE DELETE
    ON Executor_1
EXECUTE FUNCTION F_history();

-- =============================================================================
-- 4. КАК ЭТО ВСЁ РАБОТАЕТ ВМЕСТЕ (ПОШАГОВО)
-- =============================================================================

/*
ШАГ 1. Пользователь выполняет команду:
       DELETE FROM Executor_1 WHERE Executorid = 6;

ШАГ 2. PostgreSQL видит, что к таблице Executor_1 привязан триггер Executor_delete,
       который должен сработать BEFORE DELETE.

ШАГ 3. Срабатывает триггер, вызывается функция F_history().

ШАГ 4. Внутри функции F_history():
       4.1. Объявляется курсор Fiocursor, который читает ВСЕ ФИО из Executor_1
            (удаление ещё НЕ выполнено, поэтому видны все строки)
       4.2. Переменной Line присваивается пустая строка
       4.3. Цикл проходит по каждой строке из Executor_1
            Каждое ФИО добавляется в Line с запятой и пробелом
            Пример: "Иванов И.И., Петров П.П., Сидоров С.С., "
       4.4. В таблицу History вставляется одна строка:
            - Executor_list = полученный список ФИО
            - Fixdate = текущая дата и время
       4.5. Функция возвращает NULL

ШАГ 5. PostgreSQL завершает работу триггера и ВЫПОЛНЯЕТ исходную операцию DELETE
       (удаляет строку(и) из Executor_1).

ШАГ 6. Транзакция завершается (COMMIT или ROLLBACK зависит от внешней транзакции).
       Если будет ROLLBACK, то:
       - Данные в Executor_1 восстановятся
       - Строка в History НЕ ОТКАТИТСЯ? НЕТ, ОТКАТИТСЯ! Триггер - часть транзакции.

ВАЖНЫЕ ОСОБЕННОСТИ:
- Триггер срабатывает 1 раз независимо от количества удаляемых строк
- В History сохраняется ВСЯ таблица Executor_1, а не только удаляемые строки
- Триггер не может отменить удаление (RETURN NULL не работает как отмена)
- Вся операция (логирование + удаление) выполняется в ОДНОЙ транзакции
*/

-- Проверка триггера
DELETE
FROM Executor_1
WHERE Executorid = 6;

-- Просмотр результатов:
SELECT *
FROM Executor_1;
SELECT *
FROM History;

/*

В СУБД основным средством реализации возможностей строчных триггеров
по отслеживанию целостности данных являются контекстные переменные
OLD и NEW. Переменные имеют составной тип и в основном используются
в таком виде:

{ OLD | NEW }.столбец

Контекстная переменная OLD ссылается в строке на текущие или предыдущие
значения, обновляемые или удаляемые соответственно запросами UPDATE
или DELETE в таблице, для которой создан триггер. Таким образом,
переменная OLD не используется при вставке, так как старого значения
не существует.

Контекстная переменная NEW ссылается в строке на новые значения,
которые будут вставлены или обновлены соответственно запросами INSERT
или UPDATE для таблицы, для которой создан триггер. Переменная NEW
не используется при удалении, так как новое значение не создается.

Эти переменные могут быть использованы, в частности, для:

- реализации получения автоинкрементных значений;
- получения значений по умолчанию;
- проверки входных данных и, при необходимости, их изменения;
- получения значений столбцов для модификации других столбцов.

Контекстные переменные OLD и NEW могут использоваться в триггерах
для нескольких событий. Но при этом могут возникнуть ситуации, когда
для одного события, на которое реагирует триггер, контекстная переменная
может использоваться, а для другого — нет. В этом случае ссылка
на столбец NEW в контексте удаления или на столбец OLD в контексте
добавления ошибкой не является — просто будет возвращен NULL.

Простейший триггер для автоматического формирования значения первичного
ключа перед вставкой новой строки, например в таблицу Executor,
можно определить так:
*/

CREATE OR REPLACE FUNCTION Executor_Insert
(
)
    RETURNS TRIGGER
AS $$
BEGIN
    IF (NEW.Executorid IS NULL)
    THEN
        NEW.Executorid = NEXTVAL('Gen_Executor');
    END IF;
    RETURN NEW;
END;
$$
    LANGUAGE PLPGSQL;

-- Создание триггера
CREATE OR REPLACE TRIGGER Insert_Executor
    BEFORE INSERT
    ON Executor
    FOR EACH ROW
EXECUTE FUNCTION Executor_Insert();

-- Проверка триггера
INSERT INTO Executor
VALUES (NULL, 'Иванов И. И.');

select *
from Executor

         /*
         Здесь контекстная переменная NEW используется в качестве имени таблицы
         (Executor), в которую вставляется строка. Если вставка очередной строки
         в таблицу Executor производится запросом INSERT без указания значения
         первичного ключа, то оно будет генерироваться автоматически.
         */


/*
Приведем пример триггерной функции для получения информации о контексте
выполнения операций с таблицей Abonent_1:
*/

         DROP TABLE IF EXISTS Abonent_1;
SELECT *
INTO Abonent_1
FROM Abonent;

-- триггерная функция
CREATE OR REPLACE FUNCTION Context
(
)
    RETURNS TRIGGER
AS $$
DECLARE
    Rec RECORD;
    Str TEXT := '';
BEGIN
    IF TG_LEVEL = 'ROW'
    THEN
        CASE TG_OP
            WHEN 'DELETE'
                THEN Rec := OLD; Str := OLD::TEXT;
            WHEN 'UPDATE'
                THEN Rec := NEW; Str := OLD || ' => ' || NEW;
            WHEN 'INSERT'
                THEN Rec := NEW; Str := NEW::TEXT;
        END CASE;
    END IF;
    RAISE NOTICE '% % % % %', TG_TABLE_NAME, TG_WHEN, TG_OP, TG_LEVEL, Str;
    RETURN Rec;
END;
$$
    LANGUAGE PLPGSQL;

/*
В данном примере используется простая форма оператора множественного
выбора CASE.

Функция Context может быть использована как в триггере на уровне строки,
так и в триггере на уровне оператора. Рассмотрим оба случая.

Первый случай, триггер на уровне строки. Проверка TG_LEVEL = 'ROW'
гарантирует, что оператор CASE будет выполнен только для FOR EACH ROW
триггера. Оператор CASE определяет в зависимости от выполняемого запроса,
какие данные будут записаны в переменные Rec и Str. Переменная Rec
необходима для того, чтобы триггер не повлиял на результат выполнения
запроса.

1. Для INSERT возвращается переменная NEW. Запрос не отменяется,
   а добавляемые данные не изменяются.
2. Для UPDATE возвращается переменная NEW. Запрос не отменяется,
   а данные будут сохранены те, какие указаны в запросе UPDATE.
3. Для DELETE возвращается переменная OLD. Запрос DELETE отменяется,
   если вернуть из триггера NULL. Чтобы этого избежать, вместо
   переменной NEW возвращается переменная OLD, поскольку в DELETE-
   триггерах переменная NEW имеет значение NULL.

Переменная Str используется для вывода данных, связанных с соответствующим
запросом.

1. Для INSERT выводится добавляемая строка.
2. Для UPDATE выводятся предыдущая и новая строка.
3. Для DELETE выводится удаленная строка.

В конце функции с помощью оператора RAISE NOTICE выводятся значения
контекстных переменных, а также переменной Str.

Второй случай, триггер на уровне оператора. Поскольку проверка
TG_LEVEL = 'ROW' никогда не верна, оператор CASE не выполняется,
а переменные Rec и Str остаются со своими значениями по умолчанию,
NULL и пустой строкой соответственно.

В конце функции с помощью оператора RAISE NOTICE выводятся значения
контекстных переменных, а также переменной Str. Как было сказано,
в этот момент переменная Str содержит пустую строку, поэтому она
будет не выводиться.

Создадим с помощью этой функции четыре триггера:

1) BEFORE ... FOR EACH STATEMENT;
2) AFTER ... FOR EACH STATEMENT;
3) BEFORE ... FOR EACH ROW;
4) AFTER ... FOR EACH ROW.

Каждый триггер обрабатывает три запроса: INSERT, UPDATE и DELETE.

Запросы на создание триггеров:
*/

CREATE OR REPLACE TRIGGER Before_statement
    BEFORE INSERT OR UPDATE OR DELETE
    ON Abonent_1
    FOR EACH STATEMENT
EXECUTE FUNCTION Context();

CREATE OR REPLACE TRIGGER After_statement
    AFTER INSERT OR UPDATE OR DELETE
    ON Abonent_1
    FOR EACH STATEMENT
EXECUTE FUNCTION Context();

CREATE OR REPLACE TRIGGER Before_row
    BEFORE INSERT OR UPDATE OR DELETE
    ON Abonent_1
    FOR EACH ROW
EXECUTE FUNCTION Context();

CREATE OR REPLACE TRIGGER After_row
    AFTER INSERT OR UPDATE OR DELETE
    ON Abonent_1
    FOR EACH ROW
EXECUTE FUNCTION Context();

/*
Добавим нового абонента:
*/

INSERT INTO Abonent_1
VALUES ('111111', 3, 4, 1, 'Иванов И. И.', NULL);

/*
Вывод триггеров:

abonent_1 BEFORE INSERT STATEMENT:
abonent_1 BEFORE INSERT ROW: (111111,3,4,1,"Иванов И. И.",)
abonent_1 AFTER INSERT ROW: (111111,3,4,1,"Иванов И.И.",)
abonent_1 AFTER INSERT STATEMENT:

Изменим номер телефона:
*/

UPDATE Abonent_1
SET Phone = '326127'
WHERE Accountid = '111111';

/*
Вывод триггеров:

abonent_1 BEFORE UPDATE STATEMENT:
abonent_1 BEFORE UPDATE ROW: (111111,3,,,,) =>
                         (111111,3,,,,,326127)
abonent_1 BEFORE UPDATE ROW: (111111,3,4,1,"Иванов И. И.",) =>
                         (111111,3,4,1,"Иванов И. И.",326127)
abonent_1 AFTER UPDATE ROW: (111111,3,,,,) =>
                        (111111,3,,,,,326127)
abonent_1 AFTER UPDATE ROW: (111111,3,4,1,"Иванов И. И.",) =>
                        (111111,3,4,1,"Иванов И. И.",326127)
abonent_1 AFTER UPDATE STATEMENT:

Удалим добавленного абонента:
*/

DELETE
FROM Abonent_1
WHERE Accountid = '111111';

/*
Вывод триггеров:

abonent_1 BEFORE DELETE STATEMENT:
abonent_1 BEFORE DELETE ROW: (111111,3,,,,,326127)
abonent_1 BEFORE DELETE ROW: (111111,3,4,1,"Иванов И. И.",326127)
abonent_1 AFTER DELETE ROW: (111111,3,,,,,326127)
abonent_1 AFTER DELETE ROW: (111111,3,4,1,"Иванов И. И.",326127)
abonent_1 AFTER DELETE STATEMENT:

В отличие от триггеров на уровне строки, триггеры на уровне оператора
срабатывают, даже если запрос затронул ноль строк. Убедимся в этом:
*/

UPDATE Abonent_1
SET Phone = '326127'
WHERE Accountid = '111112';

/*
Вывод триггеров:

Abonent_1 BEFORE UPDATE STATEMENT:
Abonent_1 AFTER UPDATE STATEMENT:

Как следует из вывода триггеров, сработали только триггеры на уровне
оператора.

При нарушении ограничения триггер должен формировать информативное
сообщение об исключительной ситуации.

Рассмотрим пример создания триггера, контролирующего вставку строк
в таблицу Request_1:
*/

DROP TABLE IF EXISTS Request_1;
SELECT *
INTO Request_1
FROM Request;

/*
Допустим, существует такое бизнес-ограничение, по которому каждый
исполнитель может быть назначен на выполнение не более трех ремонтных
заявок в день. При попытке зарегистрировать для исполнителя "лишнюю"
ремонтную заявку должно выдаваться сообщение. Скрипт создания триггера
для решения данной задачи:
*/

-- Создадим функцию, которая проверяет количество заявок на исполнителя
-- в день
CREATE OR REPLACE FUNCTION Check_handler_requests_limit
(
)
    RETURNS TRIGGER AS $$
DECLARE
    Request_count INT;
BEGIN
    -- Считаем количество заявок, назначенных исполнителю на текущий день
    SELECT COUNT(*)
    INTO Request_count
    FROM Request_1
    WHERE Executorid = NEW.Executorid
      AND Incomingdate = CURRENT_DATE;

    RAISE NOTICE 'Текущее количество заявок для исполнителя %: %',
        NEW.Executorid, Request_count;

    -- Если количество заявок больше или равно 3, выбрасываем исключение
    IF Request_count >= 3
    THEN
        RAISE EXCEPTION 'У исполнителя % уже есть 3 заявки, назначенных
                         на сегодня', NEW.Executorid;
    END IF;
    RETURN NEW;
END;
$$
    LANGUAGE plpgsql;

-- Создаем триггер, который вызывает функцию перед вставкой или
-- обновлением
CREATE OR REPLACE TRIGGER Check_handler_requests_limit_trigger
    BEFORE INSERT OR UPDATE
    ON Request_1
    FOR EACH ROW
EXECUTE FUNCTION Check_handler_requests_limit();

/*
Созданный триггер Check_handler_requests_limit_trigger при попытке
назначить исполнителю на выполнение более трех заявок в день вызывает
исключение и предотвращает вставку строки в таблицу Request_1.
*/


